INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('༄༄', '热门专题', '家常菜', '酸', '[{"name": "猪瘦肉", "amount": "250克"}, {"name": "胡萝卜", "amount": "1段"}, {"name": "青尖椒", "amount": "1个"}, {"name": "半把木耳", "amount": "适量"}, {"name": "葱", "amount": "1段"}, {"name": "姜", "amount": "2片"}, {"name": "3瓣蒜", "amount": "适量"}, {"name": "食用油", "amount": "1勺"}, {"name": "郫县豆瓣酱", "amount": "1勺"}, {"name": "腌肉料：盐", "amount": "1勺"}, {"name": "白胡椒粉", "amount": "1勺"}, {"name": "料酒", "amount": "1勺"}, {"name": "生抽", "amount": "1勺"}, {"name": "半个蛋白", "amount": "适量"}, {"name": "玉米淀粉", "amount": "1勺"}, {"name": "食用油", "amount": "1勺"}, {"name": "料汁：清水", "amount": "5勺"}, {"name": "米醋", "amount": "4勺"}, {"name": "白糖", "amount": "3勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "料酒", "amount": "1勺"}, {"name": "玉米淀粉", "amount": "1勺"}]'::jsonb, '["木耳提前泡发，猪瘦肉切丝。", "放入碗中，加入盐🧂白胡椒粉、生抽、料酒、蛋白，抓匀后继续抓捏两分钟，将肉丝抓捏粘稠。", "加入玉米淀粉，抓拌均匀后加入食用油。", "再次抓匀后腌制十五分钟，胡萝卜丝、青椒丝和木耳丝。", "葱花、蒜末、姜丝，料汁所有食材一起放入碗中，搅拌均匀备用。", "起锅烧油，油热下入肉丝，翻炒至变色完全熟透，盛出备用。", "锅留底油，下葱姜蒜炒香，加入郫县豆瓣酱。", "炒出红油，加入胡萝卜丝和木耳丝，大火翻炒至变软断生。", "加入炒好的肉丝和青椒丝，大火翻炒至青椒🫑断生。", "倒入调好的料汁，烧开后翻炒至汤汁粘稠即可。", "太香了🤤🤤🤤", "酸甜下饭。。。", "咸香可口，色香味俱全👍🏻👍🏻👍🏻"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/3fbb2b96f7fb49dda770ca27022fa4b1_1280w_1706h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('365212:‼', '热门专题', '快手菜', '', '[{"name": "梅花肉", "amount": "500g"}, {"name": "小葱", "amount": "150g"}, {"name": "一整个大蒜", "amount": "适量"}, {"name": "鸡蛋一个、白芝麻、姜配料", "amount": "适量"}, {"name": "淀粉，黑胡椒粉、橄榄油、盐、白糖、生抽、蚝油调料", "amount": "适量"}]'::jsonb, '["梅花肉切成1cm的猪排，用一个鸡蛋、生抽、黑胡椒粉、两片姜、蚝油，淀粉腌制20分钟", "调一下盐葱料：小葱+白芝麻+蒜末+黑胡椒粉+盐+白糖+橄榄油两勺", "热锅倒油，用平底锅。猪排下锅，中火煎", "因为加了淀粉，所以煎到双面焦黄", "然后把猪排切成条（可以直接在锅里剪）", "猪排条回锅，把没熟的地方煎一下", "猪排四面都煎熟后，把盐葱料全部放上来", "盖上锅盖，最小火3-5分钟", "时间到后，就可以出锅了"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/81aa6c0f705f4370b57d40516c26b9fd_1232w_1232h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('——', '热门专题', '下饭菜', '辣', '[{"name": "一个茄子", "amount": "适量"}, {"name": "一个土豆", "amount": "适量"}, {"name": "一小把豆角", "amount": "适量"}, {"name": "3-4瓣蒜", "amount": "适量"}, {"name": "适量姜", "amount": "适量"}, {"name": "适量小米辣", "amount": "适量"}]'::jsonb, '["处理食材如图，蔬菜洗好、切好、沥干水分\n①锅内烧油，油热开始冒烟，分别炸土豆（炸至金黄）、茄子（炸至起皱皮）、豆角（炸至虎皮样），沥油备用【这一步可以在食材上喷油放入空气炸锅做，请自行实验】\n②炸的过程中准备料碗:盐1勺、白糖1勺、味精1勺、白胡椒粉半勺、生抽2勺、老抽1勺、耗油1勺、淀粉1勺、清水半碗，搅匀备用\n（盐、糖、味精、胡椒粉等固体都是调味盒送的那种小勺，其它液体的就是正常喝汤用的勺）", "①猪油烧热，姜、蒜、小米辣炒香（不吃辣可以不放小米辣）", "②下去炸过的土豆、豆角、茄子，翻炒后，倒入调好的料汁，炒至汤汁吸收", "哒哒哒，出锅了"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/76926c1ad87b423fa451115ff0ffc3c3_1080w_1835h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('15', '热门专题', '下饭菜', '辣', '[{"name": "牛肉", "amount": "250克"}, {"name": "沙葱", "amount": "50克"}, {"name": "小米椒", "amount": "1根"}, {"name": "5毫升生抽", "amount": "适量"}, {"name": "蚝油", "amount": "5克"}, {"name": "糖", "amount": "3克"}, {"name": "5毫升米酒", "amount": "适量"}, {"name": "胡椒粉", "amount": "3克"}, {"name": "油", "amount": "8克"}]'::jsonb, '["1️⃣ 沙葱洗净控水后切成大段（手指长短），牛肉切片或者切丝都行（片别太厚），加上述调味料抓匀，腌制个10分钟；\n\n2️⃣ 热锅热油，油可以多放点儿，放入牛肉片后，用中大火来炒；", "3️⃣ 只需把牛肉炒到表面完全变色了，就可以放入沙葱了；\nTIP：快炒差不多2分钟左右，牛肉丝比牛肉片还更快成熟，别炒老了。\n\n4️⃣ 加入沙葱段，翻炒个30秒，开始变软后加入腌肉剩余的料汁和小米辣，再炒个30秒就完成了。", "反正炒菜过程差不多就3-4分钟，牛肉腌制过味道很足够，而且成熟度也刚刚好", "沙葱炒过不会太辣，更多是鲜甜的口感，所以我放了小米辣提味，或者多放点儿沙葱也没问题，很好吃的。", "微甜鲜香，如果有多余的汤汁，用来拌饭就很nice了~"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/d78ca05cdfce4a3f8e9397ec823c1544_1280w_1707h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('‼', '热门专题', '下饭菜', '辣', '[{"name": "螺丝椒", "amount": "5只"}, {"name": "皮蛋", "amount": "8个"}, {"name": "8瓣大蒜", "amount": "适量"}, {"name": "适量小米辣", "amount": "适量"}]'::jsonb, '["起锅烧油，锅中放少许油就可以咯，把去头的螺丝椒加少许盐煎至虎皮状～", "可以将皮蛋上锅蒸十分钟或不处理，直接凉拌", "放入切碎的蒜瓣，小米辣，热油泼上去，调味使用糖、盐、酱油、醋搅拌均匀，腌制十分钟即可", "有条件的朋友们可以再加一点香油或者花椒油！都很提味哦~"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/c8ba2132b8ed408d97b8b484522685b0_1280w_1591h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('·', '热门专题', '下酒菜', '辣', '[{"name": "鸡翅中", "amount": "6个"}, {"name": "花椒", "amount": "1勺"}, {"name": "依个人口味干辣椒", "amount": "适量"}, {"name": "花生米", "amount": "1把"}, {"name": "白芝麻", "amount": "1勺"}, {"name": "姜", "amount": "2片"}, {"name": "2瓣蒜", "amount": "适量"}, {"name": "白糖", "amount": "2小勺"}, {"name": "料酒", "amount": "0.5勺"}, {"name": "生抽", "amount": "1勺"}, {"name": "五香粉", "amount": "1小勺"}, {"name": "盐", "amount": "1小勺"}]'::jsonb, '["鸡翅剪成小块，清洗干净，沥干水分", "蒜末、姜末，切好备用\n花椒1勺、干辣椒，放碗里备用", "鸡肉加入姜沫、料酒半勺、生抽1勺、盐1小勺、五香粉1小勺，抓拌均匀冷藏腌制30分钟以上", "六成油温，下鸡肉丁，中火炸至金黄捞出\n\n⭐有条件的还可以炸点花生米", "留底油，加入蒜末、花椒、干辣椒，小火慢炒炒出香味", "加入鸡丁、花生米、盐1小勺、白糖2小勺、白芝麻，翻炒均匀\n\n⭐附辣子鸡家常版做法：https://www.xiachufang.com/recipe/107589923/"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/b1f6710ef20a4142bfdcb9919e344786_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('—', '热门专题', '小清新', '', '[{"name": "共占1/3杯或者*黄色：玉米糖浆+橙汁", "amount": "适量"}, {"name": "百香果糖浆加糖水", "amount": "适量"}, {"name": "1/3杯的容量或*红色：玫瑰洛神花茶", "amount": "适量"}, {"name": "草莓果茶、石榴汁等红色且糖度低于黄色部分的液体", "amount": "适量"}, {"name": "*蓝紫色：蝶豆花茶", "amount": "适量"}, {"name": "一整杯的量普通冰块", "amount": "适量"}, {"name": "加蝶豆花冰块或者苏打水或雪碧", "amount": "适量"}, {"name": "大半杯椰奶", "amount": "适量"}, {"name": "1小匙左右炼乳", "amount": "适量"}, {"name": "一杯的量冰块", "amount": "适量"}]'::jsonb, '["先来做晨昏部分：倒入橙汁加玉米糖浆、或者百香果糖浆加糖水，到容器三分之一的位置。最下层的糖度一定要高，不然分分钟被其他液体压得消失掉。倒入液体后加冰块盖住液体表面", "然后沿着勺子杯缓缓倒入红色液体。如果是无糖、红色的果茶，基本只要轻轻倒就可以，如果是稍微有些糖度的果汁，那么一定要加很多冰块之后再倒入红色部分，而且动作一定要轻柔，注入一定要沿着勺子杯缓缓倒入", "最后三分之一，如果你用了蝶豆花茶冻成的冰块（推荐），那么就先加入与液面齐平的普通冰块，然后放蝶豆花冰块至满。然后缓缓倒入苏打水或雪碧", "如果你用了蝶豆花茶，那么就将杯子加满普通冰块，然后沿着冰块缓缓倒入蝶豆花茶至满杯。如果下层液体的酸碱度不足以使蝶豆花茶变成紫色，那么就滴入一两滴柠檬汁", "然后是日光部分：椰奶加炼乳搅匀增加糖度", "蝶豆花茶泡好放凉", "倒入混合好的椰奶，加冰块至满杯", "然后倒入蝶豆花茶", "这是完成后的晨昏部分。如果你加了蝶豆花冰块，就能出现紫色上方还有蓝色的效果。加入蝶豆花茶就要看运气了…", "日光的很好完成，下方有甜度，上方完全没有甜度，基本不会浑浊", "这是完整的样子", "红色部分是关键，最好选择无糖的红色液体，我试了下加入红葡萄汁，诺，黄色被压得都快没了……", "好啦，这看起来似乎很复杂，但其实蛮好玩的。拿出你做实验的好奇，祝你们玩得开心！\nヾ(๑ㆁᗜㆁ๑)ﾉ\""]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/8306691e69d811e7947d0242ac110002_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('~~', '热门专题', '小清新', '', '[{"name": "桃子", "amount": "2个"}, {"name": "一瓶巴黎水", "amount": "适量"}, {"name": "食用水", "amount": "100ml"}, {"name": "白糖", "amount": "30克"}, {"name": "冰块", "amount": "6块"}, {"name": "薄荷叶", "amount": "1片"}]'::jsonb, '["桃子洗净表皮层的毛毛，切下桃皮，桃肉切成小丁，", "桃子肉碗中撒入25克的白糖，放入冰箱冷藏，", "桃皮放入奶锅，加适量食用水煮开，加入剩余的5克白糖，小火煮10分钟，", "得到了充满少女心的桃汁~倒出晾凉，", "用糖腌过的桃肉比之前软一些了，把它们铺在玻璃杯的底部，", "然后放入冰块，", "倒入巴黎水，至六分满，", "最后倒入煮好的桃子汁，上面放薄荷叶点缀，", "冰爽清新，拍完照就喝了它！"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/85b6751e531341a48700c4dd58dfc0e8_744w_730h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('“yyds”3', '热门专题', '酱', '', '[{"name": "鸡蛋", "amount": "4个"}, {"name": "青椒", "amount": "1个"}, {"name": "黄豆酱，半勺糖，半勺生抽，小半勺老抽，8勺水（尝尝咸淡）料汁：", "amount": "3勺"}]'::jsonb, '["看看！馋不馋！真的贼下饭！", "提前调好料汁：3勺黄豆酱，半勺糖，半勺生抽，小半勺老抽，再加4勺水（自己尝咸淡喔～）", "4个鸡蛋打散，炒至5分熟", "淋入料汁～", "再倒入切小块的青椒，炒断生，最后大火收汁至浓稠就好啦"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/53ee2c6ae7664296883a64abe1bb02e1_943w_1209h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('2', '热门专题', '零食', '', '[{"name": "黄心土豆", "amount": "1000克"}, {"name": "盐", "amount": "10克"}, {"name": "玉米淀粉", "amount": "80克"}, {"name": "小苏打（可无）", "amount": "2克"}, {"name": "植物油", "amount": "1000克"}]'::jsonb, '["三个黄心大土豆，大约2斤，洗净去皮", "5厘米厚度的条（不要太粗，太粗口感容易面）", "清水淘洗几遍，尽量把土豆表面的淀粉淘洗掉（土豆淀粉很容易糊化），加入10克盐，浸泡10分钟", "浸泡好的土豆捞出，水开下锅，焯水2分钟", "捞出迅速过冰水使其冷却", "沥干水分，或者用厨房纸巾擦干表面水分，分两三次撒上共80克玉米淀粉+2克小苏打（起酥脆作用，可不加，但千万别多加，多了油容易起泡沫，且土豆发黄），每次撒完都颠匀盆子，最终粉类均匀、薄薄地裹住土豆条为准", "油温6成热，大概160度，下入土豆条（可以先丢进去一根土豆条，周围迅速泛起油花，三秒土豆条浮起来作为判断标准）", "刚下入时候不要翻动，中火大概2分钟，土豆条定型后，再推动均匀炸制3～5分钟，最后一分钟大火轰一下", "经历了七八分钟，炸熟了，捞出，先静置两分钟以上，给内部湿气继续往外挥发的空间", "两分钟后，用最大火高油温，复炸一遍，炸大约1分钟即可", "捞出，准备好番茄酱蘸食，这样做出来的薯条，放置1-2小时也不容易回软，不过还是建议尽快食用完毕"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/0971701d88bd4201ab9b6755e1ba9141_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('|', '热门专题', '零食', '', '[{"name": "苹果", "amount": "8斤"}]'::jsonb, '["苹果去皮去核切成8份", "铺在晾网放太阳底下晒", "晒到这样就可以开始一蒸了", "上锅水开蒸13分钟左右", "晒成这样开始第二次蒸", "水开蒸15分钟左右，看苹果大小", "风炉模式120度烘烤60分钟", "水开蒸20分钟左右", "烘好啦，可以吃了，哦耶", "烤箱风炉模式100度烘烤30分钟", "最后成品530g"]'::jsonb, 30, 55, '困难', 3, 'https://i2.chuimg.com/ed72e1b2813e4f4ea45b2a1406d594b5_1920w_2560h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('~', '热门专题', '早餐', '', '[{"name": "红米红米", "amount": "适量"}, {"name": "适量白米", "amount": "适量"}, {"name": "1棵生菜", "amount": "适量"}, {"name": "黄瓜", "amount": "1根"}, {"name": "鸡蛋", "amount": "2个"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量肉松", "amount": "适量"}, {"name": "适量鸡腿扒", "amount": "适量"}, {"name": "适量沙拉酱", "amount": "适量"}]'::jsonb, '["红米和白米淘洗干净。", "放电饭煲煮熟。", "碗中打入鸡蛋，加盐打散。", "锅中热油，倒入蛋液，煎至定型后翻面。", "放凉后卷起来，切成条。", "寿司帘铺张保鲜膜，取适量米饭摊开铺平。", "放上你和家人喜欢的食材，可以参考下我的搭配：肉松、生菜条、黄瓜条、鸡腿扒和鸡蛋条。", "挤上沙拉酱，慢慢卷起来。", "一口咬下去，软糯的米粒裹着满满的馅料，丰富又扎实，真的超满足~\n\n这个周末就试一次吧！蔬菜经过冷冻再加热，口感会打折扣，介意这点的朋友记得调整下♥️可以换成胡萝卜、玉米粒等……"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/41d2cfb9a405417fa83221b72b0c2de8_1905w_2540h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('——()', '热门专题', '下午茶', '甜', '[{"name": "芒果果肉(推荐凯特芒、澳芒、大金煌芒)", "amount": "400g"}, {"name": "西米", "amount": "40g"}, {"name": "椰浆", "amount": "100ml"}, {"name": "炼乳", "amount": "12g"}, {"name": "牛奶", "amount": "200ml"}, {"name": "少许西柚", "amount": "适量"}]'::jsonb, '["准备材料，我用的是椰浆，不是椰奶。", "小西米一袋，用不完的密封保存。\n西米不是米，无需冲洗直接煮就好了，洗了就融化了。", "锅内倒入500g左右的水(水量不用特别精准)，大火煮沸后将称量好的40g西米倒入锅中，转小火盖锅盖煮15分钟，期间不停揭盖观察并搅动防止西米沾底。当西米基本上透明还有一点点白芯的时候(比图片上白芯还要小)关火焖15分钟。", "直至西米的白芯消失、呈现全透明的状态。", "将西米用凉水冲洗几遍后，放入盛有凉水的碗中备用。", "配制椰汁，椰浆和牛奶的比例1:2，100ml的椰浆加入200ml的牛奶，椰浆本身是不甜的，所以再加12g炼乳调味，搅拌均匀备用。", "冷水中的西米捞出沥干水分，放入椰浆中，直接吃就是市面上的椰汁西米露。", "切芒果，芒果尽量选大的，推荐凯特芒、澳芒、大金煌芒，个大甜度高。把芒果竖起来避开果核沿两侧各切一刀，切成三片。", "用刀划十字格不要切断。", "用手在芒果皮上一顶，漂亮的芒果花就翻出来了。", "另一片也同理。", "把芒果花上好看方正的芒果丁切下来备用。", "剩下的所有芒果肉(边角料)都放入料理机搅打成芒果泥。", "细腻的芒果泥完成。(芒果和牛奶不要偷懒一起用料理机打，会起很多泡泡。)", "将芒果泥倒入步骤5的椰汁西米露中搅匀，再摆上几块芒果丁。", "放上西柚果肉(我用的普通柚子也很好吃😋)有薄荷叶的可以装饰一下，杨枝甘露完成！", "都是大块芒果果肉！过瘾不过瘾！！！", "杨枝甘露杯装。芒果泥放底部，然后倒西米，最后是椰奶部分，吃之前搅拌一下。", "没有椰浆的可以，一罐椰奶+一盒牛奶🥛，味道也很好"]'::jsonb, 30, 95, '困难', 3, 'https://i2.chuimg.com/85f3f078a14549b491f3b36558d4aece_1242w_994h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('—5N', '热门专题', '下午茶', '', '[{"name": "清水", "amount": "500克"}, {"name": "白凉粉", "amount": "25克"}, {"name": "砂糖（可以增减）", "amount": "30克"}, {"name": "几滴柠檬汁（防止氧化）", "amount": "适量"}, {"name": "👇水果", "amount": "适量"}, {"name": "取皮紫葡萄", "amount": "适量"}, {"name": "取皮青提", "amount": "适量"}, {"name": "取皮水蜜桃", "amount": "适量"}, {"name": "切块，榨汁雪梨", "amount": "适量"}, {"name": "取汁百香果", "amount": "适量"}, {"name": "没有硬性规定以上水果任选其中一种即可，也可以换成其他家里有的水果", "amount": "适量"}]'::jsonb, '["桃子，选红一点的～盐搓洗表面，削皮～500克清水，两个桃子的皮，几滴柠檬汁，煮开，捞掉皮～加入25克白凉粉，30克白砂糖搅拌均匀，分装入杯，桃子肉可以切丁加入杯中，晾凉，冷藏2小时～备用～", "凝固了，取出之后，倒入牛奶（椰奶，养乐多，任何你喜欢的茶水饮料）用勺子戳碎一点，就可以食用了～", "青提用淀粉水搓洗干净，我直接用格瑞美厨洗的～取皮～500克清水加青提皮加几滴柠檬汁煮开煮出颜色，捞去青提皮，加入25克白凉粉，30克砂糖搅拌均匀，分装入杯，青提果肉可以加入杯中，晾凉，冰箱冷藏2小时，", "凝固了，取出之后，倒入牛奶（椰奶，养乐多，任何你喜欢的茶水饮料）用勺子戳碎一点，就可以食用了～", "紫葡萄用淀粉水搓洗干净，我直接用格瑞美厨洗的～取皮～500克清水加葡萄皮加几滴柠檬汁煮开煮出颜色，捞去葡萄皮，加入25克白凉粉，30克砂糖搅拌均匀，分装入杯，葡萄果肉可以加入杯中，晾凉，冰箱冷藏2小时，", "凝固了，取出之后，倒入牛奶（椰奶，养乐多，任何你喜欢的茶水饮料）用勺子戳碎一点，就可以食用了～", "梨用盐搓洗干净，榨汁，过滤，果汁加水一共500克，加几滴柠檬汁煮开，加入25克白凉粉，30克砂糖搅拌均匀，分装入杯，晾凉，冰箱冷藏2小时～（没有榨汁机的直接切小块加500克清水煮开就好，也可以加几个枸杞一起煮，最后捞掉就行）～这款比较养生润肺哈哈哈哈哈哈", "冰箱凝固了，取出之后，倒入牛奶（椰奶，养乐多，任何你喜欢的茶水饮料）用勺子戳碎一点，就可以食用了～", "百香果操作略有不同～清水500克煮开，加入白凉粉25克，砂糖30克搅拌均匀，用网筛过滤加入百香果汁～分装入杯，晾凉，冰箱冷藏2小时～备用～", "凝固了，取出之后，倒入牛奶（椰奶，养乐多，任何你喜欢的茶水饮料）用勺子戳碎一点，就可以食用了～", "进冰箱之前～", "等待的时间，就把这些去皮的水果吃掉吧～也可以切成小丁，装在杯子里，跟液体一起去冰箱冷藏凝固～吃起来就是有果粒的了～我懒得切，你们随意", "出冰箱之后～", "来个小视频～"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/6494aa0ad26f412d86532853fbf3a4ca_480w_384h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('|', '热门专题', '便当', '', '[{"name": "鸡腿", "amount": "2只"}, {"name": "10朵干香菇", "amount": "适量"}, {"name": "青椒", "amount": "2个"}, {"name": "土豆", "amount": "2个"}, {"name": "料酒", "amount": "2勺"}, {"name": "一小把冰糖", "amount": "适量"}, {"name": "蚝油", "amount": "3勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "老抽", "amount": "2勺"}, {"name": "鸡精", "amount": "1.5勺"}, {"name": "香叶", "amount": "1片"}, {"name": "白胡椒粉", "amount": "1勺"}, {"name": "糖", "amount": "1勺"}, {"name": "五香粉", "amount": "0.5勺"}, {"name": "姜粉", "amount": "1勺"}, {"name": "姜", "amount": "3片"}, {"name": "看是否吃辣干辣椒/剁椒", "amount": "适量"}, {"name": "4瓣蒜", "amount": "适量"}]'::jsonb, '["干香菇温水泡发。（最好先洗几次，因为后面泡香菇的的水要用到。）", "鸡腿剁大块冲洗干净泡冷水1小时。", "泡出血水的鸡腿加入图上所有配料，生抽，老抽，料酒，白胡椒粉，姜粉，蚝油，五香粉腌制30分钟。", "腌制好的鸡腿肉上色均匀。", "所有食材站好合影～", "土豆切滚刀块冲水去掉淀粉，青椒切块备用，干香菇对半切开。喜欢吃辣可以准备一勺剁椒或者干辣椒。蒜拍扁。", "锅中倒油烧热。", "倒入土豆翻炒，炒一下可以让土豆更香，微微变色就可以取出备用。", "锅中底油加入冰糖。一定要小火！", "炒糖色不要超过否则会苦，锅中冒大泡迅速倒入鸡肉。", "大火翻炒均匀上色。", "倒入姜蒜辣椒和香叶翻炒。", "炒出香味后烹入料酒去腥。", "倒入蚝油。", "加入生抽。", "加入白胡椒粉。", "加入老抽上色。", "按照个人口味加入糖。", "翻炒均匀后加入干香菇。", "倒入泡香菇的水，一定没过鸡肉。没有就倒开水。一次加足，有汤汁更好吃。", "大火烧开撇去浮末，改为小火炖煮40分钟。", "40分钟后加入土豆再煮25分钟。", "中间换了个珐琅锅更好的收汁，不换也可以，不过珐琅锅炖煮出来的更香。", "加入鸡精提鲜。", "加入青椒，煮三分钟即可，时间长青椒会变色就不好看了。", "直接端锅上桌啦～"]'::jsonb, 30, 130, '困难', 3, 'https://i2.chuimg.com/8d8cb9252b8246878d12d8a03a18280c_1051w_1051h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('No.6⃣', '热门专题', '便当', '', '[{"name": "按喜欢的来蔬菜", "amount": "适量"}, {"name": "按喜欢的来荤菜", "amount": "适量"}]'::jsonb, '["炖牛腩➕清炒菠菜➕米饭。                                       炖牛腩我之前写过的方子： \n\n“总是不够吃的炖牛腩”：\nhttps://www.xiachufang.com/recipe/104409232/", "腊肠菜饭➕红烧台湾虾🦐➕清炒芦蒿", "南瓜饭➕青椒胡萝卜肉片➕秋葵菇子炒蛋", "红烧排骨➕茄子炒豆角➕米饭", "青椒肉片➕四喜烤麸➕豆角炒蛋➕米饭\n我之前写过的四喜烤麸的方子：\n“冷热皆宜的四喜烤麸”：\nhttps://www.xiachufang.com/recipe/104438853/", "黑椒煎鸡腿排➕清炒荷兰豆➕豆苗➕厚蛋烧➕米饭（撒一些味岛香松）", "虾仁滑蛋➕白灼青菜➕素什锦➕米饭", "烤鸡腿杂蔬（在我每次的便当集锦好像都出现一两次，因为只要腌制鸡腿然后放烤箱和土豆小番茄一起烤）➕虾仁蛋炒饭", "糖醋里脊➕炒菠菜➕手撕包菜➕米饭", "红烧大排➕韭黄炒蛋➕白灼杂蔬➕米饭", "辣炒鸡块➕白灼生菜淋蒸鱼豉油➕米饭", "咖喱鸡丁➕蚝油菇子➕米饭", "红烧排骨➕芹菜腐竹➕火腿片炒莴苣➕米饭", "上汤娃娃菜➕彩椒牛柳➕白煮青菜豆腐丝➕米饭", "红烧猪软骨➕蚝油香菇➕白灼西兰花🥦➕米饭", "荠菜馄饨➕青椒土豆丝➕豆角炒蛋➕红烧鸡翅根（馄饨和鸡翅根都是从奶奶家打包）", "小炒鸡腿肉➕莴苣炒蛋➕彩椒鸡软骨（超市购买的配好的方便菜）➕米饭", "青椒肉丝➕清炒茼蒿➕红烧煎豆腐", "香菇青菜➕“荷塘月色”（某送菜app购入的配好的方便菜，一炒就行）➕熟食➕米饭", "酱鸭➕素炒杏鲍菇➕酒香金花菜➕米饭"]'::jsonb, 30, 100, '困难', 3, 'https://i2.chuimg.com/3aa00aab70a7447a898156deaae4a204_1242w_994h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('-', '热门专题', '便当', '', '[{"name": "适量餐具方便直接吃的主食", "amount": "适量"}, {"name": "适量爱吃的蛋白质：肉类/鸡蛋", "amount": "适量"}, {"name": "适量营养均衡的蔬菜们", "amount": "适量"}, {"name": "适量拌饭酱汁（可选）", "amount": "适量"}]'::jsonb, '["【宫保鸡丁饭】\n宫保鸡丁（鸡胸肉/胡萝卜/青椒/腰果）+玉米青豆+紫甘蓝泡菜+米饭+芝麻海苔碎", "【煲仔饭】*电饭煲一锅出*\n腊肠+腊肉+香菇+鸡蛋+青豆+圆白菜+米饭+煲仔饭酱汁\n具体做法参考【不素懒人煲仔饭】菜谱：https://www.xiachufang.com/recipe/105815012/", "【台式卤肉饭】\n拌饭神器卤肉（三层肉/香菇/洋葱酥）+卤蛋+菜花或小青菜+米饭\n具体做法参考【不素懒人卤肉饭】菜谱：https://www.xiachufang.com/recipe/105823942/", "【韩式石锅拌饭】\n胡萝卜+西葫芦+香菇肉碎+香肠+鸡蛋+米饭+韩式辣拌饭酱\n具体做法参考【不素懒人石锅拌饭】菜谱：https://www.xiachufang.com/recipe/105827979/", "【麻辣香锅饭】\n麻辣香锅（土豆/胡萝卜/包菜/藕片/香菇/木耳/香肠/蟹棒/虾仁）+米饭+芝麻海苔碎", "【韩式部队锅饭】\n部队锅（牛肉卷/午餐肉/香肠/蟹棒/年糕/香菇/金针菇/泡菜/胡萝卜/土豆/西葫芦/辣酱锅底/芝士）+米饭+芝麻海苔碎\n\n前一晚上做足量的部队锅和芝士拉面，吃不完的配菜锅底加上米饭又是一顿简便美味的便当～", "【快手大阪烧】\n日式大阪烧（圆白菜/虾仁/扇贝/火腿/青豆/鸡蛋/牛奶/奶酪/面粉）+卤蛋or厚蛋烧+大阪烧酱汁", "【香浓咖喱鸡肉饭】\n鸡胸肉+土豆+胡萝卜+洋葱+青豆+米饭\n灵魂咖喱酱：咖喱粉2/酱油1/牛奶", "1/芝麻酱", "【照烧鸡腿饭】\n带皮鸡腿肉+青菜+胡萝卜+米饭\n灵魂照烧汁：酱油2/料酒1/蜂蜜1/番茄酱", "5/黑胡椒/盐", "【爱心蛋包饭】\n火腿/胡萝卜/彩椒/西葫芦/青豆/鸡蛋/米饭", "【麻辣拌配饭】\n麻辣拌（猪肉/香肠/大虾/蟹棒/洋葱/胡萝卜/土豆/藕片/西兰花/香菇/芝麻）+米饭", "【西班牙海鲜饭】\n鱿鱼/大虾/扇贝/西班牙辣肠/洋葱/番茄/彩椒/藏红花/西兰花/米饭/柠檬", "【辣海鲜寿司饭】-冷餐-\n照烧辣海鲜（鱿鱼/大虾/扇贝）/牛油果/裙带菜/鱼籽蟹棒/日本红姜/寿司饭", "【百变豪华沙拉】-冷餐-\n通心粉/生菜/火腿/蘑菇/鸡蛋/蟹棒/牛油果/橄榄/玉米+沙拉酱/无花果醋/黑胡椒/柠檬汁（防止牛油果氧化）"]'::jsonb, 30, 80, '困难', 3, 'https://i2.chuimg.com/b655891e385344b6a2e1a8b6edfd23fa_1502w_1124h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('Tinrry+', '热门专题', '圣诞节', '', '[{"name": "无盐黄油", "amount": "100克"}, {"name": "糖粉", "amount": "70克"}, {"name": "奶粉", "amount": "30克"}, {"name": "全蛋液", "amount": "30克"}, {"name": "低筋面粉", "amount": "200克"}, {"name": "烘焙用蛋白粉", "amount": "10克"}, {"name": "糖粉", "amount": "130克"}, {"name": "食用水", "amount": "20克"}, {"name": "新鲜柠檬汁", "amount": "10克"}, {"name": "水饴（玉米糖浆）", "amount": "5克"}, {"name": "拉线糖霜", "amount": "80克"}, {"name": "新鲜柠檬汁", "amount": "5克"}]'::jsonb, '["关注我们公众号：甜悦家烘焙，获取更多的教学视频&amp;烘焙工具，材料的优惠信息。\n\n如果在制作过程中有什么疑问，可以扫码添加我的小助理的微信，她会给你详细解答哦，还可以加入甜悦家的烘焙交流群，还会有淘宝优惠哦~", "#饼干底", "糖粉、奶粉一起过筛加入无盐黄油中，用电动打蛋器混匀；", "全蛋液分两次加入，用打蛋器低速混匀；", "过筛加入低筋面粉，用刮刀拌匀至没有干粉；", "戴上手套稍微揉匀面团；", "将面团转移到油纸上，稍微捂实，让面团没有过大的缝隙；", "盖上另一张油纸，稍微压扁，放入冰箱冷冻15-20分钟；\n\nTips：面团最好贴着冰箱的隔层板，冷却的速度更快。", "把烤箱上下火150度预热；", "冷冻好的面团可以轻易用手指戳出小坑，即表示软硬度刚好；", "用擀面杖把面团擀开至约4毫米的厚度；", "撕开油纸，在面团表面撒上面粉防粘；", "将面团的另一面翻转朝上，用饼干模具刻出饼干面团；\n\nTips：\n1、可以用牙签或裱花嘴在饼干上刻出小洞，烘烤出来的饼干就可以用绳子串起来。\n2、大小不同的饼干面团建议分开烘烤。", "饼干面团送入预热好的烤箱中层，上下火150度，烘烤20分钟左右；", "饼干边缘形成金黄色，中间还有一点白，即可以关火，在烤箱中焖5分钟左右再取出，让饼干颜色更均匀；", "饼干出炉后马上转移到一个平面上，用烤盘压着晾凉；", "过筛糖粉、蛋白粉，把三分之一过筛好的糖粉加入蛋白粉，混匀；", "加入食用水，稍微搅拌后，用打蛋器中高速打发糖霜；\n\nTips：第一次加入糖粉一定要打发变白，把蛋白粉融化并且打发起来。", "糖霜打发至变稠变白、有纹路，即可分两次加入剩余糖粉，继续混匀、打发；\n\nTips：糖粉要分三次加入打发，如果一次性加入，会打发不充足，糖霜颜色会很黄。", "糖霜打发至固体状态；", "称量加入水饴，加入柠檬汁，低速混匀糖霜，做成用于勾线的糖霜；", "称量出80克的勾线糖霜，分次看情况加入柠檬汁，混匀成可以流动的填充糖霜。\n；", "把两种糖霜分别装入裱花袋备用；", "把装糖霜的裱花袋剪一个小口；\n\nTips：可以在油纸上试一下糖霜线条的粗细。", "根据视频中的手法画出糖霜图案。\n\n填充雪花", "做好的糖霜饼干，建议送入烤箱上下火60-70度烘烤半小时（线条形状）至一个小时（填充形状）左右，把糖霜中的水分烘干，以保证口感、延长保存期限。"]'::jsonb, 30, 130, '困难', 3, 'https://i2.chuimg.com/b191f95f08c945758407b33d103baf2c_6720w_4480h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('-', '热门专题', '圣诞节', '', '[{"name": "腌肉部分：", "amount": "适量"}, {"name": "2斤左右鸡腿", "amount": "8只"}, {"name": "适量葱姜蒜", "amount": "适量"}, {"name": "几片洋葱", "amount": "适量"}, {"name": "老抽", "amount": "1勺"}, {"name": "蚝油", "amount": "2勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "淀粉", "amount": "3勺"}, {"name": "油", "amount": "3勺"}, {"name": "适量盐", "amount": "适量"}, {"name": "半勺糖", "amount": "适量"}, {"name": "半勺黑胡椒粉", "amount": "适量"}, {"name": "蔬菜部分：一切淀粉类的蔬菜都可以我为了消耗家里冰箱的蔬菜和好多叫不出名字形状的南瓜，所以决定做这个菜", "amount": "适量"}, {"name": "土豆", "amount": "1个"}, {"name": "半节藕", "amount": "适量"}, {"name": "胡萝卜", "amount": "1根"}, {"name": "半个南瓜", "amount": "适量"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "10朵（超级好吃，一定要多放）香菇", "amount": "适量"}, {"name": "青椒", "amount": "1个"}, {"name": "生抽", "amount": "1勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "盐", "amount": "1勺"}]'::jsonb, '["鸡腿肉去骨，肉切大丁备用", "把所有的蔬菜切好", "鸡腿肉来腌制，基本以这个饭勺为基准，放入葱姜蒜", "1勺老抽，2-3勺生抽，2勺蚝油，少量黑胡椒粉，一勺糖，一勺盐，盐的用量自己酌情放，因为生抽蚝油都有咸度。两大勺淀粉，再倒入适量油，拌匀腌制片刻。", "蔬菜部分尽量切一致，土豆不要切太大，不然鸡腿肉熟了刚刚好的时候 土豆还不够软糯。蔬菜放一勺生抽一勺蚝油一小勺盐适量油拌匀即可", "拿一个大烤盘，铺满锡纸", "把蔬菜铺匀，把鸡肉铺在上面", "上下火，180度，半个小时。", "半小时我尝了一下，觉得土豆不够软糯，我就盖了层锡纸，温度加到200，又烤了8分钟。火候和时间得看食材和自家烤箱脾气决定。", "时间到啦，米饭也好了，南瓜土豆超级糯，吸收了汤汁味道，鸡腿肉因为加了淀粉，超级滑嫩。拌饭吃绝了！", "鸡骨没浪费，炖了几朵香菇加了一把油菜，也相当舒坦了！", "后面我又试过一下，蔬菜部分多加了芹菜，烤的时候先加盖锡纸不用包严实，200度35分钟。然后拿掉锡纸，230度烤15-或18分钟。上面的鸡皮呈现一种焦焦的口感。都很好吃，随你喜欢咯。"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/c44a390c80c0426f84d5abb066a286fb_1280w_1023h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('/', '热门专题', '圣诞节', '', '[{"name": "（根据自己用量）杏仁（可换成其他坚果）", "amount": "200克"}, {"name": "糖", "amount": "100克"}, {"name": "盐", "amount": "1克"}, {"name": "水", "amount": "40克"}, {"name": "（我喜欢可可味的做的比较多）黑巧克力", "amount": "60克"}, {"name": "（其实还是看自己做的量）可可粉", "amount": "50克"}, {"name": "（大概可以做40颗）白巧克力", "amount": "20克"}, {"name": "抹茶粉", "amount": "15克"}]'::jsonb, '["我一般都一次性做3款 但我很负责任的告诉你 可可巧克力的最好吃！", "称取杏仁 放置烤盘中 入烤箱130度 10分钟 （烤好的杏仁最好90度放烤箱里面恒温备用）", "糖➕盐➕水放置锅中 中火加热", "待糖熬到109度（其实105度开始就可以了 怕倒入杏仁会降低糖的温度 所以我多熬了几度）", "离火 用刮刀快速翻炒", "等待糖凉了的时候就会形成糖霜杏仁（其实还可以做糖霜各种东西 比如糖霜山楂是不是）", "拿出糖霜杏仁后 剩余的放入锅中中火继续加热 使其糖霜焦糖化", "等待杏仁上的糖霜全部焦化并且裹上焦糖后", "少数的倒到铺有油布的烤盘上 （嗯 很多拉丝不重要 等糖冷却硬了之后可以弄掉）！！！强调下！一定要一点一点弄出来（如果你一次性弄出来 我保证 你还没把杏仁分开 焦糖就已经硬化了）", "冷却好的焦糖杏仁拨开丝 还是很ok的对不对？其实到这步 焦糖坚果跟糖霜坚果就很好吃了", "这个就是焦糖榛子 跟糖霜榛子 做好了装管密封 差不多可以吃一个月？", "巧克力隔水融化（或者微波炉小火融化都可以）", "倒入焦糖杏仁 裹上巧克力", "夹出来 到可可粉上 裹上可可粉 就👌🏻啦", "抹茶味的用白巧克力哦 不然颜色不好看", "同样倒入焦糖杏仁 翻版均匀", "夹出来扔进抹茶粉中（抹茶那么贵 当然要杯子装啦～摇一下杯子 就裹好了", "差不多我的杯子不大 可以4-5颗一起操作吧（and～抹茶吸水性比较高 所以差不多裹好一次后 最后还得再裹一次", "好了 冬天快到了 你确定不做一点糖来准备过圣诞么🎄 （ps：别问我 多余的抹茶粉跟可可粉怎么办 当然是做抹茶拿铁跟可可巧克力牛奶啦 这是一个暖暖的冬天）"]'::jsonb, 30, 95, '困难', 3, 'https://i2.chuimg.com/9d7f5e7ec4754220988c1927f0dde88c_1242w_2098h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('ins---', '热门专题', '圣诞节', '', '[{"name": "高筋面粉", "amount": "240克"}, {"name": "低筋面粉", "amount": "60克"}, {"name": "纯牛奶", "amount": "160克"}, {"name": "全蛋液", "amount": "35克"}, {"name": "细砂糖", "amount": "30克"}, {"name": "干酵母", "amount": "3克"}, {"name": "盐", "amount": "4克"}, {"name": "黄油", "amount": "30克"}, {"name": "适量豆沙馅", "amount": "适量"}, {"name": "适量高筋面粉", "amount": "适量"}]'::jsonb, '["将面团配料除黄油外的配料，混合一起，搅打至扩展阶段；", "加入黄油，搅打至完全扩展阶段；", "面团盖保鲜膜开始一次发酵。发酵至2-", "5倍大，用手指蘸面粉按下去不回缩不塌陷即可；", "面团一发完成后分成3等份，滚圆以后盖上保鲜膜松弛15分钟；", "取一份松弛好的面团，擀成直径约22Cm的圆饼", "抹一层豆沙馅；", "再把第二张擀成圆饼铺在第一个上面", "再抹一层红豆沙", "再把第三份擀成圆饼铺上", "把边缘捏紧；", "取一个直径约5Cm的原型磨具放在面饼中间；", "沿着边把面饼切成16份 ,每一刀都要切透。", "可以先切成4等份，再切8等份，最后切16等份；", "、取临近两个长条，一手捏一个", "反向拧两圈捏住边缘", "依次处理所有切面；", "开始二次发酵。发酵的适宜温度是37度，湿度75%。如果没有发酵箱，可以放在烤箱里，放一碗热水。", "发酵至2倍大，取出来筛上适量高筋面粉；", "放入预热好的烤箱，180度中下层烤25分钟；", "随手一拍都很美", "满满的圣诞风"]'::jsonb, 30, 110, '困难', 3, 'https://i2.chuimg.com/b4e3bfb1cd1347f0bb79554f08f4e8fa_5472w_3648h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('·', '热门专题', '深夜食堂', '', '[{"name": "猪五花肉", "amount": "200克"}, {"name": "1/4根白萝卜", "amount": "适量"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "4朵香菇", "amount": "适量"}, {"name": "半根牛蒡", "amount": "适量"}, {"name": "芋头", "amount": "3个"}, {"name": "魔芋", "amount": "1块"}, {"name": "木棉豆腐", "amount": "1块"}, {"name": "油炸豆腐", "amount": "1块"}, {"name": "半根大葱", "amount": "适量"}, {"name": "1500毫升日式高汤", "amount": "适量"}, {"name": "1大匙芝麻油", "amount": "适量"}, {"name": "5-6勺味增", "amount": "适量"}, {"name": "1小匙酱油", "amount": "适量"}, {"name": "1小匙味淋", "amount": "适量"}]'::jsonb, '["将猪五花肉切成4厘米长的薄片。白萝卜、胡萝卜切成银杏叶形片，香菇切薄片，牛蒡切薄片，芋头切成块。魔芋、木棉豆腐用手掰成适口大小备用。油炸豆腐切成1厘米宽条状，大葱的一半切成1厘米小段，另一半剁碎。", "锅烧热后倒入芝麻油，炒猪五花肉片。再放入魔芋和其余的蔬菜同炒，芋头，2种豆腐，大葱除外。", "锅内食材全部过油翻炒后，倒入高汤。煮开并撇去浮沫，放入油炸豆腐和半份味增，加盖炖煮10-15分钟。", "待蔬菜煮熟后，加芋头，葱段，豆腐，继续炖煮大约10分钟。", "起锅前加入余下的味增、味淋、酱油", "盛入汤碗，撒上碎葱末。呼噜呼噜真是下饭"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/78c2d82446a6425bb55f049e5783cdf1_1766w_943h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('-', '热门专题', '深夜食堂', '', '[{"name": "，两个拳头大土豆", "amount": "1个"}, {"name": "煮熟的鸡蛋", "amount": "1个"}, {"name": "四分之一个洋葱", "amount": "适量"}, {"name": "三分之一根胡萝卜", "amount": "适量"}, {"name": "适量沙拉酱，盐，醋，黑胡椒", "amount": "适量"}, {"name": "切片用盐腌黄瓜", "amount": "适量"}, {"name": "二分之一火腿或者香肠", "amount": "适量"}, {"name": "黄油，放入热土豆里", "amount": "10克"}]'::jsonb, '["菜谱图片", "土豆胡萝卜煮熟，我喜欢土豆还有一点点块状", "乘着热拌所有材料", "23年10月国庆节，准备材料。多了东方甄选甜玉米粒。醋用的balsamico是意大利拌沙拉用的果醋也不错。", "煮鸡蛋得放哦，调整口感。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/f3282912d2f94369aa76669dfbee1980_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('| 2', '热门专题', '情人节', '', '[{"name": "我的黑巧克力和牛奶巧克力是一样放一半的，如果你喜欢甜点的，那就牛奶巧克力多放点，两者加起来一共300克左右就差不多了。", "amount": "适量"}, {"name": "黑巧克力（65%-70%）", "amount": "150克"}, {"name": "牛奶巧克力", "amount": "150克"}, {"name": "淡奶油", "amount": "165克"}, {"name": "水饴", "amount": "15克"}, {"name": "无盐黄油", "amount": "15克"}, {"name": "适量，撒表面用的可可粉", "amount": "适量"}, {"name": "白巧克力（33%左右）", "amount": "300克"}, {"name": "无盐黄油", "amount": "25克"}, {"name": "淡奶油", "amount": "85克"}, {"name": "水饴", "amount": "7克"}, {"name": "6-8克抹茶粉", "amount": "适量"}, {"name": "适量，撒表面用的抹茶粉", "amount": "适量"}, {"name": "❣️❣️❣️视频里我做的是配料表两倍的量，因为我的模具太大了，如果做太少的话，成品会显得有点薄，不好看，谁让我是颜控😂", "amount": "适量"}]'::jsonb, '["先咬一口馋你一下，哈哈O(∩_∩)O", "黑巧克力味的~", "好啦，开始吧，提前准备好所有原材料；", "在模具里垫硅油纸，没有硅油纸的垫保鲜膜也可以，但四周都要垫好，不然不好脱模；", "在一个稍微大点的碗里倒入黑巧克力；", "再倒入牛奶巧克力；", "最后倒入黄油，这三种东西混合在一起就可以了，不分先后顺序；", "稍微铺平点，好让所有巧克力黄油均匀受热；", "隔热水放着备用，热水的温度不宜太高，太高会让巧克力增加油水分离的风险；\n\n我的水温大概是70摄氏度左右吧；", "在锅里倒入淡奶油；", "开下火加热；", "加热至边缘冒泡泡就可以了，千万不要煮太久，太烫了也会让巧克力油水分离；", "将煮好的奶油均匀的淋入巧克力里；\n\n但巧克力还是隔热水放着，不要拿出来了；\n\n因为这点奶油没办法让巧克力完全融化，所以要借助隔热水的方法让巧克力完全融化；", "再倒入水饴；", "盖上保鲜膜闷3-5分钟；", "然后取走保鲜膜；", "轻轻搅拌，让奶油和巧克力充分融合；\n\n刚开始的状态可能有点，不可描述，看着很难受，不要灰心，继续轻轻搅拌；", "可以直线朝一个方向搅拌，就是将蛋抽由外向内搅拌，这样可以让巧克力和奶油更容易融合；", "慢慢的，巧克力跟奶油就充分融合了，变得细腻顺滑；\n\n记住，一定要轻轻的搅拌，动作太大的话，会让空气进去，形成很多气泡；", "搅拌好了之后，倒入之前垫了硅油纸或保鲜膜的模具里；\n\n模具尽量用小一点的，太大了的话，成品就显得比较薄，个人觉得太薄的不好看，不过，如果你喜欢薄的话，就没问题了；", "用刮板刮平，但是呢，不刮平也不影响食用；", "铺平后，放入冰箱冷藏3小时左右，或者冷冻1-2个小时，但这个时间不是绝对的，只要把它冻硬就可以了，不冻硬的话不好切；\n\n用法芙娜巧克力做的更好吃哦，但是巧克力颗粒比较大的话，要切碎一点，不然不好融化；\n\n隔水融化巧克力的水，不可以太烫，不然巧克力会油水分离，我的水温大概是70摄氏度左右；\n\n水饴可以根据不同的季节适当增减，冬天的话，可以多加几克，因为水饴的保湿性好；", "接下来是抹茶味的，提前准备好所有原材料；", "将黄油与白巧克力放一起，铺平，隔热水融化；", "隔水融化巧克力的水，不可以太烫，不然巧克力会油水分离，我的水温大概是70摄氏度左右；\n\n水饴如果没有的话，可以不放，只是放了的话，生巧的保湿性更好；\n\n水饴也可以根据季节不同适当增减，冬天就可以多放几克；", "轻轻搅拌；", "搅拌至差不多融化就可以了，有点颗粒也没关系，因为后面还是隔热水操作，操作的过程中还会融化的；", "抹茶粉先过筛三分之一进去；", "轻轻搅拌均匀；", "再过筛剩余的抹茶粉的一半进去；", "抹茶粉过筛进去之后，轻轻搅拌均匀；\n\n搅拌均匀后，将剩余的抹茶粉全部过筛进去；", "再次轻轻搅拌均匀；", "搅拌至看不见抹茶粉为止，还是隔热水放着备用；", "奶油倒入锅中；", "小火煮至边缘冒泡泡；", "将隔热的巧克力取出来，煮好的奶油均匀的倒进去；", "再倒入水饴；", "煮好的奶油倒进去之后，\n闷半分钟左右；\n\n奶油千万不要煮太久了，\n否则会造成巧克力油水分离，边缘冒泡泡就可以了；\n\n抹茶粉粉分三次过筛进去，是为了能搅拌的更均匀；", "轻轻搅拌；", "搅拌至巧克力和奶油充分融合，一定要轻轻的搅拌哈；", "搅拌融合的巧克力倒入模具里；", "刮平，不刮也没事，不影响食用；", "铺平后，放入冰箱冷藏3小时左右，或者冷冻1-2个小时，但这个时间不是绝对的，只要把它冻硬就可以了，不冻硬的话不好切；", "冻硬的生巧，从模具里取出来；", "反过来放着，揭掉硅油纸或保鲜膜；", "用尺子量量，平分成你喜欢的大小；", "切块，具体能切多少块的话，还要看你用多大的模具，一块量的尺寸是多少；", "均匀的撒一层可可粉；", "入口即化，好吃；", "抹茶味的也一样，冻硬后从模具里取出来；", "揭掉硅油纸或保鲜膜；", "用尺子量量，平分；", "还可以用心形模具压出形状，不过这样就会多出一些边角料，哈哈，我也就做了一个；", "绿心，哈哈哈哈；", "均匀的撒上一层抹茶粉；", "细腻顺滑的口感，不简直不要太好吃，有时间你也试试吧；", "做好的生巧，可以装入礼盒送给你的男朋友、女朋友了，嘻嘻.....\n\n祝大家七夕（情人节）快乐，有情人终成眷属，哈哈~"]'::jsonb, 30, 285, '困难', 3, 'https://i2.chuimg.com/055a5e7419da474ea9103c89c5610fa9_6000w_4000h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('|  27', '热门专题', '情人节', '', '[{"name": "杏仁粉", "amount": "80g"}, {"name": "红曲米粉", "amount": "4.8g"}, {"name": "糖粉", "amount": "80g"}, {"name": "蛋白", "amount": "29.2g"}, {"name": "杏仁粉", "amount": "20g"}, {"name": "糖粉", "amount": "20g"}, {"name": "蛋白", "amount": "7.3g"}, {"name": "蛋白", "amount": "36.5g"}, {"name": "水", "amount": "25g"}, {"name": "砂糖（煮糖浆用）", "amount": "90g"}, {"name": "砂糖（打发蛋白用）", "amount": "10g"}]'::jsonb, '["将两种面糊的TPT粉类分别过筛，混合均匀。加入未打发的蛋白，拌至无干粉状态。", "制作蛋白霜。然后称重，将蛋白霜分成80%和20%。", "80%的蛋白霜用来与红色红曲面糊混合，20%的蛋白霜用来拌原色面糊。", "最后，挤面糊的时候，先挤红曲面糊，然后用原色面糊在边上挤两个小点。\n\n详细见视频啊〜", "用牙签从圆点中间划过，小圆点就变成小心心啦。是不是很可爱呢～", "入炉烘烤后，搭配柠檬山楂夹馅，看着就很喜欢呀～\n\n夹馅做法 https://www.xiachufang.com/recipe/103731640/", "我们可以将红曲米粉换成可可粉，相似的做法，搭配巧克力乳酪夹馅。\n\n夹馅做法 https://www.xiachufang.com/recipe/102273602/"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/f6e6aca574c2404cbba80b3ce80986a5_2100w_2100h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('C.J', '热门专题', '宵夜', '', '[{"name": "1KG牛肉", "amount": "适量"}, {"name": "一大把干辣椒", "amount": "适量"}, {"name": "一大把干辣椒丝", "amount": "适量"}, {"name": "少量豆豉", "amount": "适量"}, {"name": "半个姜", "amount": "适量"}, {"name": "适量茴香", "amount": "适量"}, {"name": "八角", "amount": "2个"}, {"name": "香叶", "amount": "2片"}, {"name": "一大把辣椒面", "amount": "适量"}, {"name": "一小把花椒", "amount": "适量"}, {"name": "草果", "amount": "2个"}, {"name": "白蔻", "amount": "4个"}, {"name": "丁香", "amount": "4个"}, {"name": "肉蔻", "amount": "2个"}, {"name": "香叶", "amount": "2片"}, {"name": "适量花椒粉", "amount": "适量"}, {"name": "适量芝麻", "amount": "适量"}, {"name": "桂皮", "amount": "1块"}, {"name": "少量糖", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "少量料酒", "amount": "适量"}, {"name": "少量白酒", "amount": "适量"}]'::jsonb, '["干辣椒、干辣椒丝、姜片、香叶、八角、香叶、小茴香、肉蔻、白蔻、丁香、桂皮、豆豉（没有干的就用老干妈）装盘备用。", "调料图文科普……这会分的清了吧", "辣椒面（要有辣椒子那种）、花椒粉和白芝麻备用。", "水灼下牛肉 ，加姜片、花椒、白酒、料酒水开中火煮5分钟", "灼过后的牛肉，按个人喜好切备用，个人喜欢大块吃肉的感觉所以切的粗些。", "油温六成热时下牛肉条油炸。", "炸到牛肉条外表微焦金黄，捞出备用。", "炸牛肉的油留三分之一，调料中火炒出香味。", "炒香调料后，牛肉条、白糖、盐、生抽下锅。翻炒一会。", "炒均后加刚好没过食材的清水，大火烧开，转小火开盖煮30分钟。", "30分钟后大火收汁，收到大致没过食材一半的汤汁。", "辣椒面、花椒粉和白芝麻下锅。", "中小火多搅拌，慢熬3分钟。", "出锅前尝一下味道，根据个人口味调节味道。", "出锅自然凉凉。", "放凉后忍着口水，放进冰箱冷藏浸泡2小时以上，时间久点最入味😂😂", "冷藏结束，装盘搞定", "自己动手丰衣足食", "和去成都时吃的一个味道。", "自己动手丰衣足食", "End。"]'::jsonb, 30, 105, '困难', 3, 'https://i2.chuimg.com/05c7e0229fdf4beda48eb553fd038265_1280w_1024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('—', '热门专题', '减肥', '', '[{"name": "菠菜", "amount": "1把"}, {"name": "鸡蛋", "amount": "3个"}, {"name": "花生", "amount": "40克"}, {"name": "约15克香油", "amount": "适量"}, {"name": "盐", "amount": "1.5g"}, {"name": "4瓣蒜", "amount": "适量"}, {"name": "蚝油", "amount": "8克"}, {"name": "适量白芝麻", "amount": "适量"}]'::jsonb, '["材料准备", "鸡蛋打散，少量盐，锅中刷油，倒入适量蛋液，转锅一圈铺平，小火煎成蛋皮", "菠菜热水焯一下\n\n过凉水两遍，捞出沥干水分", "蒜泥准备好\n\n调汁：蚝油、生抽、香油、盐，按需放，不要太咸", "不粘锅花生无油煎煮，有油会脆一些", "撒芝麻和花生", "小花记录自己的低卡饮食，写了公众号：\n✅【公众号：厨小花】，上百道细致的菜谱等你来！\n✅ 小花低卡饮食群，喜欢可以去找我哦！VX：CXHXH2018，有问必答，让我们一起健康吃饭！"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/a7c76ea7fdca4f22bf88a30ccff5229f_1000w_750h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('6', '热门专题', '减肥', '', '[{"name": "鸡胸肉", "amount": "1块"}, {"name": "小米辣", "amount": "3个"}, {"name": "半个柠檬", "amount": "适量"}, {"name": "料酒", "amount": "1勺"}, {"name": "各1勺辣椒面，白芝麻，葱末，蒜末", "amount": "适量"}, {"name": "各2勺生抽，香醋", "amount": "适量"}, {"name": "蚝油", "amount": "1勺"}, {"name": "食盐，白糖", "amount": "1小勺"}]'::jsonb, '["鸡胸肉冷水下锅，放小葱，姜片，1勺料酒，煮十分钟左右，煮至筷子可以扎透后捞出晾凉，顺着纹路撕成细条状", "碗中放入1勺蒜末，1勺葱花，1勺辣椒面，1勺芝麻，浇上适量热油，再加入2勺生抽，2勺香醋，1勺蚝油，少许盐和糖，搅拌均匀", "柠檬切片去籽，小米辣切段，香菜切末", "调料汁浇在鸡丝上，放上辣椒段，香菜末和柠檬片，拌匀就可以吃了~"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/ae564cbfd61e436bb33f71498d7722f8_1536w_2048h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('308', '热门专题', '减肥', '', '[{"name": "勺橄榄油", "amount": "适量"}]'::jsonb, '["牛奶➕牛仔骨➕鸡蛋➕玉米➕西兰花➕胡萝卜➕平菇➕核桃", "牛奶➕火腿片➕鸡蛋➕南瓜➕荷兰豆➕玉米➕丝瓜➕青菜➕山药➕核桃", "牛奶➕鸡胸肉➕鸡蛋➕西兰花➕玉米➕蟹味菇➕荷兰豆➕胡萝卜", "牛奶➕小龙虾➕鸡蛋➕玉米➕丝瓜➕荷兰豆➕胡萝卜➕核桃仁", "牛奶➕小龙虾➕鸡蛋➕牛油果➕西兰花➕胡萝卜➕黄瓜", "牛奶➕牛仔骨➕鸡蛋➕玉米➕西兰花➕胡萝卜➕小番茄➕核桃仁", "牛奶➕马鲛鱼➕鸡蛋➕玉米➕蟹味菇➕西兰花➕胡萝卜➕核桃仁", "牛奶➕肥牛卷➕鸡蛋➕胡萝卜➕西兰花➕南瓜➕秋葵", "牛奶➕牛排➕鸡蛋➕玉米➕小番茄➕西兰花➕胡萝卜", "牛奶➕鸡蛋➕鸡胸肉➕牛油果➕紫薯➕胡萝卜➕西兰花➕腰果", "牛奶➕鸡胸肉➕鸡蛋➕紫薯➕茄子➕玉米➕蓝莓➕番茄➕黄瓜➕核桃仁", "牛奶➕虾仁➕鸡蛋➕玉米➕西兰花➕胡萝卜➕牛油果➕番茄", "牛奶➕火腿➕鸡蛋➕小龙虾➕玉米➕全麦馒头➕黄瓜➕核桃仁➕蓝莓", "牛奶➕牛仔骨➕鸡蛋➕紫薯➕玉米➕黄瓜➕蓝莓➕核桃仁➕番茄", "牛奶➕鸡蛋➕玉米➕红薯➕黄瓜➕鸡蛋➕番茄➕核桃仁➕芝麻丸", "牛奶➕鸡蛋➕虾仁➕玉米➕紫薯➕胡萝卜➕番茄➕牛油果➕核桃仁", "牛奶➕鸡蛋➕鸡胸饼➕玉米➕芦笋➕蓝莓➕小番茄➕核桃仁", "牛奶➕鸡蛋➕鸡胸饼➕牛油果➕蓝莓➕小番茄➕核桃仁➕胡萝卜➕香菇➕荷兰豆", "牛奶➕鸡蛋➕龙利鱼➕玉米➕红薯➕牛油果➕小番茄➕蓝莓", "牛奶➕鸡蛋➕玉米➕小番茄➕牛油果➕红薯➕核桃仁➕西兰花", "牛奶➕鸡蛋➕牛仔骨➕玉米➕西兰花➕小番茄➕牛油果", "南瓜➕紫薯➕蒸茄子➕鸡蛋➕番茄➕青菜胡萝卜", "煎三文鱼骨➕玉米➕杂粮饭➕西兰花➕胡萝卜➕番茄➕黄瓜", "玉米➕紫薯➕核桃仁➕金枪鱼➕青菜➕番茄➕鸡蛋➕牛油果", "煎三文鱼骨➕玉米➕西兰花➕鸡蛋加胡萝卜➕番茄➕牛油果", "玉米➕南瓜➕胡萝卜➕核桃仁➕豆角加鸡蛋➕番茄➕牛油果", "蒸鲈鱼➕豆芽➕紫薯➕牛油果➕黄瓜➕番茄", "玉米➕紫薯➕核桃仁➕小龙虾➕凉拌菠菜➕鸡蛋➕牛油果", "玉米➕核桃仁➕紫薯➕青菜➕西兰花➕胡萝卜➕鸡蛋➕番茄➕牛油果", "牛仔骨➕鸡蛋➕番茄➕牛油果➕玉米➕西兰花➕白玉菇", "牛排➕鸡蛋➕番茄加牛油果➕玉米➕西兰花➕蓝莓", "菠菜拌核桃仁➕鸡蛋➕番茄➕蓝莓➕玉米➕黄瓜➕小龙虾", "煎三文鱼骨➕番茄➕蓝莓➕牛油果➕杂粮饭➕鸡蛋➕青菜", "b牛仔骨➕鸡蛋➕牛油果➕玉米笋➕西兰花➕番茄➕蓝莓", "牛排➕鸡蛋➕牛油果➕玉米笋➕番茄➕蓝莓➕西兰花", "牛排➕鸡蛋➕西兰花➕牛油果➕玉米➕南瓜➕番茄", "基围虾➕鸡蛋➕牛油果➕全麦馒头➕南瓜➕番茄➕蓝莓", "牛仔骨➕鸡蛋➕蓝莓➕牛油果➕玉米➕黄瓜➕甜椒", "牛油果三文鱼➕鸡蛋➕番茄➕全麦馒头➕南瓜➕豌豆苗", "煎三文鱼➕鸡蛋➕黄瓜➕蟹味菇➕番茄", "白玉菇➕鸡蛋➕核桃仁➕牛油果➕全麦馒头➕南瓜➕红椒", "基围虾➕鸡蛋➕牛油果➕南瓜➕红椒", "金枪鱼➕鸡蛋➕牛油果➕玉米➕南瓜➕番茄➕蓝莓"]'::jsonb, 30, 215, '困难', 3, 'https://i2.chuimg.com/e198557294dc404eb34e4d046fd5fe9d_1280w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('|', '热门专题', '美容', '', '[{"name": "木瓜", "amount": "1个"}, {"name": "牛奶", "amount": "250ml"}, {"name": "9颗红枣", "amount": "适量"}, {"name": "冰糖", "amount": "30克"}, {"name": "适量枸杞", "amount": "适量"}, {"name": "适量清水", "amount": "适量"}]'::jsonb, '["备好以上食材", "木瓜洗净削皮后对半切，用勺子去掉瓜瓤，切小块备用", "红枣洗净后对半切，去核备用", "将切好的木瓜红枣跟冰糖放入锅中，倒入清水没过食材，盖上盖子煮五分钟左右。", "焖煮后，倒入牛奶，放入枸杞，煮1-3分钟后即可出锅，煮太久会导致营养流失噢！"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/dee658a66b284c15acacbd0678a2f604_1279w_1706h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('——', '热门专题', '婴幼儿', '', '[{"name": "黑芝麻", "amount": "75克"}, {"name": "核桃", "amount": "150克"}, {"name": "适量（可加可不加）糖", "amount": "适量"}]'::jsonb, '["75克黑芝麻清洗然后晒去多余水分备用", "150克核桃洗净晒掉多余水分。我儿子还小所以我没加糖哦，核桃外皮衣很有营养不要去掉哦", "核桃放入烤箱，150度上下火10分钟", "趁着烤箱烤核桃的时候我们先把芝麻倒入锅中炒数熟备用", "核桃烤好拿出。用酒瓶或者擀面杖敲碎核桃", "将敲碎的核桃与黑芝麻加入料理机。研磨几分钟你就会发现出油了哈哈", "大概这样就可以说拿到密封罐里了。大功告成"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/ae3f88bc40b24f4f9d493209c273266d_1280w_2702h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('—', '热门专题', '婴幼儿', '', '[{"name": "150--170g南瓜泥（黄色圆南瓜）", "amount": "适量"}, {"name": "面粉", "amount": "300g"}, {"name": "婴儿奶粉", "amount": "10g"}, {"name": "60--80g水（根据实际用量）", "amount": "适量"}, {"name": "酵母粉（我用的燕子牌）", "amount": "2.5g"}]'::jsonb, '["南瓜去皮去瓤切块上锅蒸20-30分钟至软烂。", "料理机或者料理棒打成泥，越细腻越好。", "将所有材料混合，用筷子先搅拌成絮状，再手揉或者机器（面包机厨师机）揉至表面光滑。面团软度应比饺子面团稍软，但是不要太软。", "室温发酵至", "8倍大。", "将发酵好的面团取出，分几次加入适量干面粉（我加了20g左右），将干粉揉进面团，排气完全，切开看横截面没有明显气孔。", "搓成长条，切段，上锅（垫油纸或者笼布）盖盖子醒发20-30分钟。开火，上汽后15分钟关火。焖三分钟后掀锅取出晾凉。", "分袋保存，冷藏三天，冷冻2周。"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/3334637c626e4b70a98c5cd70f80772b_480w_384h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('“”', '热门专题', '老人', '', '[{"name": "老鸭", "amount": "1只"}, {"name": "萝卜", "amount": "1条"}]'::jsonb, '["首先我们准备6个月左右的鸭子一只切掉脚掌黑色的物质和鸭屁股", "然后将鸭子剁成大小均匀的块备用\n同学们可以尽量剁大块一些", "准备白萝卜1个切掉头尾然后再切成大小均匀的滚刀块备用同学们白萝卜可以不用去皮（去皮太浪费）", "准备生姜1小块切成姜片备用", "再准备大葱2根切成小段备用", "首先我们在锅中加入适量的清水\n然后将剁好的鸭子冷水下锅焯水，中途加入适量的料酒开大火烧开，大火烧开之后再切去浮沫然后将焯好水的鸭子倒出备用", "然后我们把锅烧热，锅烧热之后加入适量的油滑锅，滑好锅之后将热油倒出之后再加入少许的底油，油温烧热后加入几颗青花椒，然后将焯好水的鸭子下锅转小火翻炒2分钟", "2分钟之后加入准备好的热水再加入切好的白萝卜和姜葱，然后开大火烧开", "大火烧开后再切去浮沫和多余的油脂\n然后把汤倒入小锅中再转小灶煮60分钟", "中途需要多次撇去浮沫和油脂", "中途再加入几颗红枣", "60分钟后揭开盖子加入适量的枸杞", "然后我们开始调味锅中加入食用盐2勺（约5克），加入少许胡椒粉调好味道之后即可出锅。", "一道营养丰富的老鸭萝卜汤就制作完成"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/49005205e09d4b4da07a5cf9712f1ae3_1668w_907h.png', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('“”', '热门专题', '老人', '', '[{"name": "里脊肉", "amount": "300克"}, {"name": "料酒", "amount": "25克"}, {"name": "胡椒粉", "amount": "1克"}, {"name": "鸡蛋清", "amount": "2个"}, {"name": "食用盐", "amount": "4克"}, {"name": "红薯淀粉", "amount": "25克"}]'::jsonb, '["首先准备里脊肉300克\n将里脊肉切成厚片之后再剁成肉碎\n这一步剁得越细越好\n将剁好的肉碎放入盆中", "准备生姜1小块和适量的小葱头一起剁碎放入盆中备用\n加姜葱末的目的是去腥增香", "盆中加入料酒25克\n加入胡椒粉1克\n加入2个鸡蛋清之后将肉碎搅拌均匀", "拌匀之后加入适量的食用盐（约2克）\n加入适量的红薯淀粉（约25克）\n然后将肉碎朝着一个方向搅拌10分钟\n这一步的目的是让肉碎搅拌上劲", "下一步开始准备辅料\n准备适量的豌豆苗（自贡叫法）放入盆中备用\n准备适量的紫菜放入碗中加入清水浸泡\n加紫菜的目的是增加鲜味", "下一步开始制作\n首先我们在锅中加入适量的清水开大火烧开\n大火烧开之后将锅离火", "然后将肉碎挤压成大小均匀的肉丸依次下入锅中\n同学们肉丸必须在低于100度的时候下锅\n这样的目的是防止肉丸被煮碎", "肉丸下锅之后转中小火煮4分钟\n中途需要随时撇去多余的浮沫", "肉丸煮熟之后开始调味\n锅中加入食用盐2克\n加入少许胡椒粉\n调好味之后加入泡发好的紫菜", "然后转大火将水烧开后加入豌豆苗烫熟", "豆苗烫熟之后加入几滴明油即可出锅", "一道非常美味营养的汆水丸子就制作完成"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/099334d0df2e4c0aaa9088a8c8b760ca_1667w_939h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('——', '热门专题', '老人', '', '[{"name": "日本豆腐", "amount": "2条"}, {"name": "半个洋葱", "amount": "适量"}, {"name": "尖椒", "amount": "1个"}, {"name": "蕃茄酱", "amount": "10克"}, {"name": "生抽", "amount": "2小勺"}, {"name": "白醋", "amount": "5滴"}, {"name": "白糖", "amount": "8克"}, {"name": "盐", "amount": "1茶匙"}, {"name": "小葱", "amount": "2根"}]'::jsonb, '["日本豆腐从中间切开，切成差不多厚度的，放进锅里煎", "等到一面差不多金黄了再翻面，尽量少动，太嫩了容易碎", "豆腐煎好了之后捞出来，锅里留适量底油。把洋葱和尖椒切成小粒", "把洋葱粒和尖椒放进去炒出香味。\n㊙️调汁：碗中加入2瓷勺番茄酱、1瓷勺生抽、1瓷勺陈醋、2茶匙白糖、1茶匙盐，然后将所有调料搅拌均匀。", "然后把煎好的豆腐放进去，倒入调好的酱汁", "让酱汁完全包裹住豆腐，收汁差不多的时候就可以关火了，撒上一点小葱，完美！又好看又好吃😋"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/010ae5ba459a4345ba6e85bbe4803c01_3024w_3024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('“”', '热门专题', '老人', '', '[{"name": "约200克里脊肉", "amount": "适量"}, {"name": "适量黄花菜", "amount": "适量"}, {"name": "适量黑木耳", "amount": "适量"}, {"name": "适量青瓜", "amount": "适量"}, {"name": "适量胡萝卜", "amount": "适量"}, {"name": "鸡蛋", "amount": "3个"}, {"name": "适量蒜末", "amount": "适量"}, {"name": "适量植物油", "amount": "适量"}, {"name": "适量明油", "amount": "适量"}, {"name": "适量小葱", "amount": "适量"}, {"name": "适量食用盐", "amount": "适量"}, {"name": "少许料酒", "amount": "适量"}, {"name": "生抽酱油", "amount": "5克"}, {"name": "适量白糖", "amount": "适量"}]'::jsonb, '["首先我们准备里脊肉1小块（约200克）\n将里脊肉切成", "5毫米左右的片", "然后再切成细丝备用\n通常来说鲜肉在切的时候容易不规则\n时间充裕的同学可以将其放入冰箱冻2个小时再切\n切的时候将肉片整齐的码放起来\n肉片码得越平坦越好切", "肉丝切好之后加入清水清洗干净\n因为鲜肉中会有血水和杂质", "清洗干净之后挤干水份下一步准备腌制\n碗中加入少许食用盐和料酒", "然后将肉丝搅拌均匀收紧水份\n拌匀之后加入适量的植物油拌匀\n这一步的目的是让其下锅不粘连\n此菜不勾芡不加水\n所以在腌制肉丝的时候不用加淀粉和鸡蛋", "下一步开始准备配菜\n准备适量的黄花菜和黑木耳\n将泡发好的黄花菜和木耳撕开备用\n这一步的目的是为了更好的将其炒透", "准备适量的青瓜和胡萝卜切成菱形片备用\n同学们也可以将其换成玉兰片", "准备鸡蛋3个打入碗中", "加入少许食用盐搅散备用\n蛋液最好能够充分的朝着一个方向搅拌\n这样的目的是让空气进入\n让鸡蛋能承受高温煎制", "下一步开始制作\n首先我们在锅中加入适量的清水开大火烧开\n大火烧开之后加入准备好的黄花菜和木耳焯水40秒\n中途再加入少许的食用盐\n木耳属于菌类食物必须加热熟透\n否则快炒不熟透容易发生危险", "焯水熟透之后倒出备用\n然后把锅烧热\n锅烧热之后加入适量的植物油", "油温6成热之后将蛋液下锅煎至金黄干香\n同学们油多煎蛋必须开大火\n否则鸡蛋不发泡容易吸油", "中途再翻过来煎另一面\n鸡蛋煎香之后倒出备用", "锅中再次加入适量的油烧至4成热\n油热之后将其腌制好的肉丝下锅滑散\n肉丝滑散之后倒出备用", "锅中留下少许的底油\n然后加入适量的蒜末爆香", "蒜末爆香之后加入青瓜和胡萝卜炒至断生", "中途再加入木耳和黄花菜炒香炒出锅气", "辅料炒香之后加入处理好的肉丝和鸡蛋下锅", "然后加入生抽酱油5克从锅边淋入翻炒均匀", "翻炒均匀之后再加入适量的食用盐和白糖调味", "再加入适量的明油翻炒几下", "最后再加入几根小葱炒至断生即可出锅装盘", "一道口味丰富的木须肉就制作完成"]'::jsonb, 30, 120, '困难', 3, 'https://i2.chuimg.com/65fcaee11a8d4995a02bbc5cb9e633c5_3840w_2160h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('——', '热门专题', '宝宝食谱', '', '[{"name": "（去皮后）山药", "amount": "330克"}, {"name": "鸡蛋", "amount": "2个"}, {"name": "糖", "amount": "20克"}, {"name": "中筋面粉", "amount": "300克"}, {"name": "奶粉", "amount": "20克"}, {"name": "酵母", "amount": "5克"}, {"name": "玉米油", "amount": "20克"}]'::jsonb, '["山药洗干净，去皮，切断，放入蒸笼中（这时的山药是330克）。大火烧开后蒸10分钟左右，用筷子轻松扎透就是蒸好了。", "蒸好的山药用勺子压成泥，不能有颗粒。", "山药泥中倒入中粉、白砂糖、奶粉、鸡蛋、酵母和玉米油。", "用筷子搅拌成絮状，再用手揉成一个光滑的面团，覆盖保鲜膜松弛10分钟。", "将松弛好的面团放到揉面垫上，撒一层手粉，将面团擀成薄面片，约5mm左右的薄片，擀均匀一点。", "用圆形模具压出形状，我做的是小饼，用的是3cm的模具。也可以用大点的模具来压出形状，但是厚度要随着山药饼的大小适当调整。", "将压好的小圆形摆入烤盘，覆盖保鲜膜，送至温暖处醒发。", "现在天气热，我是室温醒发50分钟左右，看到面片明显变胖，用手指轻轻摁压，会有慢慢的回弹，就发酵完成了。", "将小饼放入不粘锅内，锅内不要抹油，不要抹油，不要抹油，重要的事情说三遍。开小火慢慢煎，煎的过程中可以盖上锅盖，让锅内的温度更加均衡。", "一面煎成金黄色，翻面，小火继续煎。", "两面都煎成金黄色就可以出锅了。", "一个个软乎乎的山药小饼就做好了，超松软哟！", "掰开一个看看，内部蓬松，捏一下，回弹超好，相信你一定能看得出来它是有多松软！", "赶快给宝宝吃一个吧！"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/e34338b7c58a4018bf3d94fcfc345ad2_3551w_2000h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('()', '热门专题', '宝宝食谱', '', '[{"name": "红枣", "amount": "20克"}, {"name": "山药", "amount": "90克"}, {"name": "鸡蛋", "amount": "1个"}]'::jsonb, '["将去皮的山药，红枣(去皮不去皮都可)，鸡蛋全部放入搅拌机里搅打3分钟以上。", "玻璃碗模具铺油纸，刷油。", "倒入打好的糊糊，盖上保鲜膜，用牙签扎小孔。", "上锅蒸20分钟左右。最后脱模切块。"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/6ed17d6079754d24be2602f987e72768_2866w_2294h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('()', '热门专题', '宝宝食谱', '辣', '[{"name": "一块瘦肉", "amount": "适量"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "5-6朵木耳(提前泡发洗净)", "amount": "适量"}, {"name": "香菜或柿子青椒醋", "amount": "适量"}, {"name": "香醋", "amount": "1勺"}, {"name": "半勺淀粉", "amount": "适量"}, {"name": "糖", "amount": "2勺"}, {"name": "香菜", "amount": "3根"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "料酒", "amount": "1勺"}, {"name": "耗油", "amount": "1勺"}, {"name": "番茄酱", "amount": "1勺"}, {"name": "2-3勺清水", "amount": "适量"}]'::jsonb, '["瘦肉切丝，可以用猪里脊或者鸡胸肉。\n用五香粉，盐，淀粉，老抽，料酒拌匀腌10分钟入味。", "另取一只碗，调鱼香汁：\n糖2勺，醋1勺，耗油1勺，生抽2勺，番茄酱1勺，清水2勺", "锅里放入平时炒菜那么多的油。烧热。", "油热后把姜丝煸香。底油有味，菜才会好吃。不吃姜的可以把煸干的姜丝捞出来。", "下入肉丝，滑散。", "滑散的肉丝，变色后，盛出。尽量把底油留下。", "肉丝盛出后，锅里还剩这么多油。其实肉丝不吸油。底油足够用。如果这时候你的底油不多了，可以酌情加一点。", "油热后，放入胡萝卜和木耳丝。\n如果不喜欢胡萝卜可以换成青笋丝。", "胡萝卜丝炒软以后，木耳也熟了。", "放入之前过油了的肉丝。翻炒均匀", "倒入之前调好的鱼香汁。", "开中火，收汁，直到粘稠。", "放入香菜，翻拌片刻。即可出锅。\n如果不爱吃香菜可以换成绿色的柿子椒。", "一份色香味俱全的儿童版鱼香肉丝就OK了。\n超级下饭哦(´-ω-`)"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/b85eaa5b1e5f4409ac2a46f8964e190a_750w_750h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('C', '热门专题', '味蕾工坊', '', '[{"name": "百香果（大）", "amount": "4个"}, {"name": "一瓶优益C", "amount": "适量"}]'::jsonb, '["挖出4个百香果的果肉，放在杯子里，冲入一瓶优益C，搅拌即可～嘿嘿", "完成效果图～", "尽情畅饮吧～～～😁"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/edced9cddc784d42ab98f44d81cc8cc0_4032w_3024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('68 100%', '烘焙甜品饮料', '蛋糕', '', '[{"name": "6寸", "amount": "适量"}, {"name": "鸡蛋", "amount": "3个"}, {"name": "牛奶", "amount": "40克"}, {"name": "玉米油", "amount": "35克"}, {"name": "低筋面粉", "amount": "50克"}, {"name": "糖", "amount": "30克"}, {"name": "几滴柠檬汁", "amount": "适量"}, {"name": "8寸", "amount": "适量"}, {"name": "鸡蛋", "amount": "5个"}, {"name": "牛奶", "amount": "85克"}, {"name": "玉米油", "amount": "40克"}, {"name": "低筋面粉", "amount": "100克"}, {"name": "30糖", "amount": "适量"}, {"name": "几滴柠檬汁", "amount": "适量"}]'::jsonb, '["如图准备好以下材料，分别将牛奶、玉米油、糖、低筋粉用秤把克数称好，配方在上面可以直接照着做", "准备一个干净的盆，将牛奶和玉米油倒入盆中疯狂搅拌至乳化", "筛入低筋面粉，搅拌均匀", "将鸡蛋清蛋黄分离，倒入分离好的蛋黄，把蛋清放入冰箱冷藏5分钟", "搅拌至面糊顺滑滴落有轻微堆叠状", "将冰箱冷藏过的蛋清用打蛋器打发至大气泡，加第一次糖，打蛋器中速继续打发", "继续打发蛋白有淡淡纹路，加第二次糖低速继续打发", "打发至出现明显纹路，加第三次糖，继续用低速打发，边缘也要打到，打不到的地方那刮刀刮到中间打发，保证每个部位都打发充分！", "打发成直立小尖勾", "取三分之一蛋白加入蛋黄糊中搅拌均匀，可以用打蛋器轻轻搅拌", "再将剩余的蛋白分次倒入蛋黄糊中，用打蛋器轻轻搅拌至无白色颗粒丝滑状", "翻拌好的面糊倒入6寸磨具中", "将另一半倒入8寸模具中，轻轻震几下，用牙签在表面来回画圈圈以此来消除表面的泡泡。", "烤箱145度烤45分钟，这个温度烤出来的戚风蛋糕面上会裂开，可以试试140度烤45分钟，根据自己家烤箱的脾气。", "取出烤好的蛋糕出炉重摔三下!!!震出热气后马上倒扣放凉！倒扣后等完全晾凉后再脱模！", "烤出来的6寸非常漂亮", "8寸也很漂亮"]'::jsonb, 30, 85, '困难', 3, 'https://i2.chuimg.com/55918407e036474eab2ca546096fa274_1280w_1706h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('8', '烘焙甜品饮料', '蛋糕', '', '[{"name": "鸡蛋", "amount": "5个"}, {"name": "牛奶", "amount": "60g"}, {"name": "玉米油", "amount": "50g"}, {"name": "面粉", "amount": "90g"}, {"name": "白砂糖", "amount": "60g"}]'::jsonb, '["准备好工具，大概就这些，精简就好", "盆中先打入5个鸡蛋，然后放冰箱冷冻", "碗中加入60g牛奶、50g玉米油", "用蛋抽搅匀", "加入低筋面粉90g，“Z”字形手法搅拌均匀", "从冰箱拿出冷冻的鸡蛋，将5个蛋黄捞出", "蛋抽“Z”字形手法搅拌", "蛋白打发", "打至出现泡泡，加入白砂糖20g", "打至细泡，再加入白砂糖20g", "打出出现纹路，加入最后20g白砂糖", "继续打发，直到提起打蛋器出现小弯勾", "蛋白打发好后，这个时候可以来预热烤箱，上下火160度，45分钟", "蛋白分出一半先加入蛋黄糊中，翻拌均匀", "将翻拌均匀的蛋黄糊倒入剩下打发好的蛋白中", "翻拌均匀", "倒入8寸蛋糕模具中", "放进预热好的烤箱，上下火160度烤45分钟", "烤好后，拿出轻震一下，倒扣晾凉，等蛋糕凉后再从模具中取出", "蛋糕体很松软，回弹好"]'::jsonb, 30, 100, '困难', 3, 'https://i2.chuimg.com/69bc9182e3b6475ea071721d83fffa72_1231w_977h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('——', '烘焙甜品饮料', '蛋糕', '', '[{"name": "（每个55-60克）鸡蛋", "amount": "8个"}, {"name": "牛奶", "amount": "115克"}, {"name": "玉米油（加热至70℃）", "amount": "75克"}, {"name": "低筋面粉", "amount": "145克"}, {"name": "白砂糖", "amount": "90克"}, {"name": "玉米淀粉（可不加）", "amount": "10克"}, {"name": "柠檬汁", "amount": "5克"}, {"name": "可可粉", "amount": "2克"}]'::jsonb, '["（蛋清蛋黄分离，蛋清放冷冻到有冰渣）\n\n低筋面粉过筛放入盆中，油加热到70-80℃，倒入面粉中，快速搅匀\n\n用烫面法做出来的古早蛋糕更加柔软轻盈！", "倒入牛奶，搅匀\n\n➕蛋黄，继续搅匀，提起打蛋器是这种状态", "开始打发蛋白，挤入柠檬汁\n\n先开高速打至有鱼泡眼，➕1/3糖\n继续打到有小气泡，➕1/3糖\n中速打至有纹路，➕剩下的糖\n\n开低速整理纹路，用刮刀刮一下盆壁，打至有小尖尖！干性打发（我试过打到足够发，不会回缩塌陷）", "取1/3蛋白放入蛋黄糊中翻拌均匀，倒入剩余蛋白中，混合均匀 倒入模具中！\n\n25克面糊➕可可粉混合均匀，倒入裱花袋，剪一个小口子！\n\n裱花袋口子不要贴面糊太近，倾斜45度，拉长条", "拿根筷子垂直方向，划出千叶纹路", "烤箱提前预热，145℃，60分钟\n放中下层，最后10分钟，➕10℃开热风\n\n⚠️密封性好的烤箱，夹锡纸棒", "出炉，震出热气\n我没有用油纸，倒扣晾凉至手温，脱模，晾凉切块\n\n如果是垫了油纸，出炉直接拿出来放在晾网上晾凉再撕开油补", "切块，完美！密封冷藏保存", "比戚风蛋糕绵密湿润"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/99f43ef7dd464dbfb5d4b0a9447e2643_1280w_1706h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('yyds', '烘焙甜品饮料', '面包', '', '[{"name": "面团部分：", "amount": "适量"}, {"name": "高筋面粉", "amount": "310克"}, {"name": "牛奶", "amount": "185克"}, {"name": "全蛋液", "amount": "35克"}, {"name": "鲜酵母", "amount": "10克"}, {"name": "细砂糖", "amount": "35克"}, {"name": "盐", "amount": "4克"}, {"name": "奶粉", "amount": "10克"}, {"name": "黄油", "amount": "30克"}, {"name": "椰蓉馅：", "amount": "适量"}, {"name": "蛋黄液", "amount": "60克"}, {"name": "细砂糖", "amount": "45克"}, {"name": "奶粉", "amount": "15克"}, {"name": "椰蓉", "amount": "75克"}, {"name": "黄油", "amount": "45克"}]'::jsonb, '["首先准备好所需食材\n厨师机桶中倒入面团材料（除了黄油和盐以外）", "慢速搅拌成团后转中高速揉面", "揉至可以拉出厚膜", "加入软化的黄油和盐慢速搅拌至吸收，转中高速揉面", "揉至可以拉出薄膜即可", "面团送入发酵箱发酵至2倍大小", "将面团分割成9个揉圆盖保鲜膜松弛15分钟", "制作椰蓉馅，蛋黄液加入细砂糖和奶粉搅拌均匀", "倒入椰蓉拌匀", "倒入软化的黄油拌匀", "将椰蓉分成9个，送入冰箱冷藏", "面团松弛完毕，拍扁后包入椰蓉馅", "取一个面团擀开，尽量擀大一点", "翻面对折", "再次对折", "用锋利的刀切口", "将面团往两边翻开", "全部同样的操作，放入烤盘中，送入发酵箱36度发酵", "发酵至2倍大小，表面刷一层蛋液", "送入提前预热好的烤箱，上火190度下火180度烘烤15分钟左右，每个人的烤箱不同，烘烤时间温度仅作为参考！", "出炉后轻震烤盘，放凉即可食用！"]'::jsonb, 30, 105, '困难', 3, 'https://i2.chuimg.com/245592b4599e4fbcb80cd724fe2526c3_1701w_1361h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('---', '烘焙甜品饮料', '面包', '', '[{"name": "---种面---", "amount": "适量"}, {"name": "水", "amount": "50克"}, {"name": "高筋面粉", "amount": "50克"}, {"name": "（0.5克）鲜酵母（干酵母）", "amount": "1.5克"}, {"name": "---可可面团---", "amount": "适量"}, {"name": "牛奶", "amount": "100克"}, {"name": "（3克）鲜酵母（干酵母）", "amount": "9克"}, {"name": "高筋面粉", "amount": "150克"}, {"name": "可可粉", "amount": "9克"}, {"name": "白砂糖", "amount": "25克"}, {"name": "盐", "amount": "1克"}, {"name": "所有种面", "amount": "适量"}, {"name": "黄油", "amount": "15克"}, {"name": "25- 30克耐高温可可豆", "amount": "适量"}, {"name": "适量70%巧克力", "amount": "适量"}]'::jsonb, '["种面部分材料全部混合均匀，室温发酵至2-3倍大，或者提前一晚做，种面混合后直接冷藏发酵一夜", "这是我在阳台上大概32度发酵2小时后的样子", "拨开有密密麻麻的气孔", "除黄油，可可豆和巧克力以外，可可面团材料中加入种面", "3档低速混合，5档揉出粗膜", "加入黄油，3档混合，5档揉出薄膜", "加入巧克力豆，揉匀，室温发酵", "发酵至两倍大", "发酵好的面团取出排气，平均分割成8份，每一份大约", "9克，盖保鲜膜松弛15分钟", "取出面团，手按压扁，翻面，中间包入巧克力，收口", "团圆，发酵至", "表面可以刷蛋液，我不想浪费一颗鸡蛋，就刷了牛奶~~", "180度预热烤箱，然后上下火180度烤10分钟，出炉后趁热再刷一层牛奶", "来张美照~肉眼可见的柔软", "给你们感受下~~~", "咬一口~真的超浓郁~~~~~快去做~"]'::jsonb, 30, 85, '困难', 3, 'https://i2.chuimg.com/c507e820dc644eb08f0d0989a11726bb_1280w_917h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('BSK', '烘焙甜品饮料', '披萨', '', '[{"name": "低筋粉（饼底）", "amount": "40克"}, {"name": "高筋粉（饼底）", "amount": "160克"}, {"name": "水（饼底）", "amount": "110克"}, {"name": "白糖（饼底）", "amount": "10克"}, {"name": "盐（饼底）", "amount": "1克"}, {"name": "酵母（饼底）", "amount": "4克"}, {"name": "橄榄油（饼底）", "amount": "15克"}, {"name": "（4肥6瘦）猪肉碎（披萨酱）", "amount": "500g"}, {"name": "（偏小）洋葱（披萨酱）", "amount": "2个"}, {"name": "（偏小）番茄（披萨酱）", "amount": "4个"}, {"name": "适量番茄酱（披萨酱）", "amount": "适量"}, {"name": "大蒜（披萨酱）", "amount": "2个"}, {"name": "少量黑胡椒粉（披萨酱）", "amount": "适量"}, {"name": "桂皮（披萨酱）", "amount": "3块"}, {"name": "适量盐（披萨酱）", "amount": "适量"}, {"name": "根据自己喜好放多或者少马苏里拉芝士碎", "amount": "适量"}, {"name": "培根", "amount": "3片"}, {"name": "左右虾仁", "amount": "12个"}, {"name": "适量豌豆、胡萝卜粒 、玉米粒", "amount": "适量"}]'::jsonb, '["大蒜、洋葱和肉搅碎备用", "番茄🍅搅碎备用", "不粘锅内倒入少许玉米油，蒜碎炒香，倒入洋葱碎翻炒", "洋葱炒香后加入肉碎继续翻炒", "待肉发白倒入打碎的番茄碎", "加入适量番茄酱（提色），加入桂皮和月桂叶、胡椒粉翻炒", "中火慢熬，待汤汁收干加入适量盐，披萨酱就做好啦。PS：酱一定要炒干水分！！！", "把面饼的材料依次（水、糖、盐、油、面粉）放入面包机，在面粉里掏个小坑埋入酵母，面包机一个发面程序就好了。", "取一个10寸的披萨盘，面皮慢慢碾开，用叉子叉满小孔，发酵一会儿。", "铺上自制披萨酱", "铺一层芝士碎，铺一层培根，再摆好虾仁🍤", "摆好虾仁后再铺一层芝士碎，加点蔬菜（豌豆、胡萝卜粒、水果玉米粒，提前煮好，挤干水分哦），再根据自己喜好撒上一层芝士碎。", "烤箱210度预热后放入披萨，15分钟就可以啰！", "自己做的饼底真的超好吃😋", "您学会了吗？等您上传您的作品哟……"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/840b82372e1f43818e1861524e1fe835_1242w_994h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('0', '烘焙甜品饮料', '派', '', '[{"name": "香蕉", "amount": "1根"}, {"name": "蛋挞皮", "amount": "8个"}]'::jsonb, '["香蕉切碎，取8个蛋挞皮解冻后放入香蕉碎，撕掉锡纸（我这个忘记了，后面撕掉了😂）对折捏紧封口。每个蛋挞皮上面划三刀并且刷上全蛋液两次，撒少许黑芝麻点缀，欧克啦😌", "送入烤箱，烤箱温度180度 时间15分钟"]'::jsonb, 6, 10, '简单', 3, 'https://i2.chuimg.com/d7dc26a172ca4a18aa5ee4ada5f4eb8b_1906w_1427h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('Classic Blueberry pie', '烘焙甜品饮料', '派', '', '[{"name": "派皮：", "amount": "适量"}, {"name": "通用面粉", "amount": "300克"}, {"name": "砂糖（可选）", "amount": "50克"}, {"name": "海盐", "amount": "1克"}, {"name": "无盐黄油", "amount": "226克"}, {"name": "冰水", "amount": "45ml"}, {"name": "伏特加（或者替换成冰水）", "amount": "30ml"}, {"name": "蓝莓馅", "amount": "适量"}, {"name": "（5 cups蓝莓", "amount": "500克"}, {"name": "（3tbsp柠檬汁", "amount": "45ml"}, {"name": "1tbsp柠檬皮屑（可选", "amount": "适量"}, {"name": "通用面粉", "amount": "30g"}, {"name": "砂糖", "amount": "50克"}, {"name": "一撮盐", "amount": "适量"}, {"name": "1tsp肉桂粉", "amount": "适量"}, {"name": "增加色泽", "amount": "适量"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "适量奶油", "amount": "适量"}]'::jsonb, '["先来制作派皮，将黄油🧈切成小块和面粉盐糖混合揉搓直至呈砂粒状。\n加入水和伏特加（也可替换成水）揉成面团，放冰箱冷藏。", "制作蓝莓馅🫐：将所有材料混合", "根据干湿程度自行加柠檬汁或者面粉", "从冰箱拿出来备用的面团，分成两份。案板上撒面粉面团上也撒一点防粘，把其中一份擀成大饼，放在模具上，用叉子在底部叉洞，倒入馅料。", "另一份面团也擀成饼，切成条条，编花篮。", "编花篮示意图", "切掉边缘多余的面皮，捏紧边缘", "烤箱提前预热200度20分钟转170度30-40分钟或者直至派皮金黄蓝莓爆开。 在烤的时候如果发现派的边缘上色太快可以围一圈锡纸防止烤糊。", "对了，烤之前别忘了刷蛋液，我刷的是奶油哈哈", "放凉后配上冰激凌🍦享用吧💗", "拥有甜食的一天才算完整啊嘿嘿🍬🍬(*¯︶¯*)", "再来一张图嘿嘿，美味❤️"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/31dc64a6d7494b2aae0f89e235634feb_1280w_1228h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('Savoury Scones', '烘焙甜品饮料', '司康', '', '[{"name": "普通面粉（低粉中粉都行的）", "amount": "250g"}, {"name": "黄油（切成小块）", "amount": "60g"}, {"name": "培根", "amount": "160g"}, {"name": "葱末", "amount": "35g"}, {"name": "奶酪碎", "amount": "100g"}, {"name": "一小撮盐", "amount": "适量"}, {"name": "泡打粉", "amount": "7g"}, {"name": "糖", "amount": "20g"}, {"name": "奶油", "amount": "100g"}, {"name": "2颗鸡蛋", "amount": "适量"}]'::jsonb, '["160g培根切成小方块，放在一个锅里，锅里不用放油，然后中火煎，直到四周开始变得焦黄~", "差不多这个样子就可以了，然后放一边，放凉~", "在一个空盆里放入250g低筋面粉，和切成小块的60g黄油。", "用手搓，或者用搅拌器搅拌，黄油被面粉包裹，但依然有小颗粒的黄油的时候就可以接下来的步骤啦~", "往黄油和面粉的盆里放入：已经凉了的培根，葱末35g，奶酪碎100g，盐一小撮，泡打粉7g，糖20g，奶油100g，鸡蛋两颗~", "搅拌~搅拌~搅拌~\n用刮刀搅拌或者用搅拌机，当然，你也可以选择用手~等混合的差不多了就停，如果过度搅拌最后的成品就不酥松啦~这时候的面团应该是比较粘的。", "在干净的桌上铺上一张保鲜膜，然后撒一点干粉，再把刚才的混合物倒在上面。隔着保鲜膜或者用手把面团弄成一个圆形，稍微按扁一点。注意：用手碰面团之前稍微抹一点干粉喔，不然会黏手哒~", "就是这个样子~", "然后用保鲜膜包好，放冰箱冷藏十五分钟，让面团松弛一下，同时让各种味道更好的融合一下~\n*你要是超级有耐心的话，放几个小时，或者放冰箱过夜，第二天再烤更好！！！", "十五分钟到！拿出来，切成6大块~", "移到烤盘上", "刷点牛奶", "放入提前预热好的烤箱，200度烤20分钟左右~\n\n烤的时候好香好香好香", "拍张照片，交作业\n然后就可以享用啦~\n不要问我为什么少了一块，我也不！知！道！"]'::jsonb, 30, 70, '困难', 3, 'https://i2.chuimg.com/f2fa1ecfdccb4fd6800f5e40dcc8681a_2202w_1652h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('super easy crunched scone', '烘焙甜品饮料', '司康', '', '[{"name": "面粉", "amount": "150克"}, {"name": "泡打粉", "amount": "4克"}, {"name": "盐", "amount": "2克"}, {"name": "糖", "amount": "30克"}, {"name": "奶粉", "amount": "10克"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "淡奶油", "amount": "10克"}, {"name": "适量蔓越莓", "amount": "适量"}, {"name": "黄油", "amount": "60克"}, {"name": "适量杏仁", "amount": "适量"}]'::jsonb, '["所有粉类干性材料混合均匀", "蔓越莓或者蓝莓干浸在水中泡开（放巧克力忽略这步），奶油倒入鸡蛋打散，黄油切小块", "黄油先放入粉类混合物中，搓揉进面粉", "加入蛋液混合物、蔓越莓（蓝莓干、巧克力豆）杏仁，揉成面团（揉至成型即可，切勿过度）用保鲜膜包裹，放进冰箱冷藏1小时后取出，切成六块", "烤箱预热至180度，每块面团涂抹牛奶或者蛋液，放入烤箱烤20分钟", "噹！趁热或者放凉都超好吃，比外面售卖的黄油味更突出，不仅酥脆且有坚果香。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/86fc0aa7ba85482e943a229c1c64ace6_1616w_1242h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('——', '烘焙甜品饮料', '司康', '甜', '[{"name": "低筋面粉", "amount": "250克"}, {"name": "（这个糖量不是很甜，喜甜的可以加量哦）细砂糖", "amount": "35克"}, {"name": "盐", "amount": "2克"}, {"name": "泡打粉", "amount": "6克"}, {"name": "无盐黄油", "amount": "70克"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "牛奶", "amount": "60克"}, {"name": "适量蔓越莓", "amount": "适量"}, {"name": "适量红蜜豆", "amount": "适量"}]'::jsonb, '["准备好材料。蔓越莓切碎，无盐黄油软化（是软化，不是融化哦），鸡蛋打散。", "将低筋面粉、细砂糖、盐、泡打粉混合均匀，加入软化的黄油，用手抓松抓匀，抓到小小的絮状就行了。", "加入打散的鸡蛋液（鸡蛋液留一点最后的时候刷表面用），继续抓匀抓松。留一小把抓好的粉出来备用，最后做酥顶用。", "往面粉盆里加入牛奶，揉匀，揉好的状态应该是没有干粉，可以成团。别太干，太干了整形会裂开，烤完口感会很干；也别太烂，太烂了粘手没法整形。（不同牌子的面粉吸水量不同，建议加牛奶时候最后留一点看面团情况进行调节。）", "将揉好的面团分成两份，分别用手按扁按圆，厚度大概", "5cm就好了。在其中一份按扁的面团上均匀铺上红蜜豆。铺好了轻轻按压一下，让蜜豆和面团贴合。", "将另一块按扁按圆的面团覆盖在上面，上下两块面团边缘接口处捏紧。", "刷上预留的鸡蛋液。铺上蔓越莓干，用手轻轻按一下，使蔓越莓干和面团贴合，防止烤的时候脱落。撒上之前预留的酥顶。", "将饼切成若干块。", "烤盘铺上油纸，把切好的饼分别放到油纸上，各块之间留点空隙，别挨太紧。烤箱预热190度。", "放烤箱中层，上下火190度，15分钟。（各家烤箱脾气不同，具体大家可以自己摸索哈，最后两分钟留意一下上色）", "噔噔噔噔~松脆可口，摸索摸索可以把蔓越莓蜜豆换成葡萄干啊、巧克力豆啊、蓝莓啊……各种配料做成花式松饼。", "把蔓越莓换成杏仁片也是很好吃哒～"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/b49513509c044f73a6dfa1d4dd59b641_2448w_1957h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('2', '烘焙甜品饮料', '塔', '辣', '[{"name": "⬇️❤️塔皮：", "amount": "适量"}, {"name": "低筋面粉", "amount": "200克"}, {"name": "黄油", "amount": "90克"}, {"name": "糖粉", "amount": "45克"}, {"name": "蛋液", "amount": "25克"}, {"name": "盐", "amount": "1克"}, {"name": "⬇️❤️枫糖味坚果：", "amount": "适量"}, {"name": "枫糖（蜂蜜）", "amount": "25克"}, {"name": "黄油", "amount": "25克"}, {"name": "砂糖（可减）", "amount": "15克"}, {"name": "综合果仁", "amount": "220克"}, {"name": "盐", "amount": "0.25克"}, {"name": "⬇️❤️麻辣味坚果：", "amount": "适量"}, {"name": "蜂蜜", "amount": "25克"}, {"name": "黄油", "amount": "25克"}, {"name": "砂糖（可减）", "amount": "15克"}, {"name": "综合果仁", "amount": "220克"}, {"name": "盐", "amount": "0.25克"}, {"name": "辣椒碎", "amount": "2克"}, {"name": "花椒碎", "amount": "1克"}]'::jsonb, '["坚果提前准备好～\n\n这个综合果仁我是自己搭配的，随意搭配了一些巴旦木，南瓜籽，核桃仁，夏威夷果，蔓越莓～就是家里刚好有的东西就好了～\n\n总量220克一种口味即可～你们随意啦，喜欢就好～\n\n蔓越莓和南瓜籽还是建议放，这两个有颜色上的搭配毕竟", "除蔓越莓之外的果仁全部倒入烤盘中～", "130度30-40分钟，中途可以稍微翻动一次～坚果可以提前一天烤熟～备用", "黄油提前软化，天冷可以使用烤箱发酵功能软化，也可以使用发酵箱，吹风机等等～", "黄油软化至手指可以轻松戳洞即可～开发酵软化很快的～二十来分钟就好了，又不会像做热水或者微波炉那样不均匀～", "料理机中加入：软化黄油，低筋面粉，蛋液，糖粉，盐～\n\n这一步，绞肉机厨师机也可以的～绞肉机没有的就上手吧～直接揉", "打成这样的细沙状～即可～", "倒在台面上～他不干不干不干～天气冷而已～往下看", "用手来回搓～借助你的手温～这样面团更均匀～家里太冷会搓的时间长～可以开小太阳来照耀一下你的手～", "成一个光滑的团子～", "上下各一张烘焙油纸～", "擀面杖来回擀～", "杆成厚薄均匀约3毫米的面片～", "拿出一个叉子～\n\n扎好之后送去冰箱平躺冷冻15-20分钟", "扎洞是为了烘烤膨胀不变形～", "我的12连模底宽", "5～\n\n有磨具的直接用磨具吧，我反正不想买～\n\n这个也没有的话，往下看，自己做～我写了～\n\n蛋挞模抠来用一下也可以哈哈哈哈哈哈哈～\n\n办法总比困难多～姐妹", "所以我找一个约", "5宽的圈圈～\n\n🌟就是说，你的圈，比你的托大2-3厘米就够了～\n\n你可以用矿泉水瓶，玻璃杯等东西来刻这个圈圈～", "没有磨具的怎么办～自制～用完还能回收做纸杯蛋糕～哈哈哈哈哈～真是个奇奇怪怪的博主～", "冰箱取出，刻圈～", "当然，如果你有这种花边的圈圈会更好看～我不想买了～哈哈哈哈哈～", "尽量放在正中间～", "全部弄好～没看错，就是12连蛋糕磨具，倒扣过来的样子哈哈哈哈", "边角料～重新擀开，扎洞，冷冻，刻圈～重复以上动作～\n\n\n后面实在太少了就算了～直接搓圆烤了吃掉或者留着下次用吧～", "不管做啥，都要提前预热烤箱，好习惯要保持\n\n预热的时候开热风，温度上来的更快更均匀～\n\n送入提前预热好的烤箱～175度15分钟～", "放两分钟不那么烫手了，手轻轻一推就脱模啦～不会粘～趁热去弄容易碎～\n\n我连续烤了两盘～一共24个～", "侧面看一下～不放在正中间的话，就会不平，一边高一边低～所以你们要耐心点哦～乖", "枫糖（蜂蜜），黄油，砂糖，盐～加入锅中～", "25克盐就是：1小撮盐，什么是一小撮，两根手指头抓一丢丢丢～", "小火煮至焦糖色，出现密集的小泡泡～", "倒入提前准备好的坚果～快速翻拌均匀，让每一颗坚果都裹上糖浆～", "另起一锅：枫糖（蜂蜜），黄油，砂糖，盐～加入锅中～", "25克盐就是：1小撮盐，什么是一小撮，两根手指头抓一丢丢丢～", "辣椒碎2克，花椒碎1克～", "加入糖浆里面去～看到辣椒了吗？", "搅拌均匀～", "戴手套，把坚果放在塔皮上面～用勺子也行～", "两种口味都弄好了～", "150度5-8分钟～热风～坚果和塔壳都熟的～这一步只是为了加热一下，使坚果和塔壳亲密结合一下～所以，两层也没关系～热风可以加速空气循环🔄", "翻出两月饼包装袋～密封一下～", "麻辣味～你一定要试试～", "枫糖味～你更喜欢哪个味儿？"]'::jsonb, 30, 215, '困难', 3, 'https://i2.chuimg.com/37157383b61b43c296351658c7e28c14_1616w_1077h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('-cupcake', '烘焙甜品饮料', '奶油霜', '', '[{"name": "奶油奶酪", "amount": "200克"}, {"name": "動物性淡奶油", "amount": "250克"}, {"name": "糖粉", "amount": "50克"}, {"name": "10mL利口酒(喜歡才加)", "amount": "适量"}]'::jsonb, '["奶油奶酪提前拿出冰箱室溫軟化", "把奶油奶酪隔熱攪至順滑無顆粒\n要加利口酒就這時加\n和奶油奶酪一起攪拌至融合", "淡奶油一次性加入糖粉\n打發至八分發", "把步驟2 加入 步驟3\n一起打發到融合\n不要打發過了哈\n會油水分離的\n建議這步用手動打蛋器", "把打發好的奶酪鮮奶油包上保鮮紙放入冰箱冷藏2小時\n做這步的目的是讓鮮奶油變硬\n裱花的時候花形更立體漂亮\n如果個不是完美主意者可以立即用啦", "我是把奶油直接裝袋放入冰箱的", "來做一個奶酪鮮奶油草莓搭😋"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/a6865465fc8740e8b0a91adfc8177649_1280w_1023h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('( )', '烘焙甜品饮料', '奶油霜', '', '[{"name": "铁塔淡奶油", "amount": "300g"}, {"name": "阿尔卑黄油或伊利白油", "amount": "200g"}, {"name": "白糖或砂糖", "amount": "30g"}, {"name": "适量柠檬汁", "amount": "适量"}]'::jsonb, '["200g黄油室温软化，伊利白油和阿尔卑发酵黄油是目前市场上性价比较高，颜色偏白适合裱花用的黄油(如果想做出白白的奶油霜不建议选用其他品牌黄油)", "打发黄油直至发白", "取100g铁塔淡奶油+30g糖，微波炉加热或隔水加热至糖融化(铁塔奶油在常用的几个牌子里是成色较白的，建议不要替换其他牌子，除非比铁塔白)", "加入冷藏的200g淡奶油(加热后的淡奶油会变黄，所以这里我们只取少量淡奶油加热融化糖，热奶油加冷藏的奶油刚好达到室温，做奶油霜温度正合适)", "淡奶油中加少许柠檬汁调味，并混合均匀", "分数次把淡奶油倒入黄油中并打发", "打到光滑，我们就得到了超白的奶油霜"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/939230bb70c24de8b17d60f7f96e77f5_2048w_3072h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('/', '烘焙甜品饮料', '奶油霜', '辣', '[{"name": "见下方正文奶油", "amount": "适量"}, {"name": "见下方正文各辅料", "amount": "适量"}]'::jsonb, '["一、巧克力奶油\n\n这个算是比较常用的奶油，黑森林蛋糕必备款。\n\n黑巧克力20g   淡奶油100g   细砂糖5g  稳定酱适量（可选，可不加）  细砂糖视巧克力口味增减\n\n⒈\n①黑巧20g，淡奶油100g隔水加热融化，不要超过60度，加入砂糖融化均匀。\n②冷藏隔夜降温至2-6度，隔冰水打发。\n⒉\n①黑巧20g，淡奶油20g隔水加热融化，不要超过60度，冷藏2小时至凝固。\n②凝固的巧克力奶油加适量淡奶油稳定酱打散，加入30g淡奶油打均匀，加入50g淡奶油打发。\n\n★★★这里包括下面的隔夜不是必须的，冷藏4小时以后就可以用了，但是很多时候隔夜的效果更好。这里的隔冰水也不是必须的，隔冰更好打发。加稳定酱的奶油，看稳定酱状态分次加奶油打均匀后打发。", "二、抹茶奶油（椰子/酸奶/可可味）\n\n抹茶粉3g  淡奶油30g  淡奶油100g  淡奶油稳定酱适量（可选） 白巧克力20g（可选）  细砂糖视巧克力口味增加\n\n⒈\n①抹茶粉3g淡奶油30g隔水加热混合均匀，成为无颗粒无团的抹茶酱。\n②冷藏隔夜降温至2-6度，取出加入100g奶油打发。\n⒉\n①抹茶3g淡奶油30g隔水加热混合均匀，加入白巧克力20g融化搅拌均匀。慢慢加入100g奶油使混合物温度升高，不要超过60度，并搅拌均匀。\n②冷藏隔夜至2-6度，隔冰水打发。\n\n★慢慢加入100g奶油，一次性加进去会使前面的混合物凝固。\n★如需加入稳定酱，先在抹茶奶油酱里加入稳定酱打散，在分次加入奶油打均匀后打发。\n★★★抹茶的储存，低温避光密封防潮，请入冰箱\n★★★这里很多人问过我为什么要加热，第一因为抹茶稍微加热后香味会更浓郁，第二是因为这种操作打出来抹茶不会结团起小疙瘩\n★抹茶酱+冰块打碎就是抹茶冰沙啊，加个奶油顶就是星冰乐\n\n★★★抹茶粉换成椰子粉可可粉酸奶粉按口味适量增加后，与奶油煮开，隔夜冷藏即可\n★椰子粉是叶子饮料，不是椰子面粉\n★酸奶粉是酸奶饮料，不是带菌的发酵粉。酸奶不能用", "三、乳酪口味奶油\n\n奶油奶酪30g  淡奶油20g  糖10g  淡奶油200g  淡奶油稳定酱适量（可选，可不加）细砂糖视自己口味增加\n\n①奶油奶酪隔水软化至糊糊状\n②淡奶油20g糖粉10g隔水加热至融化，加入糊糊状的奶油奶酪搅拌均匀，成为奶油奶酪酱\n③冷藏降温至2-6度，加入200g奶油打发\n\n★比例大概为30g奶酪酱100g奶油。\n★如需加入稳定酱，先把奶油奶酪酱与稳定酱混合打匀，再分次加入奶油打均匀后打发。", "四、伯爵红茶味奶油/奶茶味奶油\n\n一包红茶粉/5g红茶粉   淡奶油50g   细砂糖5g  淡奶油100g  稳定酱适量（可选）  细砂糖视自己口味增加\n\n①取一个红茶包，大概5g红茶粉，拆掉纸包只留茶粉，加入淡奶油50g和砂糖5g，开小火煮，不断搅拌，煮出红茶的颜色咖啡色和浓郁茶香关火。\n②将煮好的红茶奶油过筛，去掉茶粉。冷藏隔夜降温至2-6度备用。\n③取出冷藏好的红茶奶油酱，加入100g奶油打发。\n\n★建议翻倍做，量太少容易煮干，可以烧开以后离火焖\n★可以用红茶茶叶，多加点奶油煮或者离火焖都可以。红茶酱+牛奶就是奶茶啊👀\n★如需加稳定酱，将红茶奶油酱与稳定酱一起打散开，再分次加奶油打均匀后打发。", "五、咖啡味奶油\n\n现磨咖啡豆粉7g/速溶黑咖啡粉1-2g  淡奶油100g  吉利丁片", "5～1g  细砂糖10g  淡奶油稳定酱适量（可选，可不加）  细砂糖是自己口味增加\n\n①吉利丁片冷水泡软备用\n②黑咖啡粉与淡奶油混合，加入加糖小火熬煮出颜色及香味。煮好的咖啡奶油过筛，去掉咖啡粉。\n③保持咖啡奶油温度50-60度左右，放入泡好的吉利丁，搅拌融化。入冰箱隔夜冷藏，降温至2-6度。隔冰打发。\n\n★如需加入稳定酱，先将稳定酱打散，分次加入咖啡奶油打均匀后打发。\n★咖啡酱+热牛奶就是拿铁啊", "六、奥利奥奶油\n\n甜咸两口味，需要那种用哪种。\n\n淡奶油100g  奥利奥饼干沫10g  细砂糖10g  盐一撮  淡奶油稳定酱适量（可选，如抹面建议加）\n\n①奥利奥碾细末备用\n②淡奶油加糖（如需咸口此时加入盐一撮），打至七成发。\n②加入奥利奥沫，翻扮两三下，再打两三圈就好。\n\n★如需加入稳定酱，先把稳定酱打散一下，再分次加入奶油打均匀后打发。", "七、黑芝麻/核桃/杏仁口味淡奶油\n\n黑芝麻糊/核桃糊/杏仁糊粉（超市有售，比如南方黑芝麻糊）15g   淡奶油30g   淡奶油100g   淡奶油稳定酱适量（可选） 细砂糖视自己口味增加\n\n①各种糊的粉15g混合淡奶油30g，加热煮成糊状，这个必须加热一下才会香，都知道糊糊用凉水是冲不开的哈。冷藏降温至2-6度。\n②取出做好的糊糊，加入100g淡奶油打发。\n\n★这里的味道会比较淡一点，因为糊糊的粉里添加了其他辅料。如果需要味道浓郁可以下拉使用坚果酱调味\n★如需加入稳定酱，先与糊糊打均匀，再分次加入淡奶油打均匀后打发", "八、焦糖奶油/太妃奶油\n\n选这张图的时候，我就想到一句话，海盐焦糖巧克力，完美的搭配。\n\n细砂糖20g  奶油25g  黄油5g  海盐一撮  淡奶油200g  淡奶油稳定酱适量（可选）\n\n①加热25g奶油备用，不能太凉\n②取小号平底不沾锅，放入砂糖，翻炒至融化。加入加热过的奶油，熬煮至焦糖色，放入黄油，海盐，煮至浓稠，入冰箱冷藏降温至2-6度。既为海盐焦糖酱。\n（★焦糖酱如果大量制作起来保存，可以把熬煮淡奶油含量增加至50-75g，打发的时候适量减少就可以了。）\n③冷藏好的海盐焦糖酱，加入200g奶油打发。\n\n★比例大概为100g奶油20g焦糖酱。\n★如需加入稳定酱，先与焦糖酱混合打均匀，再分次加入奶油打均匀后打发。\n★海盐焦糖酱可以翻倍做，干净无水的玻璃瓶保存，调味蘸酱都很好吃。\n★焦糖酱水份会炒干一些，大概成品40g左右。量少不太好做，建议至少翻倍。不翻倍就注意经常离火不要让水份都蒸发没了，那就成一块太妃糖了……\n★★量少不好控制的话，熬的酱凉了以后会成为太妃糖😂😂建议①酱晾凉到40–50度左右，把200g奶油加热到40-50度。把奶油倒进焦糖酱拌匀，冰箱冷藏一夜直接打发。②同第一种办法加入50g温热奶油并冷藏，用的时候再加150g奶油打发。\n★焦糖酱+咖啡就是焦糖玛奇朵啊", "九、柠檬味奶油/百香果奶油\n（糖渍橙皮和柚子皮也适合加入奶油，但不适合做凝乳，做果酱更好一些）\n\n柠檬奶油制作稍微麻烦一些，状态也不太好掌控，多做几次熟练就好了。柠檬奶油要先做柠檬凝乳，也可以说是柠檬酱。不管是慕斯还是奶油还是其他奶制品，都是用柠檬凝乳去调味，而不是直接加柠檬。直接加柠檬汁奶油会变简易马斯卡彭。\n\n蛋黄1颗   细砂糖30g  新鲜柠檬汁25g  黄油15g  柠檬皮屑适量  淡奶油100g  淡奶油稳定酱适量（建议使用）\n\n①蛋黄细砂糖新鲜柠檬汁柠檬皮入小不锈钢盆，搅拌均匀不需打发。加入切小丁的软化的黄油。\n②烧一盆水，隔水加热①，慢慢搅拌，不要让蛋黄凝固，稍微粘稠就可以离火了。状态是用勺子背沾取酱，中间画一道，有明显痕迹即可。\n③这时候可以直接放冰水降温，没有冰水冷藏降温到2-6度。即成为柠檬凝乳。\n④20g柠檬凝乳混合100g奶油打发，撒适量柠檬皮装饰。\n\n★建议加入淡奶油稳定酱，这个奶油状态软一些。先把凝乳与稳定酱打均匀，再分次加入奶油打均匀后打发。\n★这里只写了蛋黄版柠檬凝乳，全蛋版也可以用，全蛋版下厨房加州厨房有写，自行搜一下哈。\n★百香果凝乳做法同柠檬凝乳，柠汁换去籽百香果汁，可以多加5-10g，去掉柠檬皮即可～", "十、果蔬口味奶油\n\n适用于任何有冻干粉的果蔬，用水果的时候多一些，但南瓜紫薯这类蔬菜也可以搭配出很好吃的口味，比如焦糖巧克力南瓜味，莓果芝士紫薯味。这里只能使用冻干粉，烘干研磨的不行不行不行不行不行。\n\n果蔬冻干粉5-15g（果蔬味道有浓有淡，根据自己果蔬情况去调节）  淡奶油30g  淡奶油100g   果粒适量（可选）  淡奶油稳定酱适量（可选） 细砂糖视自己口味添加\n\n①取适量冻干粉混合30g淡奶油，小火加热至冻干粉融化，冷藏降温至2-6度。\n②果蔬奶油酱，加入100g奶油打发。\n③如果用来夹心，可加适量鲜果粒或果干果粒，增加口感。\n\n★紫薯南瓜这些，选熟的粉调色用。不要加热的太热，会成为紫薯泥南瓜泥……\n★如需加入稳定酱，果蔬奶油酱与稳定酱混合打散，分次加入奶油打均匀后打发。", "十一、罗勒味/薄荷味奶油\n\n罗勒作为香料来说，咸口比较容易被人接受。清甜口带清香气息也还不错。但是毕竟是进口来的调料，国人还是接受程度差一些。但是用来辅佐正宗欧包和特殊口味甜品还是很好吃的，搭配柠檬或者松子就别有风味。也可以搭配各种粗粮及坚果。\n\n薄荷呢是接受程度比较高的一款香草，口味清新为主，适合搭配柑橘类口味，青柠柚子甜橙都很好吃，很是清爽。\n\n新鲜罗勒/薄荷叶子适量  清水几滴  淡奶油100g  吉利丁片1g  细砂糖10g/海盐", "5g  淡奶油稳定酱适量（可选）  柠檬皮碎沫适量（可选）\n\n⒈\n①吉利丁片冷水泡软备用\n②新鲜香草叶子切细碎，取2/3放入容器，加一点水捣出汁，取一小勺用就够了。剩余1/3切的细细碎碎的，考验刀功的时候到了。\n③过筛香草泥，取汁，加入100g淡奶油小火煮沸并搅拌大概半分钟一分钟的，蒸发一下水份，关火。（这一步吃咸口加盐，吃甜口加糖融化，或者此时不加，打发时在加）\n④降温至60度左右，加入泡好的吉利丁，搅拌融化。继续降温至30度以下，放入1/3切细碎的香草沫沫，翻扮几下就行了。\n⑤入冰箱冷藏隔夜降温至2-6度，取出打发。（这一步没调味的进行调味，可以加入一点柠檬皮碎末提一下清香味道，不要加多掩盖香草香味）\n⒉\n★因为这里增加的香草汁水份并不多（没有超过5g），所以直接打发也可以\n①同上面第二步\n②过筛香草泥，取汁，加入100g奶油打发。\n③加入香草碎末翻扮均匀。可以加入一点柠檬皮碎末提味。\n\n★如需加入稳定酱，分次加入奶油打均匀后打发。\n★量大可以直接搅拌机或者均质机打成香草泥来用不用过筛，因为本身细腻。也可以粗略过掉大纤维", "十二、麦片奶油（更建议做奶油霜）\n\n这个奶油是看人家做学来的，只因为很好看😂😂只是在做好的奶油里加了宝氏的彩色麦片，但是因为麦片的特性，所以更建议做奶油霜。\n\npost宝氏水果味彩色麦片适量  任意口味淡奶油  建议加一点稳定酱\n\n①彩色麦片碾碾碎备用\n②准备打发好的奶油，麦片加进去拌匀", "十三、天然色素奶油，植物本身味道，不能做太深的上色哈\n\n蝶豆花茶（蓝紫色）/山栀子（黄色）/甜菜切片（红色）适量   奶油   细砂糖  稳定酱适量（可选，建议加）\n\n天然色素帖子已经单独更新，查看新帖使用\n\n★如需加入稳定酱，先将稳定酱打散，分次将冷藏好的奶油加入稳定酱打均匀后打发。\n★黑枸杞，藏红花理论上也适用于这个方法给奶油调色，不过价格太贵了！请土豪尝试。\n★班兰叶（香兰叶）打汁过滤后直接加入也可以，加热会变色", "十四、坚果类奶油\n\n这一类是可以买到坚果酱，来调制奶油。有榛子酱，腰果酱，夏威夷果酱，杏仁酱，开心果酱，核桃酱，还有经常吃的花生酱和芝麻酱。对，芝麻酱就是麻汁…这里推荐入手的是开心果酱，颜色碧绿，口感香醇，虽然原料贵，但是成品确实特别好吃。用来做慕斯马卡龙或者夹心都不错。坚果适合搭配巧克力，黑白巧都好吃。\n\n增加口感用的坚果碎，芝麻这一种，要碾一下，直接放芝麻粒不好吃。就是北方常用芝麻盐里那种碾碎的。\n\n这里要提一下栗子泥，栗子泥也属于坚果，但并不适合用在这里。上面提到的都是油性的坚果酱，栗子泥是水性的。用栗子泥来装饰蛋糕，是栗子泥加黄油打顺滑，加奶油调节一下软硬度就可以。详细方法查阅蒙布朗配方。\n\n坚果酱5-20g  淡奶油100g  淡奶油稳定酱适量（可选，建议用） 同类坚果碎适量（可选）细砂糖视自己口味增加\n\n①奶油打发到有点粘稠的时候，加入坚果酱继续打发。\n②打发后的奶油可以视情况加入适量坚果碎增加口感。\n③建议加入淡奶油稳定酱，坚果酱先与稳定酱打均匀再分次加入奶油打发。\n\n★坚果酱和糖浆一样都要适量加，加太多了会造成奶油过于软。\n★这里用的是可流动性的坚果酱，超市里有种花生酱没有流动性，干干的膏状，那个适合做饼干，不适合打发。", "十五、利用果茸与果酱调味\n\n常见的果茸有安德鲁果茸、宝茸果茸。果茸即新鲜的水果浓缩，法式甜点里经常用到，调味或者制作镜面都很不错。我个人喜欢树莓和椰子，这两种都属于水果不好储备的。果酱就不说了，可以是自己熬的果酱，这个要求稠一点，也可以是售卖的果酱。不建议用新鲜水果，水份太多。\n\n果茸或果酱10-20g  淡奶油100g  细砂糖适量  淡奶油稳定酱适量（可选，建议用）\n\n①淡奶油100g，打发至粘稠，加入果茸或果酱，继续打发。\n②果茸和自制果酱含水多一些，市售果酱内有胶质。所以用果茸和自制果酱建议加入稳定酱，先把稳定酱与果茸打均匀，再分次加入淡奶油打均匀后打发。", "十六、调味糖浆奶油\n\n调味糖浆因为口味太多就不一一写了，可以某宝搜一下。常用的是莫林糖浆、达芬奇糖浆、法布芮糖浆、特朗尼糖浆。口味方面个人觉得枫糖、薄荷、玫瑰味是一定要入手的，其他的就看自己喜好了，比如我自己就格外喜欢樱桃和桃花口味。如果你不确定喜欢哪个口味，可以先去喝杯鸡尾酒🍸，调酒师那里糖浆比较齐活。口味方面每个人都不一样，但是调味糖浆却是增加甜品风味的好搭档，不止可以用在奶油里，比如我就会在情人节推出桃花口味甜点，在七夕推出玫瑰风味甜点。\n\n调味糖浆5-20g  淡奶油100g  淡奶油稳定酱适量（可选，建议用）  细砂糖视自己口味添加\n\n①奶油打发到稍微有点粘稠的时候，加入糖浆继续打发。\n②建议加入淡奶油稳定酱，糖浆先与稳定酱打均匀再分次加入奶油打发。\n\n★加入糖浆的奶油质地会软一丢丢，看糖浆添加量。如果加太多糖浆很有可能奶油软趴趴，所以不要加多，根据情况适量加。所以这里建议加少量稳定酱。\n★有些糖浆会带有颜色使奶油上色，如果觉得不好看可以适量增加色素。", "十七、花式酒味奶油\n\n终于更最后一个了，写到这就觉得浑身轻松精神爽。烘焙中常用的酒有咖啡力娇酒、黑白金朗姆酒、君度力娇酒、樱桃白兰地力娇酒等等。再简单一点，力娇酒都适合提风味，芭菲力娇各种水果力娇口感都甜甜的。甚至还包括伏特加龙舌兰白兰地，只要搭配得好，对于甜点来说都是一种特色。\n\n做法也相当简单，奶油打到9成发状态，加适量调味酒打匀就好了。\n\n适量的意思是你自己看着办，调你自己需要的味道，别来问加几克了，这个不固定！建议加一点稳定酱。\n\n★先打发再加酒避免了奶油打不发和泄的过快"]'::jsonb, 30, 95, '困难', 3, 'https://i2.chuimg.com/f1f129246a1711e7bc9d0242ac110002_640w_640h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('-', '烘焙甜品饮料', '布丁', '', '[{"name": "牛奶", "amount": "250克"}, {"name": "细砂糖", "amount": "15克"}, {"name": "（一片半）（或7克吉利丁粉）吉利丁片（或吉利丁粉）", "amount": "7.5克"}]'::jsonb, '["吉利丁片放入凉水中浸泡备用，注意一定要用凉水。大概十几分钟就会泡软。", "家里的普通袋装牛奶一包，剪开放入小奶锅，加糖，开小火边加热边用手动打蛋器搅拌至白糖融化。待牛奶微微沸腾后关火。", "牛奶晾至温热不烫手。将泡好的吉利丁片放入牛奶中，轻轻搅拌至融化。注意不要用力搅拌以免产生过多气泡。（对腥味敏感的朋友可以加几滴柠檬汁）", "这里注意啦！我有让牛奶布丁变得超可爱的小窍门啦！拿出秘密武器—装蛋黄酥的小圆盒！将小圆盖放在小盆里使其固定不倒，把牛奶混合液轻轻倒进去吧！做完大概是三个的量！\n当然如果你放在任何你喜欢的容器里都是可以哒！只是这个圆圆滚滚白白胖胖实在可爱！", "端着小盆放进冰箱冷藏，大概", "5小时就会成型。时间久点效果会更好哦！", "取出布丁，倒扣在盘中脱模，按照自己的想法装饰一下吧！我放的玫瑰花酱，香香甜甜的，放水果丁也很棒，清凉爽口哦！\n脱模小妙招：1手轻轻按着布丁向内侧稍微用力，布丁和模具时间会出现小缝隙，沿着缝隙倒一点点的牛奶或者蜂蜜，过一会液体渗入就能轻易倒扣脱模啦！2可以用吹风机在模具四周吹几圈热风。3用热毛机裹住模具四周和底部。\n另外如果用蛋黄酥模具，可以剪掉多余的、没装满布丁液的一圈塑料壳，脱模会更容易！", "看，餐桌上的焦点，超级简单，做来试试吧！"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/23676bd91c1c4a338496e3323a751810_1836w_2448h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('Lemonade', '烘焙甜品饮料', '冷饮', '', '[{"name": "柠檬", "amount": "5个"}, {"name": "白砂糖", "amount": "250克"}, {"name": "250毫升纯净水", "amount": "适量"}, {"name": "1400毫升冰冻纯净水", "amount": "适量"}]'::jsonb, '["制作糖水：白砂糖250克", "纯净水250毫升", "倒入锅中，上灶大火融化。", "融化过程中，不停搅拌，直至白砂糖完全融化，不需要将糖水煮沸。", "糖水制作完成，放凉，备用。", "挤柠檬汁：5个柠檬洗干净，对半切开，准备开挤。（温馨提示这可是体力活啊）", "记得切两片柠檬片，去籽，备用。", "挤好的柠檬汁及果肉", "将之前切好，去籽的柠檬片放入壶中。使用过滤网，过滤出柠檬汁。", "用小勺压一压，不能浪费。", "过滤好的柠檬汁", "加入放凉的糖水", "加入冰冻纯净水，我用的是农夫山泉550ml装的，用了", "又加了2片薄荷和冰块，真是太好喝了。", "媳妇拍的，好看啊。"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/dccd6636c90d4bb78b8ee91ea68f4364_3024w_2419h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('4', '烘焙甜品饮料', '果酱', '', '[{"name": "草莓", "amount": "700克"}, {"name": "柠檬", "amount": "1个"}, {"name": "180-200克白砂糖", "amount": "适量"}]'::jsonb, '["新鲜草莓洗干净，控干水份", "切成小块", "加入白砂糖", "搅拌均匀", "放入冰箱冷藏24小时", "倒入无油锅中", "大火翻炒至草莓变软，炒的时候用锅铲不停的捣碎草莓", "转中火熬出胶，继续捣碎草莓", "出胶，果肉也变细腻了", "关火倒入柠檬汁", "搅拌均匀", "先来一口尝尝😊😊，酸酸甜甜", "待冷却后，装入密封罐，放冰箱可保存两三个月。", "配上吐司面包，太好吃啦😋", "视频图示"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/25434306cd184bcb8c53cdec8d4ec290_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('1⃣', '烘焙甜品饮料', '糖水', '', '[{"name": "（去皮净重）六鳌红薯🍠", "amount": "300克"}, {"name": "木薯粉", "amount": "227克"}, {"name": "————————-", "amount": "适量"}, {"name": "（去皮净重）紫薯🍠", "amount": "300克"}, {"name": "木薯粉", "amount": "108克"}, {"name": "————————-", "amount": "适量"}, {"name": "（去皮净重）土豆🥔", "amount": "300克"}, {"name": "木薯粉", "amount": "197克"}, {"name": "—————————", "amount": "适量"}, {"name": "适量白糖", "amount": "适量"}]'::jsonb, '["今天做的是三色芋圆，所以就用三种，粗粮去皮洗干净切块放锅里蒸熟，筷子能扎透就熟了，今天买不到好的芋头，就用这三种！", "准备三个碗，各装上木薯粉备用！", "粗粮取出三个颜色各拿一个盆子装上，趁热用铲子压泥，喜欢甜的就是这个时候加点白糖。然后加一勺木薯粉拌，要是湿还可以加一勺，⚠️⚠️紫薯比较干先加一勺。", "大概加图中的状态。", "各取一部分煮熟团，今天材料300克，捏这么大煮熟团就够了，⚠️紫薯比较干，要是觉得松散熟团可以多煮一点点，用手捏长，无论多难捏你尽量捏这样，揪成小剂子扔滚水里煮，煮芋圆一样。", "煮熟浮起来（我比较懒三种一起煮）煮好捞起倒主面团里，也可以一种一种煮", "煮好分别倒主面团里，用铲子拌均", "倒入一勺木薯粉拌均,倒出桌面手搓揉，用点巧劲加蛮力推揉，揉几下加粉继续揉（粉不能一下子加太多，加多干了还得用水补救那样就不好吃了）就这样揉啊揉揉成一个软度适中的光滑面团", "揉面手法图中演示，土豆芋圆（娃爸拍的）", "紫薯比较干，松散，刚开始你们会怀疑失败了，想加水，哈哈哈哈😂⚠️⚠️（喜欢糯的不需要加一滴水。喜欢Ｑ的就加一点点刚才煮熟团的水）只要有耐心揉几分钟弹性会越来越好。", "看看紫薯的弹性，真的太好了！我这里没有加一滴水！🤪⚠️如果还是有点松散熟团再煮一点点补救就行了，毕竟紫薯比较干！", "变这样就揉的差不多了，再用力揉一会儿OK！紫薯加的粉实在少，所以是最好吃的😋", "三个依次揉好的面团，（我粉没有称，做好才称出准备比例，不要问我粉剩的问题了🤣）", "用保鲜膜包下防止干了，有空就马上做，没空的亲包起来空了做，不是醒面⚠️也可以分开包，防止串色。这个时候带娃的妈妈就可以先去哄宝宝睡觉了，去两小时没问题，我都是分两次做，等会儿做的时候再揉揉依然是柔软的面团。", "撒少许干粉搓。很轻松就能搓条，娃帮我拍一个揉面视频。", "补一个芋圆搓条", "好漂亮的说，撒一些干粉均匀摸下", "揉好直接切，切好撒干粉防粘！", "美美哒，不需要整形，再撒一些干粉防粘", "三色混合", "煮一点尝尝，水烧开把芋圆仍进去煮膨胀浮起捞出。", "冲冷水想吃Q的这部很重要，冲下倒糖水里。", "我今天加的是牛奶😋，为了方便就加这个。⚠️⚠️甜汤可以加冰镇的奶茶、椰汁，椰浆、牛奶、喜多多、红豆汤，燕窝，银耳汤，然后上面铺一些蜜豆、仙草、珍珠、椰果、坚果、水果、可以吃的很丰富营养，尽情发挥想象😄", "芋圆煮好冲凉倒一杯一点点奶茶好吃😋", "🤩🤩🤩这份是牛奶蜜豆仙草芋圆", "这里金黄的就是小小的板栗🎃南瓜做的，很软糯😋", "上次还搓小小的当珍珠给小朋友吃❤️", "我喜欢像煮面一样吃，哈哈哈哈😂", "冷冻后的芋圆。后期还会继续发一些更详细的图，比如差不多比例😄", "晒晒😄😄", "一斤斤打包好的👌", "有问题留言，附上图片问问题，失败了找我帮你补救!一有时间我就回复，谢谢🙏不卖芋圆！"]'::jsonb, 30, 160, '困难', 3, 'https://i2.chuimg.com/b0b08d155a6446de9f0164f16e728a75_1656w_1242h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('|', '烘焙甜品饮料', '果冻', '', '[{"name": "白凉粉", "amount": "16克"}, {"name": "沸水", "amount": "400克"}, {"name": "（按个人口味增减）细砂糖", "amount": "15克"}, {"name": "随意各种水果", "amount": "适量"}]'::jsonb, '["准备材料", "水果切开。", "放入碗中。", "锅中放入白凉粉和细砂糖拌匀。", "开大火，沸水慢慢倒入锅中，边倒边搅拌。", "煮沸关火。", "倒入碗中。", "冷却后放冰箱冷藏风味更佳。", "清甜Q弹的水果冻做好了，一起来品尝吧～"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/f7deae47852d4ea2aefa5c15c7f21be9_1124w_1500h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('~', '烘焙甜品饮料', '果冻', '', '[{"name": "水", "amount": "400克"}, {"name": "糖", "amount": "40克"}, {"name": "白凉粉", "amount": "16克"}, {"name": "5-6朵茉莉花", "amount": "适量"}, {"name": "5-6朵菊花", "amount": "适量"}]'::jsonb, '["准备好茉莉花菊花，放入泡茶器", "加入400克开水，盖上盖子泡几分钟。\n\n（其实你也可以直接在锅里把菊花、茉莉花、白凉粉、糖全准备好了然后搅拌均匀）", "称40克白砂糖，16克白凉粉。", "这是我在某宝上买的白凉粉，2包才8块钱还包邮，超级划算。\n\n一克粉比25克水/液体。所以做之前先算好多少水要放多少粉就可以了。", "将茶汤、白砂糖、白凉粉都放入锅中，搅拌均匀，直到砂糖融化。然后煮开", "起锅晾凉，常温放凉后可以放冰箱冷藏，味道更佳哦。\n\n超级晶莹剔透，要不是它是热的，我都觉得可以拿来做蛋糕的镜面了😜（脑洞太清奇）", "脱模，切块就能吃了，完美！"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/f2dfdb45e9b54a98b5e33f2536ca2d34_1080w_1440h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('400', '烘焙甜品饮料', '咖啡', '', '[{"name": "1尖汤匙（勺子能装的最大份量）速溶咖啡", "amount": "适量"}, {"name": "1尖汤匙糖", "amount": "适量"}, {"name": "1平汤匙（表面与边缘平齐）热水", "amount": "适量"}, {"name": "牛奶或淡奶", "amount": "适量"}]'::jsonb, '["将1尖匙咖啡（小包的直接一包进）、1尖匙糖、1平匙开水依次放入杯中，用汤匙拌匀，大概是图中这个样子。", "左手手掌整个握住杯子下部，右手拿汤匙快速划圈搅拌杯中的混合物，搅拌大概几百次（官方说法是400次），到最后变成了浓稠的浅色的花生酱状。（和上图不是同一次做的）", "倒入开水搅匀，根据咖啡的种类和自己的口味加入淡奶、牛奶或者省略，即可享用。", "将咖啡酱舀到牛奶上，就出现分层的效果啦！如果能打至不流动了效果更好（但是喝还是要搅匀了喝唷）", "再发个动图。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/6072fbe15dd545f494aadf786a80274f_909w_918h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('ICED MATCHA LATTE', '烘焙甜品饮料', '咖啡', '', '[{"name": "【抹茶拿铁】", "amount": "适量"}, {"name": "2茶勺抹茶粉", "amount": "适量"}, {"name": "1到2大勺热水", "amount": "适量"}, {"name": "1cup温水", "amount": "适量"}, {"name": "适量冰", "amount": "适量"}, {"name": "加了冰块后几乎1咖啡杯的3/4满你喜欢的牛奶（原方是杏仁奶）", "amount": "适量"}]'::jsonb, '["抹茶粉中加入一到2大勺热水，搅拌至无粉，会有一点黏黏的。", "倒入剩下的1cup水混合，放入冰箱冷藏或冷冻室，冷藏15分钟。", "两个杯子装满冰，加入你喜欢的牛奶", "喜欢甜的话，可以加入糖浆。然后加入冰镇抹茶", "冷粹抹茶拿铁完成！"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/01b95c2711e147b9a63c1f06b0d526a3_912w_730h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('##', '烘焙甜品饮料', '咖啡', '', '[{"name": "酌量速溶咖啡", "amount": "适量"}, {"name": "酌量白糖", "amount": "适量"}, {"name": "少许矿泉水", "amount": "适量"}, {"name": "250毫升纯牛奶", "amount": "适量"}]'::jsonb, '["320ml的玻璃杯一个，打蛋器，黑咖啡，纯牛奶，白糖，矿泉水", "先放糖，甜度根据自己的喜好放", "放入速溶咖啡，追求品质的，就买最好的速溶咖啡，品质好坏口感区别很大。\n雀巢的速溶咖啡同一种包装，原产国有好几个，价格也不同，我这个原产国是法国，我试过很多品牌的速溶咖啡，最喜欢这个香味，就一直喝这款，放入的量也是可以根据自己的喜好放，咖啡味重一点还是牛奶味重一点，随意调整", "倒入矿泉水，可以常温，也可以先放冰箱冷藏过，冷开水也可以，就地取材", "矿泉水的量需要控制一下", "就是比泡湿多一点", "用打蛋器打发至膨胀发白成坨，以上步骤是引用了韩国咖啡的制作方法", "跟韩国咖啡的区别在这个步骤，也就是咖啡泡倒入牛奶和牛奶倒入咖啡泡的区别。\n此处敲重点，我这里是把冷藏的牛奶倒入咖啡泡里，这个大小的杯子正好可以盛下250ml的牛奶，最好是边倒边搅拌，这样咖啡泡就能很好的融进牛奶里，喝起来的口感要比韩国咖啡好很多很多", "这是没搅拌拍的图", "用打蛋器随便拉了一下，有花纹出来", "这是边倒边搅拌好的，完美的奶泡就浮出，比奶泡机打出来的奶泡要绵密很多，口感超棒", "泡速溶冰咖啡没那么多讲究，简单又快速，只要材料齐全，步骤不出错，手残党也是可以分分钟就做出一杯口感超棒的冰咖啡。\n好了，开始享用吧，希望这方法你也喜欢☕️"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/503ddba5af2349868bd33dff837fa78d_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('Dirty', '烘焙甜品饮料', '咖啡', '', '[{"name": "厚椰乳", "amount": "100g"}, {"name": "适量浓缩", "amount": "适量"}, {"name": "一只容量为120ml的玻璃杯", "amount": "适量"}]'::jsonb, '["已经养成习惯，喝完就把杯子洗净重新放回冷冻室。\n杯子的温度对dirty是否够污起到很重要的作用喔！", "100g 菲诺厚椰乳，这款味道真的不错，价格也便宜，1L也就二十来块，唯一一点就是这个包装实在不好储存", "直接将浓缩萃进椰乳里\n让萃取嘴尽可能靠近液面，也可以用勺子🥄的背面进行一个引流\n\n要快快喝哦！\n第一口可以喝到热咖啡和浓郁的椰奶味\n越往下喝融合的越好！\n好好享用吧～\n\n如果没有现成的生椰乳可以用100ml牛奶🥛➕70g的椰浆 搅拌均匀，可以喝到差不多的味道哦"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/254ebe5feff94e41a048decd6fdd2614_854w_854h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('KFC', '烘焙甜品饮料', '豆浆', '', '[{"name": "农家黄豆", "amount": "50克"}, {"name": "纯净水", "amount": "400ml"}]'::jsonb, '["黄豆用纯净水泡发，放入料理杯，我全程用的小瓶矿泉水。", "加大概300ml水，剩100ml留着打第二遍的。如果是做豆浆水多一点少一点都没有关系，做豆腐脑要严格按比例来。", "按压搅打，我这个机子是按压的", "打完以后倒入茶漏袋里面过滤到锅里，挤干净生豆浆。用这种布的过滤会比滤网更干净，目数小于80的滤网建议过滤两三遍。", "然后把挤干净的豆渣重新放回料理杯，加入剩下的100ml水，继续搅打。", "然后重复步骤4的过滤，这次搅打豆渣明显细腻了很多。两次豆浆混合在一起就可以了。", "然后把生豆浆煮开，滤去浮沫，一定要煮开，因为豆浆会假沸，一般闻到豆香，没有生豆子的味道就好了，煮好的豆浆豆香浓郁，不加糖喝都有淡淡的清甜。"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/2572e863f5d64f92b84ea25fd92661f2_1280w_1280h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('12', '烘焙甜品饮料', '豆浆', '', '[{"name": "南瓜", "amount": "150克"}, {"name": "糯米", "amount": "15克"}, {"name": "小米", "amount": "20克"}, {"name": "3颗红枣", "amount": "适量"}, {"name": "5/1朵银耳", "amount": "适量"}, {"name": "适量冰糖", "amount": "适量"}, {"name": "500毫升水", "amount": "适量"}]'::jsonb, '["✅南瓜小米银耳露👉香甜顺滑\n\n1⃣️南瓜150克，糯米15克，小米20克，红枣3颗，银耳5/1朵，冰糖适量，水500毫升\n2⃣️所有食材装入破壁机里选择米糊模式即可\n\n晶莹水润，补水润嗓", "✅紫薯莲子银耳羹\n\n1⃣️紫薯40克，莲子20克，银耳半朵泡发1小时，撕成小块，水500毫升\n\n2⃣️所有食材放入破壁机，选择米糊模式", "✅宫廷花生酪\n\n1⃣️去皮花生100克，冰糖30克，糯米20克，大米20克，水600毫升\n\n✅香芋红豆沙\n\n1⃣️芋頭200克，牛奶100克，冰糖30克，紅豆60克，水400毫升\n\n❗️做法都是把所有食材放入破壁機裡，選擇米糊模式即可。", "✅浓香美龄羹\n\n👉山药50克，黄豆30克，大米10克，糯米20克，枸杞3克，冰糖适量，水500毫升\n\n✅红豆薏米燕麦糊\n\n👉红豆30克，薏米25克，红枣4颗，燕麦30克，水500毫升，选择五谷模式。", "✅山药紫薯芋泥羹\n\n👉芋头60克，紫薯40克，糯米20克，山药30克，冰糖适量，水600毫升\n\n✅香浓黑芝麻糊\n\n👉黑芝麻60克，花生15克，红枣4颗，冰糖适量，糯米20克，水500毫升", "✅韩式南瓜粥\n\n👉南瓜250克，糯米50克，牛奶250克，冰糖适量，水400毫升，选择米糊模式\n\n✅香浓玉米汁\n\n👉玉米120克，小米15克，大米20克，冰糖适量，水600毫升，选择玉米汁模式", "✅香蕉可可燕麦奶\n\n👉可可粉5克，香蕉1根，核桃20克，即食燕麦50克，水500毫升，选择奶昔模式！健康低脂，香甜好喝\n\n✅山药黑豆红枣糊\n\n👉山药100克，黑豆30克，红枣3颗，核桃15克，冰糖适量，水600毫升，选择五谷模式！健脾胃，养生美味"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/a76ec0d490674d45b5f3ff9d8587c5fa_1125w_1485h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('| mojito', '烘焙甜品饮料', '酒', '', '[{"name": "8~10片薄荷叶", "amount": "适量"}, {"name": "1/2个青柠", "amount": "适量"}, {"name": "粗糖", "amount": "1茶匙"}, {"name": "适量碎冰+大块冰块", "amount": "适量"}, {"name": "白朗姆酒", "amount": "50ml"}, {"name": "适量苏打水", "amount": "适量"}, {"name": "8~10片薄荷叶", "amount": "适量"}, {"name": "1/2个青柠", "amount": "适量"}, {"name": "粗糖", "amount": "1茶匙"}, {"name": "适量碎冰+大块冰块", "amount": "适量"}, {"name": "适量雪碧", "amount": "适量"}]'::jsonb, '["材料根据口味准备好，粗糖半勺也可以，根据口味自己调整。", "青柠事先滚一滚，切去2头，再对半切，最后十字下刀切成4小块，剔去柠檬籽，放进杯子。", "新鲜的薄荷叶提前泡在冰水里回复活力，吃之前摘取新鲜的茎和叶子，用手稍微拍打出香味放进杯子。", "然后放一勺粗砂糖，用擀面杖把杯子里的青柠+薄荷+砂糖碾压出汁液。", "放50ml或者你喜欢数量的朗姆酒进来，（无酒精的不用加），再加入3/4杯碎冰。（具体碎冰操作见视频）", "最后，倒进适量的苏打水（有酒精）和雪碧（无酒精）就可以啦~"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/77717a36049942b3bb350643e2948fc3_1353w_762h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('——', '烘焙甜品饮料', '酒', '', '[{"name": "五瓣切碎蒜", "amount": "适量"}, {"name": "黄油", "amount": "20克"}, {"name": "蛤蜊", "amount": "400克"}, {"name": "日本清酒", "amount": "2大勺"}, {"name": "（熟透加）黄油", "amount": "10克"}, {"name": "少许黑胡椒", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}]'::jsonb, '["锅烧热➕黄油至融化", "加大蒜末，炒香，黄油和大蒜的味道最配哦", "加入两勺清酒", "盖好锅盖进行焖煮，不用加一滴水哦", "两分钟左右蛤蜊开口啦", "加剩下的黄油，黑胡椒，盐", "我还加了一点点西芹碎，也可以不加", "等黄油融化就可以出锅啦！"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/34164338f2564a288af0b268aa0494f8_3024w_3024h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('| B', '烘焙甜品饮料', '酒', '', '[{"name": "鸡胗", "amount": "适量"}, {"name": "盐", "amount": "适量"}, {"name": "白酒/黄酒/料酒", "amount": "适量"}, {"name": "食盐", "amount": "适量"}, {"name": "花椒", "amount": "适量"}, {"name": "朝天椒", "amount": "适量"}, {"name": "老姜片", "amount": "适量"}, {"name": "葱段", "amount": "适量"}, {"name": "花椒", "amount": "适量"}, {"name": "八角", "amount": "适量"}, {"name": "香叶", "amount": "适量"}, {"name": "干辣椒", "amount": "适量"}, {"name": "桂皮", "amount": "适量"}]'::jsonb, '["鸡胗用力搓洗数遍，加入白酒和盐继续干搓一会，用流动的水搓洗干净鸡胗的腥臭味，这一步是非常重要的，盐水鸡胗好吃不好吃全靠洗得是否干净彻底。", "沥干水分的鸡胗倒入腌料抓匀，在冰箱冷藏腌制一晚。", "我选择放在保鲜袋里，让食材和调味料充分接触。", "把腌制一宿的鸡胗挑拣出来，把腌料和煮料一起塞进无纺布包，煮鸡胗的时候一起放进来。", "鸡胗先焯一遍水，换一盆干净的冷水，放入盐、料酒和料包，大火煮开后转小火焖煮，计时30分钟。", "煮好的鸡胗泡在水里冷藏一晚是最好吃的，吃不完继续泡着冷藏，随吃随取。", "切成厚厚的薄片是很干净的味道，还可以加点佐料凉拌，丰俭由人。"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/575b96a04ce2449ab7977d3be911ebac_1920w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('37', '烘焙甜品饮料', '果汁', '', '[{"name": "水果", "amount": "适量"}, {"name": "蔬菜", "amount": "适量"}]'::jsonb, '["芦笋果菜汁\n　　\n材料：芦笋80g、荷兰芹80g、苹果1个、柠檬半个\n　　\n做法：\n    （1）芦笋与荷兰芹洗净切小段，加入少许冷开水放入果汁机打汁。\n　　（2）苹果，柠檬去皮切小块，放入如上的菜汁中一起打成果汁。\n　　\n　　功效：这种饮料富含丰富维他命B1与B2，能强化心脏功能。", "综合健康果菜汁\n　　\n材料：苹果1个、青椒80g、苦瓜110g、荷兰芹120g、大黄瓜150g\n　　\n做法：\n　　（1）将青椒，苦瓜，荷兰芹洗净切小块，加些冷开水一起放入果汁机打汁。\n　　\n　　（2）苹果，大黄瓜洗净去皮，切小块放入如上菜汁一起打成果菜汁即可。\n\n功效：可增强抵抗力，降血压，整肠及减肥，美容养颜等功效。", "柳橙牛乳汁\n　　\n材料：柳橙1/2个、牛乳140cc、绿豌豆60~70g、蜂蜜适量\n　　\n做法：柳橙切小块与牛乳，绿豌豆，蜂蜜一起打汁即可。\n　　\n功效：此果汁含丰富的维生素与钙质，是运动后的好饮料。", "西瓜汁\n　　\n材料：西瓜200g、柠檬1/2个、蜂蜜适量、冰块适量\n　　\n做法：西瓜切皮去籽后切成小块，柠檬去皮也切成小块与蜂蜜和冰块一起打成西瓜汁。\n　　\n功效：有沙除浮肿，利尿等作用。也是炎夏消暑的好饮料。", "哈蜜瓜毛豆汁\n　　\n材料：毛豆（煮熟后去壳）50g、哈蜜瓜200g、柠檬1/2个、蜂蜜适量、冰块适量\n　　\n做法：哈蜜瓜，柠檬切皮去籽后切成小块，与其他材料一起放入果汁机打汁即可。\n　　\n功效：此果汁含有维生素C，是营养非常丰富的果汁", "马铃薯苹果汁\n　　\n材料：马铃薯（土豆）2个、苹果1个、蜂蜜适量\n　　\n做法：马铃薯和苹果洗净去皮切小块，加些冷开水与蜂蜜放入果汁机打汁即可。\n　　\n功效：预防高血压，中风，动脉硬化，纾解精神压力。", "奇异果水梨汁\n　　\n材料：奇异果（弥猴桃）2个、水梨1个、柠檬1/4个、冰块适量\n　　\n做法：奇异果去皮切小块，梨子去皮及果核切小块，连同柠檬汁与冰块榨汁即可。\n　　\n功效：含丰富维生素C，有养颜，美容及利尿等作用。", "苹果芥菜汁\n　　\n材料：苹果1个、柠檬1个、芹菜60g、芥蓝菜80g、蜂蜜与冰块适量\n　　\n做法：\n　　\n（1）青菜类洗净切小段，加少许冷开水放入果汁机中打汁\n　　\n（2）苹果去皮去核切小块，连同冰块与柠檬汁放入如上的菜汁中一起打成果汁，最后加蜂蜜适量。\n　　\n功效：预防高血压，感冒，增强抵抗力，促进血液循环。", "蕃茄小黄瓜汁\n　　\n材料：蕃茄1个、小黄瓜3条、蜂蜜适量\n　　\n做法：\n　　\n（1）小黄瓜洗净切小块，加入少许冷开水，放入果汁机打汁。\n　　\n（2）蕃茄洗净切成小块与蜂蜜放入如上的黄瓜汁一起打成果汁。\n\n功效：含维生素A，B1，B2及维生素C，对身体虚肿有利尿作用，能净血，调节身体机能，是夏天美容保健圣品。", "苹果青江菜汁（青江菜即为普通白菜）\n　　\n材料：苹果1个、青江菜150g、柠檬1/4个、蜂蜜适量\n　　\n做法：\n　　\n（1）青江菜洗净切小块，加少许冷开水放入果汁机打汁。\n　　\n（2）苹果削皮切成小块，柠檬去皮切成小块，全部材料放入如上的菜汁中一起打汁。\n　　\n功效：青江菜含有丰富的维他命C及钙质和红萝卜素。对高血压，动脉硬化及便秘均有预防的效果。", "奇异果高丽菜汁（奇异果即弥猴桃；高丽菜即包心菜）\n　　\n　　材料：奇异果1个、高丽菜200g、柠檬1/6个、冰块适量、蜂蜜适量\n　　\n　　做法：\n　　\n　　（1）高丽菜叶分别洗净切小块，加入少许冷开水放入果汁机打汁。\n　　\n　　（2）奇异果去皮切成小块，柠檬去皮切成小块。连同蜂蜜及冰块放入如上的菜汁中打成果汁。\n　　\n　　功效：可促进肠胃蠕动，帮助消化。高血压，皮肤粗糙及糖尿病者适用。", "苹果荷兰芹汁\n　　\n　　材料：苹果1个、荷兰芹120g、油菜（即小芥菜）100g、柑橘（橙子）1/2个\n　　\n　　做法：\n　　\n　　（1）油菜洗净切小块，荷兰芹洗净切小段，加少许冷开水放入果汁机打汁。\n　　\n　　（2）苹果削皮切成小块，柑橘去皮切成小块，全部材料放入如上的菜汁中一起打成果汁。\n　　\n　　功效：此果汁含丰富维生素C，胡萝卜素及钙质，可增强抵抗力，预防感冒，适合糖尿病及高血压患者。", "胡萝卜苹果汁\n　　\n　　材料：胡萝卜1条、苹果1个、柠檬1/4个、冰块适量\n　　\n　　做法：\n　　\n　　（1）糊萝卜削皮洗净切小块，加适量冷开水放入果汁机中打汁，\n　　\n　　（2）苹果削皮切成小块，柠檬去皮切成小块，全部材料放入如上果汁中一起打汁。\n　　\n　　功效：此果菜汁可增强抵抗力，消除疲劳。是对高血压及肝病患者有益的饮料。", "凤梨高丽菜汁（凤梨即菠萝，高丽菜即包心菜）\n　　\n　　材料：凤梨200g、高丽菜150g、柠檬1/6个、冰块适量、蜂蜜适量\n　　\n　　做法：\n　　\n　　（1）高丽菜叶洗净切小块，加入少许冷开水放入果汁机打汁\n　　\n　　（2）凤梨削皮切成小块，连同柠檬汁，冰块放入如上的菜汁中打成果汁。\n　　\n　　功效：凤梨含有大量纤维可帮助消化，预防便秘。胃溃疡及皮肤粗糙者适用。", "苹果白萝卜汁\n　　\n　　材料：苹果1个、白萝卜50g、高丽菜叶80g、芦荟20g、柠檬1/6个、蜂蜜适量\n　　\n　　做法：\n　　\n　　（1）高丽菜叶，芦荟洗净切成小块，加入少许冷开水放入果汁机中打汁。\n　　\n　　（2）白萝卜，苹果，柠檬均去皮切成小块，全部放入如上菜汁中一起打成果汁。\n　　\n　　功效：对高血压，消化不良及胃溃疡有帮助，并有整肠及美容的作用。", "苹果水芹汁（水芹即日常炒菜用的普通芹菜）\n　　\n　　材料：苹果1/4个、葡萄柚1/4个、水芹120g、生菜叶子100g、蜂蜜适量\n　　\n　　做法：\n　　\n　　（1）水芹和生菜叶子先洗净切小块，加少许冷开水放入果汁机打汁。\n　　\n　　（2）葡萄柚剥除内层薄膜切成小块，苹果削皮切成小块，全部放入如上菜汁一起打成果汁。\n　　\n　　功效：此果菜汁有清血作用，有益高血压及心脏者患者饮用。", "哈蜜瓜高丽菜汁\n　　\n　　材料：哈蜜瓜1/3个、高丽菜（包心菜）120g、柠檬汁1/6个份、蜂蜜适量、冰块适量\n　　\n　　做法：\n　　\n　　（1）包心菜叶分别洗净切小块，加少许冷开水放入果汁机中打汁。\n　　\n　　（2）哈蜜瓜去皮去籽切小块，连同柠檬汁，蜂蜜及冰块一块放入如上的菜汁中一起打成果汁。\n　　\n　　功效：此果汁可预防胃溃疡，牙龈出血及高血压，并可以帮助消化。", "青椒苹果汁\n　　\n　　材料：苹果1个、大青椒1个、蕃茄半个、蜂蜜适量\n　　\n　　做法：\n　　\n　　（1）青椒洗净切小块，加些许冷开水放入果汁机中打汁。\n　　\n　　（2）苹果洗净去皮，蕃茄洗净一起切小块与蜂蜜一起加入如上青椒汁，搅拌打成果汁即可。\n　　\n　　功效：预防高血压，强化心脏功能。", "蕃茄哈蜜瓜汁\n　　\n　　材料：水芹（普通芹菜）70g、蕃茄1个、蛋白1个、哈密瓜1/2个、柠檬1/4个\n　　\n　　做法：\n　　\n　　（1）水芹洗净切小段，加少许冷开水放入果汁机打汁。\n　　\n　　（2）蕃茄，哈蜜瓜削皮切成小块，柠檬剥除内层薄膜切成小块，放入如上汁中一起打成汁。\n　　\n　　（3）最后将蛋白慢慢倒入打好的果汁中拌匀。\n　　\n　　功效：增强体力，消除疲劳。适合运动后饮用。", "苹果枇杷汁\n　　\n　　材料：苹果1个、枇杷5个、红萝卜1/3条、柠檬汁1/6个份、冰块适量\n　　\n　　做法：\n　　\n　　（1）红萝卜去皮洗净切小块，加适量冷开水放入果汁机打汁\n　　\n　　（2）苹果削皮切成小块，枇杷去皮去籽洗净切块，连同柠檬汁，冰块全部放入如上一起打汁。\n　　\n　　功效：此果汁红萝卜素，锌铜含量丰富。是贫血，便秘症状者最佳果汁。", "芒果汁\n　　\n　　材料：芒果1个、柠檬1/2个、蜂蜜适量、冰块适量\n　　\n　　做法：芒果去皮去籽后切成小块，和柠檬汁，蜂蜜及冰块一起放入果汁机打汁。\n　　\n　　功效：芒果中含有很高的维生素C，可帮助食欲，消除疲劳。", "枇杷汁\n　　\n　　材料：枇杷8个、柠檬1/4个、蜂蜜适量、冰块适量\n　　\n　　做法：枇杷剥皮去籽切小块，与柠檬汁，蜂蜜及冰块一起放入果汁机打汁。\n　　\n　　功效：此果汁有镇咳去痰及消除肠胃不适的疗效。", "香蕉牛奶汁\n　　\n　　材料：香蕉1条、柠檬1/4个、牛奶200cc、蜂蜜适量、冰块适量\n　　\n　　做法：香蕉剥皮切小块，与牛奶，柠檬，蜂蜜及冰块一起放入果汁机中打汁。\n　　\n　　功效：促进食欲，帮助消化。对便秘有很好的疗效。", "牛蒡葡萄柚汁\n　　\n　　材料：牛蒡150g、葡萄柚1个、柠檬1个、蜂蜜适量、冰块适量\n　　\n　　做法：\n　　\n　　（1）牛蒡彻底洗净后切小段，加少许冷开水放入果汁机中打汁\n　　\n　　（2）柠檬去皮切小块，葡萄柚去皮去籽切小块，连同冰块一起放入如上牛蒡汁中打成果汁。\n　　\n　　功效：牛蒡含丰富钙质，对高血压，便秘，肝病，晒伤，肩膀酸痛，褐斑，雀斑，贫血等有效。", "哈蜜瓜果汁\n　　\n　　材料：哈蜜瓜400g、柠檬1/4个、蜂蜜适量、冰块适量\n　　\n　　做法：哈蜜瓜去皮去籽切小块，柠檬去皮切成小块，放入果汁机打汁。喜甜味者可加入蜂蜜调味。\n　　\n　　功效：哈蜜瓜含丰富维生素C，有美容及利尿作用。", "柠檬柳橙汁\n　　\n　　材料：柠檬1个、柳橙1个半、蜂蜜适量、冰块适量\n　　\n　　做法：柳橙和柠檬去皮切成小块，加入蜂蜜放入果汁机中打成果汁。\n　　\n　　功效：可预防高血压，皮肤粗糙和晒伤过敏。并有利尿作用。", "葡萄柚菠萝汁\n　　\n　　材料：葡萄柚1/2个、菠萝150g、蜂蜜适量、冰块适量\n　　\n　　做法：菠萝削皮切成小块，葡萄柚去皮切成小块，连同蜂蜜及冰块放入果汁机中打成果汁。\n　　\n　　功效：菠萝含有促进肉类消化的酵素，可以整肠促进食欲，防止高血压和皮肤粗糙。", "菠萝柠檬芹汁\n　　\n　　材料：菠萝200g、柠檬1个、西洋芹100g、冰块适量、蜂蜜适量\n　　\n　　做法：\n　　\n　　（1）荷兰芹洗净切成小块，加适量冷开水放入果汁机中打汁\n　　\n　　（2）菠萝，柠檬去皮切成小块与其他材料放入如上的荷兰芹汁中一起打汁即可。\n　　\n　　功效：高血压，糖尿病，增强体力，消除疲劳者适用。", "蕃茄红萝卜汁\n　　\n　　材料：蕃茄1个、红萝卜1条、柠檬1/2个、蜂蜜适量、冰块适量\n　　\n　　做法：\n　　\n　　（1）红萝卜洗净切小块，加适量冷开水放入果汁机中打汁\n　　\n　　（2）蕃茄，柠檬去皮切成小块，全部材料放入如上的红萝卜汁中一起打成果汁。\n　　\n　　功效：此果汁含丰富维生素。适合高血压，消化不良，便秘，容易感冒者饮用。", "土豆红萝卜汁\n　　\n　　材料：土豆1个、红萝卜1条、苹果1个、蜂蜜适量\n　　\n　　做法：\n　　\n　　（1）土豆与红萝卜洗净去皮切小块，加少许冷开水，放入果汁机中打汁。\n　　\n　　（2）苹果洗净去皮切小块与蜂蜜一起放入如上的菜汁中一起打成汁即可。\n　　\n　　功效：含有丰富维生素B1，维生素C，矿物质，蛋白质，可预防高血压，中风，肝硬化，防止老化，强化体内免疫系统。", "菠萝柠檬汁\n　　\n　　材料：菠萝350g、柠檬1个、蜂蜜适量、冰块适量\n　　\n　　做法：菠萝，柠檬洗净切小块，与其他材料一起放入果汁机中打汁即可。\n　　\n　　功效：能帮助消化，有提神及健胃等功效。", "柳橙红萝卜汁\n　　\n　　材料：柳橙2个、芦笋150g、红萝卜120g、柠檬1/4个、蜂蜜适量\n　　\n　　做法：\n　　\n　　（1）芦笋，红萝卜洗净切小块，加些冷开水放入果汁机中打汁。\n　　\n　　（2）柳橙，柠檬洗净去皮切小块与蜂蜜一起放入如上打汁即可。\n　　\n　　功效：柳橙含丰富维生素C，维生素P，能增进抵抗力，降低胆固醇。芦笋能清热降火。", "葡萄柚菠菜汁\n　　\n　　材料：葡萄柚1个、菠菜150g、柠檬1个、蜂蜜适量、冰块适量\n　　\n　　做法：\n　　\n　　（1）菠菜洗净切小段，加少许冷开水放入果汁机中打汁。\n　　\n　　（2）葡萄柚去皮去籽切成小块，柠檬去皮切成小块。连同蜂蜜冰块放入菠菜汁中一起打成果汁。\n　　\n　　功效：此果汁适用于贫血，高血压，便秘，皮肤粗糙者饮用。", "胡萝卜牛奶汁\n　　\n　　材料：胡萝卜1条、牛奶150cc、蜂蜜适量\n　　\n　　做法：胡萝卜削皮洗净切成小块放入果汁机，再将牛奶和蜂蜜一起倒入打汁即可。\n　　\n　　功效：可预防感冒，肌肤干裂。对减肥者也有帮助。", "蕃茄柠檬汁\n　　\n　　材料：蕃茄2个、柠檬半个、蜂蜜适量\n　　\n　　做法：蕃茄，柠檬洗净切小块，与蜂蜜一起放入果汁机中打汁即可。\n　　\n　　功效：蕃茄含丰富胡萝卜素与维生素C，维生素P等，可预防细胞老化。是养颜美容的好饮料。", "苹果芥菜汁\n材料：苹果1个柠檬1个芹菜60g芥蓝菜80g蜂蜜与冰块适量\n\n作法：（1）青菜类洗净切小段，加少许冷开水放入果汁机中打汁（2）苹果去皮去核切小块，连同冰块与柠檬汁放入如上的菜汁中一起打成果汁，最后加蜂蜜适量。"]'::jsonb, 30, 180, '困难', 3, 'https://i2.chuimg.com/aa5c9f9e891711e6b87c0242ac110003_500w_330h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('4+1', '烘焙甜品饮料', '果汁', '', '[{"name": "香浓香蕉燕麦牛奶", "amount": "适量"}, {"name": "香蕉", "amount": "2根"}, {"name": "燕麦", "amount": "30g"}, {"name": "牛奶", "amount": "300ml"}, {"name": "美颜火龙果草莓奶", "amount": "适量"}, {"name": "火龙果", "amount": "1个"}, {"name": "草莓", "amount": "4个"}, {"name": "酸奶", "amount": "100ml"}, {"name": "甜蜜胡萝卜橙子汁", "amount": "适量"}, {"name": "胡萝卜", "amount": "1根"}, {"name": "橙子", "amount": "1个"}, {"name": "蜂蜜", "amount": "5g"}, {"name": "饮用水", "amount": "100ml"}, {"name": "清新奇异果黄果汁", "amount": "适量"}, {"name": "黄瓜", "amount": "1根"}, {"name": "奇异果", "amount": "1个"}, {"name": "梨", "amount": "1个"}, {"name": "饮用水", "amount": "50ml"}, {"name": "维C凤梨芒果汁", "amount": "适量"}, {"name": "凤梨", "amount": "1个"}, {"name": "芒果", "amount": "1个"}, {"name": "半个百香果", "amount": "适量"}, {"name": "饮用水", "amount": "50ml"}]'::jsonb, '["香浓香蕉燕麦牛奶：\n2根香蕉去皮切小块。", "榨汁机内放入香蕉块、30g燕麦。", "倒入300ml牛奶，打至顺滑。", "倒入杯中，撒上燕麦，放入吸管。", "香浓香蕉燕麦牛奶就完成啦，开喝吧~", "美颜火龙果草莓奶：\n1个火龙果对半切开，去皮切成小块。", "4个草莓去蒂对半切开。", "将草莓、火龙果块放入榨汁机中，倒入100ml酸奶。", "打至顺滑，倒入杯中。", "美颜火龙果草莓奶就做好啦，开喝吧~", "甜蜜胡萝卜橙子汁：\n1根胡萝卜去皮切成小块。", "1个橙子去皮，去筋切出果肉。", "榨汁机内放入胡萝卜、橙子，加入5g蜂蜜，100ml饮用水。", "打至顺滑。", "倒入杯中，放入吸管。", "甜蜜胡萝卜橙子汁就完成啦，开喝吧~", "清新奇异果黄果汁：\n1根黄瓜切块。", "1个奇异果去皮切块。", "1个梨去皮切小块。", "切好的果肉放入榨汁机中，倒入50ml饮用水。", "打至顺滑倒入杯中，放入吸管。", "清新奇异果黄瓜汁就做好啦，开喝吧~", "维C凤梨芒果汁：\n半个凤梨，切条切成小块。", "1个芒果对半切开，沿杯口用力按出果肉。", "把锅内放入榨汁机内，倒入50ml饮用水。打至顺滑。", "倒入杯中，放入半个百香果，放入吸管。", "维C凤梨芒果汁就做好啦，开喝吧~"]'::jsonb, 30, 135, '困难', 3, 'https://i2.chuimg.com/34cd53f4469a11e7bc9d0242ac110002_1920w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('--', '肉类', '排骨', '', '[{"name": "排骨", "amount": "400克"}, {"name": "豆角", "amount": "300克"}, {"name": "土豆", "amount": "1个"}, {"name": "1捏花椒（或粉）", "amount": "适量"}, {"name": "八角", "amount": "1个"}, {"name": "半勺盐", "amount": "适量"}, {"name": "适量料（白）酒", "amount": "适量"}, {"name": "4瓣大蒜", "amount": "适量"}, {"name": "半根葱", "amount": "适量"}, {"name": "姜", "amount": "4片"}, {"name": "1圈东古黄豆酱油（老式塑料瓶比较便宜那种）", "amount": "适量"}, {"name": "半圈东古一品鲜酱油", "amount": "适量"}, {"name": "老抽", "amount": "1勺"}, {"name": "干辣椒", "amount": "2个"}]'::jsonb, '["食材处理：", "排骨凉水浸泡2小时以上（急就不泡）", "摘豆角，掰不掰断随意。关于土豆在下一步。", "姜切片，葱切葱花，蒜拍扁，大概切两下。花椒八角干辣椒备用。", "几种酱油和料酒备好，免的炒时候慌乱。", "如图↑如果不是焖面用，土豆平时我还是用刀别（锛）成块或者切滚刀块。（玉米、倭瓜炖进去都好吃，很好吃的那种好吃！和土豆一块下锅就行）", "不焯水直接爆炒 肉香味绝对更浓郁（冻的久的话还是先焯一下），热！锅凉油下排骨，要不然粘锅粘的你怀疑人生。", "花椒八角干辣椒可以先扔进去，中小火多煸一会儿炒干水分，转大火锅边烹一圈料（白）酒（一定炒的水分够干再烹料酒，即刻颠勺绝对出火苗↑像这样），放姜蒜，酒和姜蒜水分炒干后重复上述操作，再放葱花。", "锅边淋入半圈一品鲜，一圈老酱油，一点老抽，炒出酱香味，转小火加热水没过排骨。", "中小火，水开后炖15-20分钟下豆角土豆，适量加盐。再炖15分钟左右。出锅前撒蒜末盛出。"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/710054dc2be3431d857d46c7e9e3732a_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('/', '肉类', '猪肉末', '', '[{"name": "适量肉末", "amount": "适量"}, {"name": "青椒", "amount": "3个"}, {"name": "3朵香菇", "amount": "适量"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "生抽", "amount": "3勺"}, {"name": "半勺老抽", "amount": "适量"}, {"name": "耗油", "amount": "1勺"}, {"name": "醋", "amount": "1勺"}, {"name": "少许糖", "amount": "适量"}, {"name": "黄豆酱", "amount": "1勺"}]'::jsonb, '["将胡萝卜香菇切碎，放肉馅中，加盐，生抽2勺，老抽，耗油拌匀", "尖椒切段，我的尖椒比较长，我分成了三段，将拌好的肉馅塞进尖椒里", "锅里加油，油热放入尖椒.，煎至两面出虎皮即可，大约煎6-7分钟，全部煎完后锅中加入少许水，盐一丢丢，生抽1勺，糖，醋，黄豆酱，水开后2分钟就好了", "出锅啦，开动"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/3ce4350edcd04cc08d0087d9658f6707_684w_912h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('——', '肉类', '五花肉', '', '[{"name": "五花肉", "amount": "250克"}, {"name": "大葱", "amount": "1根"}, {"name": "小米椒", "amount": "2个"}, {"name": "杭椒", "amount": "3个"}, {"name": "3-4瓣大蒜", "amount": "适量"}, {"name": "姜片", "amount": "3片"}, {"name": "少许淀粉", "amount": "适量"}, {"name": "料酒", "amount": "3勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "郫县豆瓣酱", "amount": "2勺"}, {"name": "糖", "amount": "1勺"}, {"name": "小半碗清水", "amount": "适量"}]'::jsonb, '["五花肉片250克可以炒一盘子，看家里人份量决定。五花肉片切成合适大小后倒入碗里加3勺料酒2勺生抽和少许淀粉抓匀腌制20分钟。", "准备好姜，蒜、小米椒、杭椒和一根大葱。", "切片完毕。", "热锅热油，五花肉翻炒。", "炒到微微焦色后盛出。喜欢口感硬实点的可以多煸炒一会儿到五花肉片焦色发硬，个人喜欢微软一些的口感。", "锅里加入姜片和蒜片炒出香味。", "加入椒和大葱片炒软。", "葱姜撇到一边，加入2勺郫县豆瓣酱炒出红油。", "姜蒜葱等和豆瓣酱炒匀。", "加入五花肉，一起翻炒2分钟后，加入小半碗水继续炒。", "豆瓣酱本身挺咸的，不加盐，加一勺白糖提鲜，炒匀。", "出锅盛盘。", "咸鲜入味，大口吃完这一碗葱蒜味🧄十足的五花肉片，才叫爽快。\n真❗️\n的❗️\n香❗️"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/419b0355fc2d42058023479b43612541_3024w_2821h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('(……)', '肉类', '瘦肉', '', '[{"name": "猪瘦肉", "amount": "250g"}, {"name": "马铃薯淀粉(或红薯淀粉)", "amount": "175g"}, {"name": "细味精", "amount": "10g"}, {"name": "精盐", "amount": "9g"}, {"name": "香甜泡打粉", "amount": "6g"}, {"name": "高弹素（可略，自己吃别放！！！）", "amount": "5g"}, {"name": "嫩肉粉（可略，自己吃别放！！！）", "amount": "5g"}, {"name": "鸡精", "amount": "5g"}, {"name": "白砂糖", "amount": "5g"}, {"name": "黄料酒", "amount": "3g"}, {"name": "食用碱", "amount": "1g"}, {"name": "猪肉粉精(可略，自己吃别放！！！)", "amount": "1g"}, {"name": "适量佐料(葱、姜、芹菜、香菜、紫菜、虾皮、榨菜、醋、香油、胡椒粉)", "amount": "适量"}, {"name": "水", "amount": "150g"}]'::jsonb, '["到菜市场购买半斤瘦肉(250g),要全瘦肉，不要带肥，最好是猪腿肉或里脊肉，以保证瘦肉丸的口感细腻而不柴。", "把瘦肉和葱姜末放入绞肉机，直到绞成肉泥为止。或者用菜刀刀背，擀面杖之类的慢慢敲成肉泥。", "把绞好的瘦肉放在一个盆子里，将高弹素，嫩肉粉，猪肉粉精，黄酒，味精，鸡精，食用碱，添加到肉里，用力揉搓10分钟，要用手掌揉，直到肉富有弹性为止。", "倒入马铃薯淀粉，初步将肉与淀粉混合。", "将泡打粉，白砂糖，盐，放入之前称好的150g水中，用筷子搅拌，使之溶于水中。然后分两次倒入之前的肉中，用手揉搓或者用筷子朝同一个方向搅拌使淀粉完全和肉混合均匀，看上去只有肉色为止。", "按照自己的口味，将葱，芹菜，紫菜，虾皮，榨菜，盐，放入一个空碗中。", "把锅中的水烧开，水一定要是开的，这样煮出来的瘦肉丸的汤会是清的，不然，汤就会变得混浊。", "把肉用刀片之类的工具刮成一小长条一小长条地放入烧开了的水里，盖上锅盖，煮一两分钟。", "当看到锅中的瘦肉丸全都浮起来时，用勺子舀些汤放入已准备好的佐料碗里，烫下佐料。", "将煮熟的瘦肉丸捞起放入碗中，然后再放入胡椒粉，醋，香菜，香油，用一个小勺子搅拌一下。\n此时美味的瘦肉丸才算大功告成。"]'::jsonb, 30, 50, '中等', 3, 'https://i2.chuimg.com/0f40fbea24ff45aa813f3cb30b6573e6_470w_284h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('-', '肉类', '瘦肉', '', '[{"name": "瘦肉", "amount": "250克"}, {"name": "豆瓣酱", "amount": "2勺"}, {"name": "油", "amount": "1勺"}, {"name": "料酒", "amount": "1勺"}, {"name": "适量盐、鸡粉", "amount": "适量"}]'::jsonb, '["先准备好材料", "切好肉之后把以上配料腌20分钟", "蒸15分钟"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/b6b6b3ad39564065b031c83997ff07e8_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('•', '肉类', '瘦肉', '', '[{"name": "猪肉（里脊肉）", "amount": "300g"}, {"name": "15朵木耳", "amount": "适量"}, {"name": "1小根胡萝卜", "amount": "适量"}, {"name": "1-2个（看大小）青椒", "amount": "适量"}, {"name": "大葱", "amount": "1根"}, {"name": "适量姜丝", "amount": "适量"}, {"name": "2瓣大蒜", "amount": "适量"}, {"name": "郫县豆瓣酱", "amount": "1大勺"}, {"name": "淀粉", "amount": "2勺"}, {"name": "香醋", "amount": "3勺"}, {"name": "白砂糖", "amount": "3勺"}, {"name": "生抽", "amount": "2勺"}, {"name": "（可不放）盐", "amount": "1小勺"}, {"name": "清水", "amount": "4勺"}]'::jsonb, '["腌肉：猪肉切丝，依次加入少许料酒、盐、胡椒粉、淀粉、植物油，抓匀腌制10分钟。", "备料：木耳提前泡软切小或切丝，胡萝卜、青椒切丝，姜、葱切丝，蒜切瓣，备用。", "调汁：调制鱼香汁是这道菜的关键，盐、生抽、醋、糖、淀粉、水的比例是，1：2：3：3：2：4。", "炒肉：锅内热油，倒入腌制的肉丝翻炒至变色后盛出，备用。", "炒料：锅内热油，倒入葱、姜、蒜炒香后，加入1勺豆瓣酱，翻炒出汁。", "炒菜：依次加入胡萝卜丝、木耳、青椒丝，炒至七成熟后，加入肉丝，翻炒片刻，倒入调好的鱼香汁，翻炒均匀。", "收汁：翻炒均匀、等待收汁，即可出锅。", "盛盘：即可食用。"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/c3ffdb79ee6042a190052659c21a4ce3_1024w_807h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('-', '肉类', '里脊', '', '[{"name": "猪里脊", "amount": "300克"}, {"name": "1丢丢白胡椒粉", "amount": "适量"}, {"name": "1丢丢椒盐粉", "amount": "适量"}, {"name": "1丢丢洋葱粉", "amount": "适量"}, {"name": "1丢丢生姜粉", "amount": "适量"}, {"name": "1丢丢糖", "amount": "适量"}, {"name": "盐", "amount": "1小勺"}, {"name": "1汤勺啤酒", "amount": "适量"}, {"name": "1汤勺油", "amount": "适量"}, {"name": "面粉", "amount": "50克"}, {"name": "红薯淀粉", "amount": "50克"}, {"name": "泡打粉", "amount": "1克"}, {"name": "一汤勺油", "amount": "适量"}, {"name": "100-110克水", "amount": "适量"}, {"name": "3汤勺糖", "amount": "适量"}, {"name": "1.5汤勺香醋", "amount": "适量"}, {"name": "半汤勺柠檬汁", "amount": "适量"}, {"name": "1汤勺李锦记红烧汁", "amount": "适量"}, {"name": "半汤勺红薯淀粉", "amount": "适量"}, {"name": "少许油", "amount": "适量"}]'::jsonb, '["里脊肉去掉外面的筋膜.\n切成厚一些的片.\n再切成条.\n\n不建议切太粗了的.\n成品会很大块.\n\n切细一点比较好入味.\n然后....\n主要是份量也显多呀.(˶‾᷄ ⁻̫ ‾᷅˵)", "放入：\n白胡椒粉.生姜粉.洋葱粉.盐.糖.\n搅拌均匀放一会儿.\n然后放啤酒搅拌至完全吸收后.\n再放10分钟以上..\n\n没有生姜粉.洋葱粉的.\n可以把新鲜的剁成茸挤汁用..\n\n啤酒最好不要换其它酒.\n如果介意的.\n可以放凉水.\n\n成品是无酒味的..)^o^(", "面粉和红薯粉.泡打粉混合均匀.\n\n红薯粉一般在超市都能买到.\n和淀粉.盐.鸡精这些做邻居.\n\n如果实在没有的.\n就用玉米淀粉吧.吧.吧...！\n\n面粉如果有低筋粉的.\n可以用低筋的.\n没有就用普通的面粉就好.\n\n（真够随便的..ಠ_ಠ...）", "慢慢加水.\n一直到如图状态..\n\n大概100-110克左右..", "把肉放下去搅拌均匀.", "再放一汤勺食用油下去搅拌均匀.", "小锅里面放油..\n最好是口径小一些的.\n深一些的..！\n\n油热至6成.\n大概就是筷子放下去能冒泡的那种.\n\n小火.\n把肉一条条放下去.\n不要动.\n炸一会后一般会自动浮起来.\n如果不浮.（锅不好.ಠ_ಠ ）\n那就炸一会再拨动..", "炸至微黄后捞出..\n\n把所有的都炸好后.\n放一旁备用.", "把酱汁材料里的香醋.糖.红烧汁.柠檬汁.\n再加二汤勺左右的水.\n（多点少点无所谓.）\n混合均匀备用...", "再次把油烧热.\n中大火.\n把炸好的里脊肉放下去炸一遍.\n可以分几次炸..", "炸至如图金黄色捞出.\n大概也就10多秒的时间.\n动作要快.姿势要帅.\n很容易就炸过头的.\n\n這时候吃都非常的爽...！( ´▽｀)", "另用一个锅.\n倒入混合好的酱汁.\n小火加热至酱汁浓稠一些.", "把淀粉放入碗中.\n加小半碗水混合均匀.\n倒入锅中..\n\n用锅铲一直铲动混合均匀..！\n变成透明.浓稠的酱汁后关火.\n放少许炸里脊肉的食用油下去搅拌均匀.\n成品会比较通透发亮.\n不想放的也可以不放哈.！", "装入小碗中.\n撒上一些熟白芝麻..\n\n娃可以就光吃這酱汁.\n吃一碗饭下去.\n是不是傻...╮(￣▽￣\"\")╭", "吃的时候.\n蘸着酱汁吃就好.\n這样可以避免放久了..\n里脊肉会变软的问题..\n\n强烈推荐這种吃法..", "当然.\n伱要不接受推荐的话.\n也可以在步骤13的时候.\n把里脊放下去迅速翻炒均匀.\n装盘撒白芝麻呀.."]'::jsonb, 30, 80, '困难', 3, 'https://i2.chuimg.com/6f29fef678d84a99a1c8d4750d1803f6_1578w_1182h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('··', '肉类', '里脊', '', '[{"name": "（500g）猪小里脊", "amount": "1条"}, {"name": "1小撮白胡椒粉", "amount": "适量"}, {"name": "1/2小匙盐", "amount": "适量"}, {"name": "鸡蛋清", "amount": "1个"}, {"name": "2大匙生抽", "amount": "适量"}, {"name": "1小匙生粉", "amount": "适量"}, {"name": "1大匙（没有也行）everything bagel（各种芝麻混合物）没有就用芝麻", "amount": "适量"}, {"name": "大葱", "amount": "1根"}]'::jsonb, '["小里脊一条，先把有筋膜的地方修掉。", "小里脊切片+白胡椒+盐+2大匙生抽+鸡蛋清抓匀，放置5分钟后加1大匙生粉+2大匙水拌匀，再加1大匙油拌匀备用，一根大葱葱白切丝备用", "热锅加1大匙油，150度左右就可以放肉下去划开，由于我家是电磁炉，火力不太猛，要炒2分钟才能肉呈白色，此时下大葱翻炒1-2分钟，下1大匙everything bagel，没有就撒白芝麻，然后盐调味就可以装盘了", "口味鲜、嫩，但不是重口味哦，喜欢辣口的请忽略", "临时组局和朋友吃个便饭，有了这道葱爆小里脊顿时提高了便饭档次"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/64b7a3f8feed4fa79507fd024f4b01ed_1280w_1023h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('~', '肉类', '里脊', '', '[{"name": "醋", "amount": "1勺"}, {"name": "猪里脊", "amount": "300克"}, {"name": "糖", "amount": "1勺"}, {"name": "番茄酱", "amount": "3勺"}, {"name": "适量白胡椒粉", "amount": "适量"}, {"name": "鸡蛋", "amount": "1个"}, {"name": "适量淀粉", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "半勺生抽", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "半勺蚝油", "amount": "适量"}]'::jsonb, '["腌肉：将猪里脊肉先切厚片，用刀背拍一拍，把肉拍松一点。切成一个手指头粗的条，加料酒，生抽，蚝油，一点点盐，白胡椒粉，一个鸡蛋（或蛋清），将肉用手抓匀，腌制20分钟以上。", "调酱：3勺番茄酱+1勺白醋+1勺白糖++一勺淀粉+半碗（饭碗）清水，搅拌至糖融化，放在一边备用。", "裹粉：一般老手是边裹粉边下锅油炸，新手建议先把粉全部裹好再来炸，这样在炸的时候就不会手忙脚乱。准备一个大碗，里面放干淀粉，玉米淀粉，红薯淀粉，土豆淀粉都可以。把每一根肉条都满满裹上干淀粉。", "炸制：油温160度左右下里脊，可以拿一个干筷子放在油里面试一下，周围冒小泡就可以下锅。炸到表面微黄可以捞出，全程中火。然后等几分钟，油温升高到200度左右，把里脊倒进去复炸一次，只需40秒，表皮就会很脆，马上捞出。", "裹酱：另外拿一个锅，锅里放一点点底油，把调好的酱汁倒进去，煮到冒大泡，把炸好的里脊放进去，翻炒，让每一根都裹上酱汁。", "出品：出锅啦！撒上万能装饰：黑芝麻+葱花（如果有白芝麻更好）。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/35a8bcd0f0dd4a48a36e23e0f9d9f4b3_912w_684h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('“”', '肉类', '猪肝', '', '[{"name": "猪肝", "amount": "350克"}, {"name": "几颗大蒜", "amount": "适量"}, {"name": "约15克生姜", "amount": "适量"}, {"name": "小米辣", "amount": "30克"}, {"name": "大红椒", "amount": "1个"}, {"name": "蒜苗", "amount": "3根"}, {"name": "适量植物油", "amount": "适量"}, {"name": "小半勺食用盐", "amount": "适量"}, {"name": "适量胡椒粉", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "少许白糖", "amount": "适量"}, {"name": "蚝油", "amount": "5克"}, {"name": "生抽酱油", "amount": "2克"}]'::jsonb, '["首先我们准备新鲜的猪肝350克\n加入清水清洗干净之后备用\n此做法属于干香类菜需要提前清洗", "清洗干净之后将猪肝切成3毫米左右的厚片\n同学们可以适当的切厚一些这样更方便新手操作", "猪肝切好之后下一步开始腌制\n碗中加入食用盐1小半勺（约", "5克）\n加入胡椒粉", "5克\n加入老抽3克调底色\n调好味之后抓拌均匀备用", "最后加入少许的食用油搅拌均匀\n这一步的目的是防止猪肝下锅黏成一团", "下一步开始准备辅料\n准备大蒜几颗切成小粒备用（约30克）", "准备生姜1小块切成小粒备用（约15克）", "准备小米辣30克切碎备用\n不能吃辣的同学可以不加", "准备大红椒1个切成小颗粒备用", "准备蒜苗3根轻轻拍散之后切碎备用", "下一步开始制作\n首先我们把锅烧热\n锅烧热之后加入适量的油滑锅\n滑好锅之后将热油倒出\n然后加入适量的冷油", "再将腌制好的猪肝下锅滑10秒钟\n这一步的目的是将猪肝炒至定型（此时约5成熟）", "然后将切好的姜蒜粒和辣椒粒下锅翻炒30秒\n这一步的目的是将料头炒香\n同学们家庭小灶则需要2分钟左右", "翻炒30秒钟之后开始调味\n锅中加入胡椒粉", "5克\n加入少许白糖提鲜\n加入蚝油5克\n加入生抽酱油2克\n最后加入老抽2克翻炒几下", "翻炒均匀之后再加入切好的蒜苗粒\n开中小火翻炒至断生即可出锅装盘", "一道干香下饭的小炒猪肝就制作完成"]'::jsonb, 30, 90, '困难', 3, 'https://i2.chuimg.com/b8e30b7580b741c297305d2c746b067e_3840w_2160h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('-', '肉类', '猪排', '辣', '[{"name": "猪瘦肉（里脊肉）", "amount": "适量"}, {"name": "鸡蛋", "amount": "适量"}, {"name": "面粉", "amount": "适量"}, {"name": "面包糠", "amount": "适量"}, {"name": "辣椒面（自选）", "amount": "适量"}, {"name": "黑胡椒", "amount": "适量"}, {"name": "盐", "amount": "适量"}, {"name": "料酒", "amount": "适量"}, {"name": "酱油", "amount": "适量"}]'::jsonb, '["先把猪肉切成1厘米左右的薄片，用刀背敲断经络（十字纹的方法敲）。", "把敲好的猪肉用黑胡椒、盐、料酒、酱油腌制10分钟以上", "鸡蛋和面粉放在一个碗中调成面糊，小美忘记量他们的比例了。面糊要稍微粘稠一点，这样好裹在猪排上，把腌制好的猪排放入面糊中。", "准备一个大的容器，里面倒入面包糠，把猪排从面糊中取出放在面包糠上，用手轻轻的压猪排，使面包糠完全覆盖在猪排上。", "热锅多油（要保证猪排能完全浸在油里，PS：小美为了节约，所以油放得少了点），油温升高以后放入猪排，然后转中火，直到炸熟为止，一面炸成型了，需要翻面哦。", "小编的个人公众号，上面很多菜谱，每天也都会更新最新的菜谱，搜索公众号“meishi0123”或者扫这个二维码添加。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/af911bfc891711e6b87c0242ac110003_1000w_663h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('-', '肉类', '猪肚', '', '[{"name": "猪肚", "amount": "1只"}, {"name": "一大块生姜", "amount": "适量"}, {"name": "小米辣", "amount": "1只"}, {"name": "1瓣蒜头", "amount": "适量"}, {"name": "小葱", "amount": "2根"}, {"name": "适量黄酒", "amount": "适量"}, {"name": "少许麻油", "amount": "适量"}, {"name": "适量海鲜酱油（或蒸鱼豉油）", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "少许白胡椒粉", "amount": "适量"}, {"name": "", "amount": "适量"}]'::jsonb, '["锅里放水先把猪肚焯水后捞出，小图中间有一层白色的用刨子刨去，再次冲水清洗干净备用。", "锅里放水放入猪肚，加入小量黄酒，切片的生姜，切段的葱白，盖盖子大火煮开后改小火焖，煮80分钟左右捞出，中间翻几次身，可根据自己的喜好调整时间，晾凉后切片装盘，\n蘸酱碟放入海鲜酱油百分之三十（或蒸鱼豉油），海天特级生抽百分之七十，葱末、切丁的小米辣、蒜末、小磨香油，胡椒粉，一盘香喷喷的白切猪肚就做好了，很简单吧。"]'::jsonb, 6, 10, '简单', 3, 'https://i2.chuimg.com/d3982a008b9111e6a9a10242ac110002_1080w_1097h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('—', '肉类', '猪骨', '', '[{"name": "猪骨", "amount": "300克"}, {"name": "半根玉米", "amount": "适量"}, {"name": "半根胡萝卜", "amount": "适量"}, {"name": "6～8个马蹄（荸荠）", "amount": "适量"}, {"name": "两片+一块姜", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}]'::jsonb, '["猪骨在水龙头下冲洗干净后，放入锅内，入清水，加两片姜，两勺料酒，大火烧开，撇去浮沫，再开盖滚多两、三分钟，关火捞出后用温水再次冲洗干净备用。", "洗净的猪骨置于砂煲内，加足量清水、一块拍松的生姜，一点点陈醋（以利于猪骨中的钙质溶解于汤内），大火开煲。", "同时准备其他食材，玉米撕去包衣切成小段（我一般切段后会再分两半），胡萝卜去皮后切滚刀块，马蹄洗净削皮切两半。", "砂煲中加入洗净切好的的玉米、胡萝卜、马蹄，大火烧开后转中小火煲", "5～2个小时，加少许盐，关火出锅。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/6a89cdb406154ba2a424eacdde4142a2_1106w_1091h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('3', '肉类', '猪骨', '', '[{"name": "猪筒骨", "amount": "600克"}, {"name": "淮山", "amount": "325克"}, {"name": "一根玉米", "amount": "适量"}, {"name": "半个胡萝卜", "amount": "适量"}, {"name": "少许盐", "amount": "适量"}]'::jsonb, '["食材准备；", "猪骨洗净冷水下锅煮沸焯去血水，捞出用凉水冲几遍洗干净，沥干水备用；", "淮山、胡萝卜去皮切小块，玉米也切小块，淮山切好后可以用清水泡着以免氧化变色；", "锅里加入1600克清水，先加入猪骨和玉米；", "珐琅锅盖上盖子，电磁锅选择“排骨汤”功能，口感选择“适中口感”；", "煮到程序还剩下30分钟的时候再加入淮山和胡萝卜，继续煮到程序完成就可以了；", "最后加少许盐调味即可。", "营养又美味~"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/b3c6303c411f419e987cc80ebe878453_5472w_3648h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('~', '肉类', '猪骨', '', '[{"name": "适量猪骨", "amount": "适量"}, {"name": "茯苓", "amount": "20克"}, {"name": "薏米", "amount": "50克"}, {"name": "五指毛桃", "amount": "50克"}, {"name": "陈皮", "amount": "1片"}, {"name": "少许盐", "amount": "适量"}, {"name": "2000毫升清水", "amount": "适量"}]'::jsonb, '["材料清洗干净，清水泡30分钟，再次洗干净就可以。", "猪骨焯水，也可以用鸡肉，焯水后洗干净。", "把洗好的材料都放在一起，加入清水，一次加够水。", "大约煮一个半小时，如果明火煮，煮开了，就改小火慢慢熬。", "煮好放少许盐，其它不用放。", "五指毛桃茯苓薏米猪骨汤"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/6bcdb712310649a190764b6f38b58b83_763w_1017h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('‖', '肉类', '猪油', '', '[{"name": "猪板油", "amount": "750克"}, {"name": "水", "amount": "350克"}, {"name": "四片姜", "amount": "适量"}, {"name": "黄酒", "amount": "10ml"}, {"name": "盐", "amount": "2克"}]'::jsonb, '["猪板油切厚片", "锅里放水和姜片少许黄酒煮至微开", "下入板油煮三分钟", "捞出 透明感", "锅内放350ml清水。倒入焯过水的板油片", "大火煮开", "水少时 把火力调至小火", "随着油量增加水汽成大泡", "水汽少之又少的时候关火", "把油篦出。在油脂中加入盐2克", "放凉一小时后的油脂", "放至三小时后的油脂"]'::jsonb, 30, 60, '困难', 3, 'https://i2.chuimg.com/18758a9c5b8f466ca2024f998a81fb65_1080w_1440h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('“”', '肉类', '猪血', '酸', '[{"name": "克猪血", "amount": "适量"}]'::jsonb, '["厨师长教你：“酸菜烧猪血”的家常做法，非常开胃下饭"]'::jsonb, 5, 10, '简单', 3, 'https://i2.chuimg.com/72f510f35c01475c9582754592eeea49_1920w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('()‼', '肉类', '肉末', '', '[{"name": "红薯粉丝", "amount": "80g"}, {"name": "肉末(猪肉糜)", "amount": "30g"}, {"name": "少许葱花", "amount": "适量"}, {"name": "少许姜片", "amount": "适量"}, {"name": "盐", "amount": "2g"}, {"name": "料酒", "amount": "1勺"}, {"name": "酱油", "amount": "1勺"}, {"name": "豆瓣酱", "amount": "1勺"}, {"name": "少许糖", "amount": "适量"}, {"name": "少许油", "amount": "适量"}]'::jsonb, '["红薯粉丝剪成段，用温水浸泡20分钟泡软备用。", "泡软后的粉丝沥干水分。", "葱切成末，姜切片。", "锅内倒入少许油，烧热后倒入葱末姜片爆香，加1勺豆瓣酱翻炒均匀后下猪肉糜(肉末)炒散。倒1勺料酒、1勺酱油、糖、盐调味炒均匀，加入小碗冷水，煮沸。", "汤煮沸后倒入沥干水分的红薯粉，入锅一起翻炒几下后小火焖煮5分钟。", "大火翻炒收汁出锅。此菜要速炒，时间长了粉条容易粘连，影响菜肴口感！", "出锅的肉末炒粉丝色泽油亮。", "装盘后可以撒少许葱花和白芝麻，美味诱人！", "粉丝油亮，柔软滑嫩，肉末香嫩！"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/7ea02eee3d4744c6b97563f3e907c3f2_3072w_2304h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('·', '肉类', '鸡翅', '', '[{"name": "鸡翅中", "amount": "8个"}, {"name": "2粒冰糖", "amount": "适量"}, {"name": "料酒", "amount": "3勺"}, {"name": "蚝油", "amount": "1勺"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "适量葱姜蒜", "amount": "适量"}, {"name": "半个辣椒", "amount": "适量"}]'::jsonb, '["准备阶段：", "鸡翅正反面各划两刀➕料酒3勺➕生抽2勺➕蒜末、姜片➕生粉半勺➡️放入盘中腌制20分钟", "生姜切6片、大蒜切末、葱切成丝、辣椒半个切丝备用", "半勺生抽、半勺老抽、一勺蚝油、2颗冰糖备用", "热锅冷油➡️油热后加入葱、姜、蒜、辣椒➡️炒出香味\n\n⚠️注意：我这里放的前一天熬出来的猪油，猪油会更香，没有的话普通的油也是可以的", "加入腌制后鸡翅➡️煎至两面金黄", "加入热水沒过鸡翅➡️倒入之前准备好的半勺生抽、半勺老抽、一勺蚝油、2颗冰糖➡️加入一根完整的打成结的小葱➡️热水煮开后关成小火煮15分钟\n\n⚠️注意：要放热水，冷水会使肉收缩，从而影响口感；同时要放一根完整的小葱，这样汤汁会更香哦😜", "大火收汁装盘➡️撒上葱花\n\n鸡翅肉质鲜嫩｜汤汁浓稠\n\n真的超级好吃，快来试下吧❤️"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/1136c60f7ae3439ea67e8ddcc7208991_2700w_2160h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('ღ Candice ʚྀིɞ', '肉类', '鸡翅', '', '[{"name": "（11个）鸡翅中", "amount": "500g"}, {"name": "1听可口可乐", "amount": "适量"}, {"name": "少许葱段", "amount": "适量"}, {"name": "姜片", "amount": "3片"}, {"name": "料酒", "amount": "3勺"}, {"name": "海天红烧酱油", "amount": "2勺"}, {"name": "海天海鲜酱油", "amount": "1勺"}, {"name": "八角", "amount": "1个"}, {"name": "一小块桂皮", "amount": "适量"}, {"name": "具体每步的配料需要多少下面有写", "amount": "适量"}]'::jsonb, '["把鸡翅中洗净，两面都用刀切口，让鸡翅可以更好的入味，加入2勺料酒，1勺红烧酱油，腌制，腌制时长看个人，半小时至两小时均可", "冷水中放入葱段，姜片，把腌制好的鸡翅倒入，一起煮，直至锅差不多全开，有很多的血沫出来，就把鸡翅捞出", "捞出的鸡翅可以用温水冲洗，也可以不冲洗，我觉得影响不大，我做的时候没冲洗！捞出来直接下锅了", "把焯鸡翅的水倒掉，锅洗干净，热锅，把锅里残留的水滴烧干，倒入一点点油（防止锅不太好的话，鸡翅会粘锅）把鸡翅倒入锅中，大火煎至双面焦黄", "倒入1听可口可乐，1勺料酒，1勺红烧酱油，1勺海鲜酱油，1个八角，1小块桂皮，无需加水，翻匀后盖锅，转至小火炖", "待汤汁收至差不多还有一碗的样子吧，尝下汤汁咸淡，加入适量的盐", "要及时观察，因为可乐糖分较高，很容易糊锅，汤汁收的差不多就可以起锅了！", "出锅，因为我不喜欢有汤汁，所以基本都收干了，鸡翅上一层可乐 ，并不是糊了，口感很棒！"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/580a01c880ce4dbeb5383fd3e69b6a70_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('~', '肉类', '鸡腿', '辣', '[{"name": "鸡腿🍗", "amount": "4个"}, {"name": "鸡翅根", "amount": "2个"}, {"name": "水煮蛋", "amount": "4个"}]'::jsonb, '["操作如图", "操作如图", "操作如图", "操作如图", "汤汁泡一宿好好吃！"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/74f807f20e7e41b4b544fb87505476ec_3024w_2417h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('“”', '肉类', '鸡爪', '', '[{"name": "鸡爪", "amount": "500g"}, {"name": "6瓣大蒜", "amount": "适量"}, {"name": "生姜", "amount": "2块"}, {"name": "辣椒", "amount": "2个"}, {"name": "料酒", "amount": "5勺"}, {"name": "红烧汁", "amount": "3勺"}, {"name": "冰糖", "amount": "1块"}, {"name": "少许盐", "amount": "适量"}, {"name": "米醋", "amount": "5勺"}, {"name": "生抽", "amount": "5勺"}, {"name": "2-3勺蚝油", "amount": "适量"}]'::jsonb, '["鸡爪剪去指甲洗净备用。", "冷水锅放入姜片和少许盐加入料酒焯水约6分钟。", "过冷水二次清洗。", "配料：带皮大蒜、姜块、辣椒。", "锅里倒入少许油下生姜大蒜炒香。", "下鸡爪和辣椒（辣椒被掩盖了）过油表层微微起皱。这里敲重点：鸡爪一定用厨房纸巾拭干水分，锅里中小火低温翻炒（预防油溅）。一旦无法避免的发生油溅事故（厨房如战场），请及时勇敢的拿起锅盖当盾牌，保护好自己嗷！", "下蚝油、生抽、红烧汁炒出酱香味。左上角可看到辣椒的“身影”。", "下料酒去腥入味。", "加入适量清水下一块冰糖。大火煮沸转小火焖煮约35-40分钟。", "慢慢收汁后加入“米醋”灵魂深处的一抹酸爽，绝对提味。", "边看电视边吃爪爪一盆立马消灭殆尽！！无敌我胃！带皮大蒜也是灵魂所在嗷，吸饱了精华酱汁软糯嫩滑，轻轻一吸，回味无穷啊！", "太多朋友留言问我红烧汁了，干脆拍张图片给大家做个参考吧😘，一般各大超市都有售，家里没有红烧汁可以用老抽替代。", "太多厨友询问勺子大小，就家常普通的瓢羹，从自己其他菜谱借用一下，请忽略图片背景与鸡爪不符，哈哈哈😄…大家参考吧！", "还有厨友们留言问我家的锅子，“臻三环”铸铁双耳锅，厚底薄边34cm。好用的土式老锅，纯属个人实用分享，不打广告！哈哈哈😄…", "一直习惯叫米醋，因为是大米小麦天然发酵的，今天应厨友要求拍照片才发现，名字叫“同康香醋”，尴尬了😅！这是我们台州本土品牌，台州人惯用的。"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/a2ca37e9088a43e4b83ecc0abc9a6881_814w_748h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('——', '肉类', '鸡肉', '辣', '[{"name": "几根葱", "amount": "适量"}, {"name": "一块姜", "amount": "适量"}, {"name": "3-5瓣蒜", "amount": "适量"}, {"name": "少许（可忽略）甜椒", "amount": "适量"}, {"name": "半只鸡", "amount": "适量"}, {"name": "一勺料酒", "amount": "适量"}, {"name": "少许胡椒粉", "amount": "适量"}, {"name": "半勺盐", "amount": "适量"}, {"name": "特级生抽", "amount": "2勺"}, {"name": "一勺耗油", "amount": "适量"}]'::jsonb, '["鸡肉切块洗干净控干水分（不控干水分炒出来不好吃）。蒜姜切块，我喜欢蒜的味道，所以弄多一倍的量，葱最好用小葱切断，我这是大葱所以切丝。甜椒是点缀颜色好看，切颗粒（没有就算了）。如果你喜欢吃辣可以换成小米椒，切小段。", "油热下蒜姜颗粒炒香，然后下鸡肉翻炒。", "炒到鸡肉变色了，加入料酒（沿锅边下），炒到酒精挥发以后，加入生抽，耗油，胡椒粉继续翻炒", "炒一会以后加入一小碗水（大概如图的量，别多了），加盖小火15分钟。中途开盖翻炒一下。", "开盖大火收汁，加入少许盐（因为加了生抽和耗油了，盐适量），点缀的红椒（或小米椒），翻炒2下，最后加入葱。搞定。"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/46b9ce442d0545149dcc9c69cea93867_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('()', '肉类', '鸡肉', '', '[{"name": "鸡肉：1000克", "amount": "适量"}, {"name": "干香菇：50克", "amount": "适量"}, {"name": "八角：3克", "amount": "适量"}, {"name": "干红辣椒：6个", "amount": "适量"}, {"name": "大葱：20克", "amount": "适量"}, {"name": "生姜：20克(分两次用)", "amount": "适量"}, {"name": "盐：13克左右", "amount": "适量"}, {"name": "生抽：20克", "amount": "适量"}, {"name": "老抽：5克", "amount": "适量"}, {"name": "耗油：10克", "amount": "适量"}, {"name": "食用油：适量", "amount": "适量"}, {"name": "料酒：20克(分两次用)", "amount": "适量"}, {"name": "白糖：17克", "amount": "适量"}]'::jsonb, '["我这次的是从京东生鲜上买的一家知名品牌冷冻土香鸡(其他鸡也可以)，提前从冰箱里拿出来自然解冻，解冻后清洗干净，剁掉鸡屁股和鸡脚指备用。", "把干香菇清洗干净，用1300毫升的凉水提前3个小时泡上", "把清洗干净的鸡剁成小块，放入锅内，倒入凉水，再加入12克姜片和10克料酒，大火烧开后，打开锅盖，撇去浮沫，开着锅盖焯水1分钟捞出控干水分（开着锅盖焯水有利于腥味散出）。", "这是水开后的状态，还是会有很多浮沫的，把浮沫撇去。", "这是撇去浮沫后是不是就好多了呢！", "鸡肉焯水后捞出控水备用（上图焯过水的鸡肉）。", "1、把泡好的香菇捞出控水备用。\n2、把泡香菇的水烧开，撇去水里浮沫备用（泡香菇的水图片省略了）。", "炒锅里加入适量食用油，把葱段、八角、干红辣椒段和8克姜片倒入锅内炒出香味。", "倒入鸡块先翻炒片刻，再沿着锅边转圈倒入10克料酒(利用料酒遇热锅底蒸发去腥味提鲜)，翻炒几下，然后再倒入老抽、生抽、耗油、白糖、盐继续翻炒两分钟左右。", "上图是倒入所有调味料翻炒片刻后的状态", "加入1000毫升左右泡香菇的热开水(水的多少如图状态淹没过鸡肉就行，这个加水量只是参考），再加入香菇，盖好锅盖就开始炖了，大火烧开后转小火炖，只要锅内始终保持沸腾状态就可以了。\n\n注：如果加粉条的话，就需要多加水，粉条提前用凉水泡软，最后5分钟加入炖入味即可！加粉条的话，配方中的各种调味品都需要相应再增加用量。", "上图是炖了35分钟打开锅盖沸腾中的状态，可以收汤汁也可以不收汤汁(这只鸡肉嫩，只炖了35分钟鸡块就完全熟了，如果是真正的土鸡需要炖1个半小时左右才可以，也就需要往锅里相应多加些水了，注意一次要把水加够，中途不加水)。\n        出锅前加入适量鸡精、淋入适量的芝麻香油、撒上适量小香葱搅拌即可出锅装盘了！菌香四溢，肉香味鲜，属于香而不腻的一道美味！", "最后锅里汤汁留多少根据喜好定，有时汤汁留的多，有时留汤汁留的少，随喜好来（应该撒小香葱更好卖相也会更漂亮，可惜家里没有小香葱就只好切了片大葱叶子来点缀一下了）。\n          出锅前品尝一下咸淡，淡了就加盐，咸了汤汁就多留些。终于记录完了，写菜谱真的是好费眼睛啊！\n       (拍照技术太拙，菜谱封面对不起味道，口感是王道，理解万岁)。"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/e9d57ca13e2544fd8836576c69600d4e_1280w_959h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('-', '肉类', '乌鸡', '', '[{"name": "半只乌鸡", "amount": "适量"}, {"name": "当归", "amount": "10g"}, {"name": "川芎", "amount": "10g"}, {"name": "熟地", "amount": "10g"}, {"name": "白芍", "amount": "10g"}, {"name": "红枣", "amount": "10g"}, {"name": "枸杞", "amount": "10g"}]'::jsonb, '["先把鸡肉洗好备用（药材我是去药店买，说要半只鸡的量，药剂师会看着给配的，四物汤-或者按照我上面写的买也可以）", "准备好食材，接下来就是焯水\n炖汤我都习惯把肉放锅里焯水后再炖汤", "冷水下锅后放入鸡肉、药材，开大火炖，煮开了之后转小火慢炖，炖个2小时的样子，药效差不多可以炖出来", "起锅时我会放一点点盐巴（放一点冰糖改善一下口感）很简单的养生汤，空了可以自己动手做一做"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/5a4702e969f6496bb5e4eb2ae49b7b15_828w_828h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('•', '肉类', '鸡胗', '辣', '[{"name": "匙酱油       2", "amount": "适量"}, {"name": "瓣蒜     6", "amount": "适量"}, {"name": "小片姜片     6", "amount": "适量"}, {"name": "根香芹      4", "amount": "适量"}, {"name": "匙料酒  1", "amount": "适量"}, {"name": "只鸡肾       10", "amount": "适量"}, {"name": "勺盐      1", "amount": "适量"}, {"name": "个红青椒    5", "amount": "适量"}, {"name": "块沙姜     2", "amount": "适量"}]'::jsonb, '["主配料齐全", "炒鸡什配菜：香芹切段，红椒青椒切片，香葱切段。", "切什花的确适合技术活，所以直接拍视频算了。", "把切好的鸡肾花，倒入少许米酒和盐拌匀十分钟，等锅里水开倒入绰水，鸡肾变色立马捞起，时间千万不要久了，太久老了炒出来不好吃", "绰过水的鸡什花，漂亮！", "鸡什花花调味：加入料酒，蚝油，生抽，香油，胡椒粉拌匀入味30分钟", "拌好入味的什花", "炒鸡什我一般都用菜籽油，去腥炒出来更香，油热放几颗白胡椒，倒进鸡什大火爆炒两分钟，家里有酒糟的话倒两匙酒糟水（或米酒或料酒），把配菜倒入翻炒两分钟，欠汁倒入收汁起锅。", "这道菜真的让人食欲满满！今晚忍不住想要添饭！"]'::jsonb, 27, 45, '中等', 3, 'https://i2.chuimg.com/667cc22249854caf8b8160e11c5dddaa_1080w_864h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('—', '肉类', '土鸡', '辣', '[{"name": "半只肉鸡", "amount": "适量"}, {"name": "一把小米椒", "amount": "适量"}, {"name": "适量干辣椒", "amount": "适量"}, {"name": "适量葱姜蒜、香菜", "amount": "适量"}, {"name": "一个八角", "amount": "适量"}, {"name": "适量料酒、老抽", "amount": "适量"}, {"name": "适量油、盐、糖", "amount": "适量"}]'::jsonb, '["鸡剁块，并用温水清洗干净，不用焯水（这样鸡的味道比较香），彻底沥干水分备用。", "小米辣切丝，干辣椒剪碎，葱姜蒜、香菜切好备用。", "锅烧热后下油，直接倒干辣椒、葱姜和八角以及一半的蒜、煸香（一定要煸出香味来），再倒入鸡块不停煸炒。", "等到鸡肉煸炒至发白发紧，倒入料酒继续煸炒，把鸡肉的腥气炒出来。我家做菜喜欢用这种土绍酒或白酒代替料酒，土法酿制比较醇香。", "加入老抽继续翻炒，再加入盐、糖继续翻炒，再盖上锅盖中火焖5分钟左右。", "开盖继续翻炒，再加入剩下的一半大蒜、小米辣丝、香菜丝一起继续翻炒。", "等到这些蔬菜熟了就可以出锅享用了"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/e32b0e5689de11e6b87c0242ac110003_1080w_1616h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('“”', '肉类', '土鸡', '', '[{"name": "半只黑皮土公鸡", "amount": "适量"}, {"name": "大蒜", "amount": "40克"}, {"name": "几根二荆条", "amount": "适量"}, {"name": "小米辣", "amount": "40克"}, {"name": "大葱", "amount": "2根"}, {"name": "1小块仔姜", "amount": "适量"}, {"name": "适量熟菜籽油", "amount": "适量"}, {"name": "适量食用盐", "amount": "适量"}, {"name": "老抽", "amount": "2克"}, {"name": "生抽酱油", "amount": "10克"}, {"name": "少许白糖", "amount": "适量"}, {"name": "少许胡椒粉", "amount": "适量"}, {"name": "少许晒醋", "amount": "适量"}]'::jsonb, '["首先我们准备黑皮土公鸡半只\n将土鸡剁成几大块之后再剁掉鸡屁股", "然后去掉指甲之后将鸡肉剁成小块备用\n同学们最好剁小块一些这样更容易爆炒和入味", "最后我们在处理鸡脖子的时候将鸡皮扯下来", "然后将吸附在鸡皮表面的淋巴清除干净\n鸡脖上面的淋巴不分家养或者养殖都会有\n所以我们在处理鸡脖子的时候必须认真仔细检查一遍", "将鸡头剁好之后下一步开始准备辅料", "准备大蒜40克切成小粒备用\n同学们爆炒土鸡可以适量的多加一些大蒜这样更香", "准备几个二荆条去蒂之后切成小粒备用\n同学们也可以用魔芋或者小土豆代替二荆条", "准备小米辣40克切成小粒备用\n不能吃辣的同学可以不加", "准备大葱2根切成小粒备用", "最后准备仔姜1小块切成小粒备用\n建议川外的同学加生姜更好，因为出川后的仔姜味道会发苦\n温馨提示：此菜为家常小炒一锅成菜，无宽油", "下一步开始制作\n首先我们在锅中加入适量的清水\n然后将剁好的鸡头下锅焯水\n因为鸡头比较大块所以焯水之后更容易熟透\n鸡头焯熟之后倒出备用", "然后我们把锅烧热\n锅烧热之后再加入适量的熟菜籽油\n将油温烧至6成热", "油温6成热之后在锅中加入食用盐1勺（约3克）", "然后将剁好的鸡块下锅开中小火爆炒5分钟\n油中加盐的目的是让鸡肉更加的干香和入味", "当鸡肉炒至水份略干的时候再加入切好的大蒜和辣椒", "料头下锅之后翻炒几下将大蒜炒香", "大蒜炒香之后再加入老抽2克转小火将鸡肉翻炒至上色\n此菜不能加豆瓣酱所以加少许老抽上色", "鸡肉上色之后加入10克生抽酱油从锅边淋入炒香", "最后再加入切好的大葱粒，仔姜粒和辣椒粒", "然后开始调味\n锅中加入少许白糖中和辣味和提鲜\n再加入少许胡椒粉\n然后翻炒几下将辅料炒至断生", "再加入少许的晒醋从锅边淋入开大火翻炒均匀\n没有晒醋的同学可以用香醋或者陈醋代替\n最后大火翻炒几下炒出锅气即可出锅装盘", "一道非常美味的爆炒土鸡就制作完成"]'::jsonb, 30, 110, '困难', 3, 'https://i2.chuimg.com/659b0e55f6544040847dc25ff5443511_3840w_2160h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('()', '肉类', '三黄鸡', '', '[{"name": "三黄鸡", "amount": "1只"}, {"name": "半个土豆", "amount": "适量"}, {"name": "半个胡萝卜", "amount": "适量"}, {"name": "半个青辣椒", "amount": "适量"}, {"name": "鲜香菇", "amount": "3个"}, {"name": "半个洋葱头", "amount": "适量"}, {"name": "5瓣大蒜", "amount": "适量"}, {"name": "两片姜", "amount": "适量"}, {"name": "半个八角", "amount": "适量"}, {"name": "适量白醋、生抽、老抽、耗油", "amount": "适量"}, {"name": "半瓶啤酒", "amount": "适量"}, {"name": "适量盐、白糖、鸡精", "amount": "适量"}, {"name": "（可不放）干辣椒", "amount": "2个"}]'::jsonb, '["上好的三黄鸡一只（我在超市买的带包装冷冻的）", "改刀切成小块", "辅料切成喜欢的形状", "爆香料切好备用", "热锅凉油将洋葱、生蒜、姜片、八角、干辣椒翻炒爆香。", "下入鸡肉块煸炒，将肉块炒制变色变干。（肉块炒成白色）", "点上少许白醋（肉会更加鲜嫩）", "放生抽适量（后补的图）", "放老抽适量上色", "放适量耗油提鲜", "啤酒半听（我用的是大听的，品牌随意，没有也可以放料酒）", "加入适量清水，（没过鸡肉便可）", "大火烧开放入食用盐、白糖、鸡精转小火，盖上锅盖炖15—20分钟，（时间以鸡肉熟烂为准）", "倒入配菜，土豆和香菇先行入锅，大火收汁，出锅前两分钟在放胡萝卜和青椒。", "摆好桌子、椅子、筷子、勺子，上菜上大米饭，开造。", "孩子吃的很开心"]'::jsonb, 30, 80, '困难', 3, 'https://i2.chuimg.com/3bf3d8f9ef4b4e338501db7048f0cc78_1728w_2304h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('·', '肉类', '鸡肝', '', '[{"name": "4、5个鸡肝", "amount": "适量"}, {"name": "姜片", "amount": "2片"}, {"name": "两勺适量盐", "amount": "适量"}, {"name": "5、6粒（喜欢可以多放）花椒", "amount": "适量"}, {"name": "可有可无牛奶", "amount": "适量"}]'::jsonb, '["新买的新鲜鸡肝要先泡去血水，（水里可以加一点点盐和牛奶）至少10分钟，然后用清水淘洗两次，至水清，注意下手轻柔，不要碰破了鲜嫩的鸡肝。", "事先准备一个大碗，或者是耐100℃高温的保鲜盒，撒入花椒粒和盐，喜欢花椒就多放一些，我就是随手一抓。", "泡好洗净的鸡肝冷水下锅焯水，水量淹没鸡肝就够，放几个姜片去腥，中小火，把水慢慢烧开后，立即捞出鸡肝。\n\n（请注意：不要放任何黄酒、料酒、白酒……\n虽然这也是去除腥味的传统方法，但是，不适合用作动物肝脏，不信的话，您就试试看。）", "水开后立即捞出的鸡肝，趁热放在之前准备好的碗里，鸡肝带着温度焖在花椒粒上面，很能激发出香味儿。\n\n      此时鸡肝已经八成熟，可能还会带有些许血丝，不要担心，只差最后一步。", "再次烧开一些开水，倒入大碗，淹没碗中的鸡肝，尝尝盐味儿，不够就再加一些食盐调整咸淡，就这么泡着，直到自然冷却。\n\n\n      有做过的朋友说，鸡肝较大，可能不能熟透。我有两个方法来解决：\n      其一、上一步水开以后，小火再煮1分钟，肯定熟了；\n      其二、用更大的容器浸泡，更多的开水带来更长的保温时间，也能保证熟透。\n\n根据巴氏消毒法，食物内部温度达到68℃以上，半个小时以内就可以杀死所有细菌，我们这个做法，基本上也就达到了理想的环境。", "泡上十分钟以后，就算入味了，鸡肝的鲜嫩程度刚刚好，血丝已经消失，可以像白灼虾那样连汤一起上桌了。\n\n      也可以提前准备好，就这么泡着，凉了拿出来还是鲜嫩的，连汤装保鲜盒一起放冰箱，两三天内随时享用。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/214e5b520e4111e7bc9d0242ac110002_1296w_1729h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('-', '肉类', '童子鸡', '', '[{"name": "半只新鲜童子鸡", "amount": "适量"}, {"name": "盐", "amount": "5克"}, {"name": "生姜", "amount": "3片"}, {"name": "小葱", "amount": "5根"}]'::jsonb, '["把童子鸡洗净，用盐把里外都均匀抹上盐，腌制片刻。", "在童子鸡肚子里塞入生姜和小葱。", "锅里烧水，水开后，把装有童子鸡的碗放入锅里，大火蒸30分钟即可。"]'::jsonb, 9, 15, '简单', 3, 'https://i2.chuimg.com/94d3823d42ad4538a50722772bd26e40_1000w_750h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('C', '肉类', '牛腱', '', '[{"name": "牛腱", "amount": "2斤"}, {"name": "随意桂皮", "amount": "适量"}, {"name": "随意八角", "amount": "适量"}, {"name": "随意香叶", "amount": "适量"}, {"name": "随意草果", "amount": "适量"}, {"name": "随意肉豆蔻", "amount": "适量"}, {"name": "随意小茴香", "amount": "适量"}, {"name": "随意丁香", "amount": "适量"}, {"name": "随意花椒", "amount": "适量"}, {"name": "随意干辣椒", "amount": "适量"}, {"name": "随意姜片", "amount": "适量"}, {"name": "随意大蒜", "amount": "适量"}, {"name": "随意大葱葱白", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "一小口！白酒", "amount": "适量"}, {"name": "一小块！冰糖", "amount": "适量"}]'::jsonb, '["首先要挑选一块好的牛腱，首选筋膜丰富的腱芯（又称：金钱腱），不论筋纹还是口感，都是最棒的。当然腱芯的价格也会比一般的腱子肉贵一些。", "第1个“一小时”：不汆水，用浸的！\n把牛腱分割成大小合适的条状，横截面就差不多是切片的大小，牛肉煮后会缩水，留点余量不要切太细了。切好的牛腱浸在水中去血水，期间多换水多翻动翻动，尽可能多洗去一些，土豪可以用流动水。看图片一小时下来是不是也白白的了~~", "第2个“一小时”：倒掉水，把牛腱放入冰箱冷冻，是冷冻，冷冻！\n此做法可保切片不散，肉质也更紧致！\n完全无事可干的一小时，赶时间的可以去掉这个步骤。", "香料准备工作：把你家的香料全都拿出来，每个都放一点，随意就好，缺几样也无所谓的。新鲜的姜蒜葱也一样，不强求，有就放。喜欢蒜味的朋友们，推荐你们把一整头大蒜放进去，不要剥开，不要去皮，冲一冲就可以了。如果香料实在不多，那么加一包五香粉吧，但口感不怎么好，总有点粉粉的。", "第3个“一小时”：汤锅中加入所有香料、调料、水（不要加太多，不够可以补），大火煮开。接着把冰冻了一小时的牛腱直接加入沸锅中，汤汁要没过牛腱，不够再加热水，大火再煮沸。", "因为没有汆过水，多少还有些血沫的，刚开始容易噗锅，盖子开一些并且注意观察。前10分钟大火滚煮，人不要离开。中程改中火，厚底汤锅可改小火，保持滚就行了。期间看望几次，顺便翻翻身尝尝味，缺啥补啥。咸味可以略重一些，这样肉中间是刚好的。\n最后这个一小时是大致时间，具体看火力和肉的大小决定，筷子能插入即可关火，喜欢吃有嚼劲些的，差不多是稍用力能插入的程度。", "浸泡6小时以上或者过夜，过夜的话要放冰箱。吃的时候再切片。撒上椒圈，开瓶啤酒，看看美剧，吹吹空调，我就问你爽不爽！！！"]'::jsonb, 21, 35, '中等', 3, 'https://i2.chuimg.com/0cae1296897111e6b87c0242ac110003_1000w_1000h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('15', '肉类', '牛肉末', '', '[{"name": "牛肉馅", "amount": "300克"}, {"name": "冷冻蔬菜粒", "amount": "500g"}, {"name": "各一勺（15ml）牛肉馅腌制材料（料酒，生粉，生抽，蚝油，花椒油，橄榄油）", "amount": "适量"}]'::jsonb, '["牛肉馅加腌制材料，拌匀腌制2小时以上", "蔬菜粒开水中焯一下至蔬菜粒浮起，滤干备用。", "热锅加如油，油热后倒入腌制好的肉末爆炒至变色。", "加入蔬菜粒，加一勺生抽提鲜炒匀。", "可与出锅啦～～"]'::jsonb, 15, 25, '简单', 3, 'https://i2.chuimg.com/3ce74d3e5a3840349024956024cc4b46_1868w_1240h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('-', '肉类', '牛肉末', '辣', '[{"name": "牛肉", "amount": "100克"}, {"name": "杭椒", "amount": "50克"}, {"name": "小米辣", "amount": "50克"}, {"name": "生抽", "amount": "10ml"}, {"name": "白糖", "amount": "10g"}, {"name": "2头蒜头", "amount": "适量"}, {"name": "生姜", "amount": "3片"}]'::jsonb, '["还好在家里屯了好多的牛肉，这一块当时超市28块钱一斤买的，现在看来好划算，切一小块下来做今天的下饭菜。", "牛肉切成小丁", "这些肉需要有一些味道更好入味，加入一点酱油，一点糖，先腌制一下。", "要下锅前，在放入水和淀粉，搅拌匀。", "然后加入一点食用油润滑，这样下锅炒的时候肉和肉之间不会容易粘连。", "起锅热油，放入牛肉末翻炒。", "等到肉都变了颜色就可以捞出备用了。", "今天的辣椒要两种，一种是小米辣，提供辣味，另一种是小杭椒，提供清香味。", "将这两种辣椒切成小小的，备用。", "起锅热油，放入蒜末和姜末爆香。", "加入辣椒末，辣椒末多炒一会儿，让辣椒的香气和辣味出来。", "接着就是放入我们炒好的牛肉末啦～ 快速翻炒一会儿，加入一圈生抽，一些白糖，翻炒30秒钟就可以出锅啦～", "一份超级无敌下饭的辣椒炒牛肉末就完成了。", "搭配上两个简简单单的素菜，就是很棒的一餐啦·", "来，看看，搭配上米饭是不是很有胃口～"]'::jsonb, 30, 75, '困难', 3, 'https://i2.chuimg.com/eadf2c7a23524a50a32d413e1a258440_1616w_1080h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('Q', '肉类', '牛百叶', '', '[{"name": "牛肚", "amount": "适量"}, {"name": "青尖椒", "amount": "适量"}, {"name": "红尖椒", "amount": "适量"}, {"name": "葱", "amount": "适量"}, {"name": "姜", "amount": "适量"}, {"name": "蒜", "amount": "适量"}, {"name": "豆瓣酱", "amount": "适量"}, {"name": "白糖", "amount": "适量"}, {"name": "生抽", "amount": "适量"}, {"name": "料酒", "amount": "适量"}, {"name": "非必需辣椒油", "amount": "适量"}]'::jsonb, '["补充一步处理牛肚的方法：牛肚买回来先整块下锅加葱姜料酒焯水，放点醋容易熟，烧开后转小火半个小时左右、煮到能用筷子戳进去就可以了，然后拿出来洗干净切条", "准备食材，尖椒（尖尖的就叫这个名字吧，具体叫啥，大家看我图片，青的比较长，红的比较短）切段，葱切段，姜切条，蒜切片；\n重点在牛肚，刚买回的牛肚是整片的，需要清洗干净，然后放锅里水煮，煮到半熟，注意千万别煮烂了，烂了没口感，煮好后切成条状备用。", "油，姜，蒜，葱依次下锅，炒香后加入少许白糖，再加适量（半勺即可）豆瓣酱，翻炒；\n倒入牛肚，加生抽，料酒，辣椒油（喜欢吃辣可以多放），炒匀", "加青红椒，大火翻炒，出锅装盘（不需要放盐）", "手写菜谱，字丑见谅", "手写菜谱2，加入可视化图形，帮助您理解这道菜的精髓"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/104d282f4a784b08931b0721877ec044_677w_751h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('Korean Beef Bone Soup', '肉类', '牛骨', '', '[{"name": "2磅牛骨", "amount": "适量"}, {"name": "（1磅以内即可）牛胸肉Beef Brisket", "amount": "1块"}, {"name": "水", "amount": "6升"}, {"name": "细挂面", "amount": "100g"}, {"name": "1-2根香葱", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量胡椒", "amount": "适量"}]'::jsonb, '["先将牛骨用冷水冲净，然后泡在冷水中，大约2-3小时。第二张图可以看得很明显，2-3小时之后所有的血水、大部分油脂以及其他脏东西都泡出来了。这步很重要，可以保证你的汤出来时颜色是乳白色的。", "在大锅中用水没过所有的牛骨，然后将牛肉也放到锅中（其实我们后来骨头是分了两个锅煮，不要被第一张图骗了，没有那么满的哈）。中火慢炖，这个过程撇去浮沫。", "煮大约1个小时后，牛肉已经煮软时拿出来切成片备用。具体的煮牛肉时间还取决于你的水的多少、牛肉大小等等，请依据实际情况调整。", "这一步非常重要！切完牛肉之后，汤大概再煮3-4小时，直至汤减少了一半的时候，放凉，然后放入冰箱冷藏2小时以上，直至汤表面所有的油脂都结成硬块，然后用小勺全部刮下。这样就可以保证基本所有的油脂都被撇走了。", "当你撇完所有的硬块时，如果你的汤看上去像我们上图这样完全变成果冻状，你大概再煮20-30分钟至牛汤全都热透就可以了。但是如果你的牛骨汤撇完硬块状的油脂，下面依然是水水的，那还需要至少炖煮1小时左右。你最后的牛骨汤的质地是半透明的，有点像牛奶的，不会过稠或者过稀的。", "将细挂面煮熟之后过一遍冷水。滤去水分之后放入碗中。", "将切好的牛肉、葱花都摆在面上面，然后趁热倒入牛骨汤。", "任何多余的调味料都不需要，只要盐、现磨黑胡椒即可！牛骨汤要趁热喝哦！"]'::jsonb, 24, 40, '中等', 3, 'https://i2.chuimg.com/405b928888ba11e6a9a10242ac110002_700w_460h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('.', '肉类', '牛骨', '', '[{"name": "牛蝎子", "amount": "1000g"}, {"name": "都可以的其他骨头", "amount": "适量"}, {"name": "调味", "amount": "适量"}, {"name": "一块姜", "amount": "适量"}, {"name": "八角", "amount": "2个"}, {"name": "可有可无生黄豆一把", "amount": "适量"}, {"name": "干辣椒", "amount": "2个"}, {"name": "几粒花椒", "amount": "适量"}, {"name": "稍微多点（替盐）生抽", "amount": "适量"}, {"name": "适量（上色）老抽", "amount": "适量"}, {"name": "半勺糖", "amount": "适量"}]'::jsonb, '["凉水泡牛骨，多换几次水，去血水\n凉水入锅，开锅转小火，煮几分钟去浮沫\n\n骨头捞出来，凉水冲去浮沫杂质\n放进干净的锅里，放姜片八角（必要的）\n干辣椒花椒（次要的）淋上生抽老抽糖\n抓把黄豆，喜欢花生米的可以放点花生米（出来可以干吃也能当下酒菜）\n\n添水，没过骨头就行\n启动电压力锅，肉，骨，蹄筋的按钮都可以\n\n\n现在，你可以等着闻味道了😄", "想卤蛋的现在煮几个白水蛋，剥皮等着\n\n压力锅程序完成\n找个大的容器把骨头干捞出来\n晾凉，骨肉表面稍微风干（超级好吃）\n（比热吃更好吃，更好吃，更好吃啊，可以吃出西北酱牛肉的味道🐯）", "黄豆花生捞出来就可以吃了\n汤不要倒，把之前的水煮蛋放进去\n喜欢吃豆腐皮，金针菇，海带，豆干的朋友们。。。。。\n一切都可以泡进去，煮熟就可以吃了\n（提前泡进去，或者煮好再多泡着腌制一会会更入味好吃）\n不过加了太多菜的，要适当加盐奥", "来吧，不计热量，嗨起来"]'::jsonb, 12, 20, '简单', 3, 'https://i2.chuimg.com/6e3d4de9ee8742249387d37c24a2dfa1_620w_621h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('·', '肉类', '牛骨', '', '[{"name": "👇约3～4人份", "amount": "适量"}, {"name": "约800克牛骨", "amount": "适量"}, {"name": "约牛骨4倍量清水", "amount": "适量"}, {"name": "白萝卜（中大）", "amount": "1根"}, {"name": "白胡椒粒（现研磨）", "amount": "1克"}, {"name": "约20克料酒", "amount": "适量"}, {"name": "1～2个葱结", "amount": "适量"}, {"name": "2大块（约30克）姜（分2次用）", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "适量葱花（必备·提味）", "amount": "适量"}]'::jsonb, '["准备好所需食材·白萝卜削皮切成滚刀块", "牛骨提前一小时用清水浸泡，去除骨内血水、多余油脂。", "锅内加入适量清水，把牛骨冷水下锅，加入姜块、葱结、料酒", "中大火煮沸，再煮5分钟，中途撇去浮沫", "绰好的牛骨用清水多清洗几遍，直至水不再浑浊。", "锅内加入牛骨、胡椒、姜块、牛骨4倍左右的水量，水尽可能一次加够·大火煮30分钟「转」小火慢熬", "5小时（1小时左右加入白萝卜继续煮）", "如果锅内有汤溢出，盖子开个小缝即可。", "大约一小时左右加入白萝卜、少许盐，大火煮沸转小火慢熬半小时，至萝卜熟透，最后调味即可。", "「清甜·牛骨萝卜汤」", "「清甜·牛骨萝卜汤」", "熬好的牛骨萝卜汤再撒点葱花提味，完美～", "「清甜·牛骨萝卜汤」", "「清甜·牛骨萝卜汤」", "「清甜·牛骨萝卜汤」", "「清甜·牛骨萝卜汤」"]'::jsonb, 30, 80, '困难', 3, 'https://i2.chuimg.com/58df54bb313f4a5188db1bf141a738d5_3024w_4032h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('-15', '肉类', '牛肉馅', '辣', '[{"name": "土豆", "amount": "1斤"}, {"name": "普通瓷勺4勺（当然你可以多放）牛肉馅", "amount": "适量"}, {"name": "半根螺丝椒", "amount": "适量"}, {"name": "两根香芹", "amount": "适量"}, {"name": "1瓷勺花椒粉", "amount": "适量"}, {"name": "1瓷勺（最好选香辣味的）辣椒粉", "amount": "适量"}, {"name": "3瓷勺鲜味酱油", "amount": "适量"}, {"name": "1瓷勺料酒", "amount": "适量"}, {"name": "1瓷勺蚝油", "amount": "适量"}, {"name": "半勺白糖", "amount": "适量"}]'::jsonb, '["准备好食材，提示：如果你的食材比我的多，按比例增减调味料即可。", "处理食材：肉馅加1勺料酒，1勺鲜味酱油拌匀腌制，如果你用的肉馅多就按比例增加。", "芹菜切丁，螺丝椒切丁。", "一斤土豆，先切片，再切条，最后切成四方小丁。", "锅内入瓷勺2勺油，大火，入土豆丁。", "煎到表面出现黄色焦壳，取出沥油，如图，大家可以参考。", "煎土豆剩下的底油，中火，入牛肉馅，炒至全部变白。", "入瓷勺一勺辣椒粉，一勺花椒粉，翻炒出香味。", "入土豆丁。", "入2勺鲜味酱油，1勺蚝油，半勺糖。", "如果有辣椒油可以放一勺。加水，没过土豆。盖上锅盖，大火烧5分钟。", "5分钟后，开盖，撒入芹菜碎和螺丝椒碎，关火装盘。", "一定要有些汁水才香，不需要加盐，味道足够好了。"]'::jsonb, 30, 65, '困难', 3, 'https://i2.chuimg.com/6ba6e39b3fc54abe8ab01f89af91f24d_960w_562h.gif', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('()', '肉类', '羊蝎子', '', '[{"name": "羊蝎子", "amount": "6斤"}, {"name": "一根葱", "amount": "适量"}, {"name": "八片姜", "amount": "适量"}, {"name": "一头蒜", "amount": "适量"}, {"name": "60粒小茴香", "amount": "适量"}, {"name": "80粒花椒", "amount": "适量"}, {"name": "各四颗草果、豆蔻、肉蔻、草寇、丁香、", "amount": "适量"}, {"name": "各两块良姜、桂皮", "amount": "适量"}, {"name": "五片香叶", "amount": "适量"}, {"name": "六颗（泡两颗，四颗炖肉）大料", "amount": "适量"}, {"name": "四个干辣椒", "amount": "适量"}, {"name": "适量，实在没法数孜然", "amount": "适量"}, {"name": "两根荜拨", "amount": "适量"}, {"name": "两颗白扣", "amount": "适量"}, {"name": "适量辛夷", "amount": "适量"}, {"name": "适量冰糖", "amount": "适量"}, {"name": "适量红糖", "amount": "适量"}, {"name": "适量植物油", "amount": "适量"}, {"name": "适量生抽", "amount": "适量"}, {"name": "适量老抽", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量甜面酱", "amount": "适量"}, {"name": "十二根香菜", "amount": "适量"}, {"name": "一个，比拳头大点的洋葱", "amount": "适量"}, {"name": "两包注意注意！！没有上面香料的，可以直接用牛羊肉炖肉料包，料包也没有的，直接用花椒，大料，桂皮，香叶家里有什么放什么也行！", "amount": "适量"}]'::jsonb, '["羊蝎子肉多的吃着过瘾，买的时候让店家切小块，放适量的花椒大料泡四个小时左右，中间换三四次水，把血水泡出来", "经过几次换水和长时间侵泡，干净了很多", "泡好的羊蝎子冷水下锅，水多放点，加花椒，大料，料酒，葱，姜，焯水", "煮出血沫子，撇出", "撇到汤渐渐变清，汤留着一会炖蝎子", "盛出焯好的羊蝎子", "温水冲洗掉羊蝎子上的血沫子", "准备香料，因为六斤比较多，分两锅炒，所以准备两份", "炒锅倒油，油温不要太高时倒入香菜和洋葱丝炒香", "炒出香味的洋葱和香菜盛出，待用", "重新起锅，把香料和葱姜蒜爆香，放入一半焯好的羊蝎子，翻炒两分钟，倒入刚才留的汤锅中，不喜欢焯肉汤水的，用清水也可以（一定要是开水哦）", "翻炒好的羊蝎子和料一起倒入汤锅", "加入炒香的洋葱和香菜", "冰糖，红糖，盐，生抽，老抽，料酒，白胡椒粉，甜面酱混合，倒入锅中", "大火烧开，转小火慢炖2小时，出锅前过滤掉汤中的香料和煮烂的洋葱香菜", "放入适量枸杞和香菜，点上电磁炉，上桌开撮吧，吃完肉蝎子，还可以用汤涮喜欢的青菜，豆腐，特别推荐用汤涮烙饼！巨好吃！", "满屋飘香啊，肉软烂入味，老爸没牙都可以吃", "烙饼就是这样的，葱花饼，发面饼，乌冬面，拉面，只要是自己喜欢的都可以，万物皆可涮哈。"]'::jsonb, 30, 90, '困难', 3, 'https://i2.chuimg.com/a221eb109d0b11e6947d0242ac110002_1080w_1440h.jpg', true, true);
INSERT INTO recipes (name, category, type, flavor, ingredients, steps, prep_time, cook_time, difficulty, servings, image_url, is_published, is_verified) VALUES ('·', '肉类', '鸭腿', '', '[{"name": "鸭腿", "amount": "3只"}, {"name": "一把小葱", "amount": "适量"}, {"name": "适量姜", "amount": "适量"}, {"name": "八角", "amount": "1个"}, {"name": "适量冰糖", "amount": "适量"}, {"name": "适量盐", "amount": "适量"}, {"name": "克糖", "amount": "适量"}, {"name": "适量料酒", "amount": "适量"}, {"name": "适量桂皮", "amount": "适量"}]'::jsonb, '["腌制，这一步忘了拍照，具体如下：\n鸭腿用大量食盐抓匀，也可以用大粒泡菜盐，目的是杀出腥气，至少一个小时，看到有大量水析出就对了，不要怕太咸，因为鸭肉难以入味儿，也可以出门上班前少放点儿盐腌制，下班回来做。实在怕咸就在鸭腿下垫上两根筷子，可以避免泡在盐水中。\n还有一种做法就是，用盐和花椒抓匀以后，放在通风处，晾上半个小时。", "腌好的鸭腿洗净、擦干。\n炒锅大量油，比炒菜多一倍，下姜片，下小葱结、花椒、八角爆香，皮朝下鸭腿下锅，煎两分钟，至出油。", "翻面，继续煎1分钟。", "下冰糖或或者白糖，下酱油、花雕酒，热水加至淹没鸭腿，大火烧开，转中小火，保持微微沸腾状态，加锅盖焖。", "焖烧大概二三十分钟，过程中翻面两次，糖、水、油已经乳化。", "挑出已经稀烂的小葱，出锅、收汁、装盘。"]'::jsonb, 18, 30, '中等', 3, 'https://i2.chuimg.com/a2b2413c090e11e7bc9d0242ac110002_1488w_1488h.jpg', true, true);
